<template>
  <Transition name="search-fade">
    <div v-if="visible" class="search-box">
            <a-input
        ref="inputRef"
        v-model:value="keyword"
        placeholder="搜索节点名称或ID"
        class="search-box__input"
        size="small"
        allow-clear
        @keyup.enter="handleNext"
        @keyup.esc="handleClose"
      >
        <template #prefix>
          <SearchOutlined />
        </template>
      </a-input>

      <span class="search-box__count">
        {{ displayCount }}
      </span>

            <a-tooltip title="上一个 (Shift+Enter)">
        <a-button
          class="search-box__btn"
          size="small"
          :disabled="total === 0"
          @click="handlePrev"
        >
          <UpOutlined />
        </a-button>
      </a-tooltip>

      <a-tooltip title="下一个 (Enter)">
        <a-button
          class="search-box__btn"
          size="small"
          :disabled="total === 0"
          @click="handleNext"
        >
          <DownOutlined />
        </a-button>
      </a-tooltip>

      <a-tooltip title="关闭 (Esc)">
        <a-button
          class="search-box__btn"
          size="small"
          @click="handleClose"
        >
          <CloseOutlined />
        </a-button>
      </a-tooltip>
    </div>
  </Transition>
</template>

<script setup lang="ts">
import { ref, watch, computed, nextTick, toRef } from 'vue'
import type { Graph } from '@antv/x6'
import { SearchOutlined, UpOutlined, DownOutlined, CloseOutlined } from '@ant-design/icons-vue'
import { useNodeSearch } from './composables/useNodeSearch'

// ── Props ────────────────────────────────────────────────────────────────────
interface Props {
  visible: boolean
  graph: Graph | null
}

const props = defineProps<Props>()

// ── Emits ────────────────────────────────────────────────────────────────────
interface Emits {
  (e: 'update:visible', value: boolean): void
}

const emit = defineEmits<Emits>()

// ── 搜索逻辑 ──────────────────────────────────────────────────────────────────
const graphRef = toRef(props, 'graph')
const { keyword, results, currentIndex, total, next, prev, reset } = useNodeSearch(graphRef)

// ── 显示计数 ──────────────────────────────────────────────────────────────────
const displayCount = computed(() => {
  if (total.value === 0) return '0/0'
  return `${currentIndex.value + 1}/${total.value}`
})

// ── 输入框引用 ────────────────────────────────────────────────────────────────
const inputRef = ref<any>(null)

// ── 监听可见性，自动聚焦 ────────────────────────────────────────────────────────
watch(() => props.visible, (newVal) => {
  if (newVal) {
    nextTick(() => {
      inputRef.value?.focus()
    })
  } else {
    // 关闭时重置
    reset()
  }
})

// ── 监听 Shift+Enter（上一个） ──────────────────────────────────────────────
const handleKeydown = (e: KeyboardEvent) => {
  if (e.key === 'Enter' && e.shiftKey) {
    e.preventDefault()
    handlePrev()
  }
}

// ── 监听键盘事件 ──────────────────────────────────────────────────────────────
watch(() => props.visible, (newVal) => {
  if (newVal) {
    window.addEventListener('keydown', handleKeydown)
  } else {
    window.removeEventListener('keydown', handleKeydown)
  }
})

// ── 事件处理 ──────────────────────────────────────────────────────────────────
function handleNext() {
  next()
}

function handlePrev() {
  prev()
}

function handleClose() {
  emit('update:visible', false)
}
</script>

<style scoped lang="scss">
.search-box {
  position: absolute;
  top: 3px;
  right: 6px;
  z-index: 1000;
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 6px 10px;
  background: #ffffff;
  border-radius: 6px;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
  min-width: 280px;

  &__input {
    flex: 1;
    min-width: 150px;
  }

  &__count {
    font-size: 12px;
    color: #8c9bb5;
    white-space: nowrap;
    user-select: none;
  }

  &__btn {
    flex-shrink: 0;
  }
}

// ── 过渡动画 ──────────────────────────────────────────────────────────────────
.search-fade-enter-active,
.search-fade-leave-active {
  transition: all 0.2s ease;
}

.search-fade-enter-from {
  opacity: 0;
  transform: translateY(-10px);
}

.search-fade-leave-to {
  opacity: 0;
  transform: translateY(-10px);
}

// ── 响应式布局 ────────────────────────────────────────────────────────────────
@media (max-width: 768px) {
  .search-box {
    top: 60px;
    right: 10px;
    min-width: 240px;

    &__input {
      min-width: 120px;
    }
  }
}
</style>
