import type { CellView } from '@antv/x6'

/**
 * 光圈高亮器配置选项
 */
export interface HaloHighlighterOptions {
  /** 光圈填充颜色 */
  fill?: string
  /** 光圈描边颜色 */
  stroke?: string
  /** 描边宽度 */
  strokeWidth?: number
  /** 光圈透明度 */
  opacity?: number
  /** 光圈额外半径（在锚点半径基础上增加）*/
  haloSize?: number
  /** 是否启用脉动动画 */
  animated?: boolean
}

/**
 * 空操作高亮器：什么都不做，用于禁用某些高亮效果
 */
export const noop = {
  highlight(): void {
    // 不做任何操作
  },
  unhighlight(): void {
    // 不做任何操作
  },
}


/**
 * 自定义光圈高亮器：在锚点外围绘制半透明SVG circle
 * 用于拖线时标记可用目标锚点
 */
export const halo = {
  /**
   * 高亮显示：在锚点外围添加光圈
   */
  highlight(
    cellView: CellView,
    magnet: Element,
    options: HaloHighlighterOptions = {}
  ): Element {
    const {
      fill = 'rgba(82, 196, 26, 0.15)',
      stroke = '#52c41a',
      strokeWidth = 2,
      opacity = 0.6,
      haloSize = 0,
      animated = false,
    } = options

    // 🔑 只处理 <circle> 元素，跳过 <g>（X6有时会把整个节点容器作为magnet传入）
    if (magnet.tagName.toLowerCase() !== 'circle') {
      const dummy = document.createElementNS('http://www.w3.org/2000/svg', 'g')
      dummy.classList.add('x6-highlight-halo-group')
      magnet.appendChild(dummy)
      return dummy
    }

    const magnetCircle = magnet as SVGCircleElement

    // 🔑 计算光圈在"端口容器父级"坐标系下的绝对位置
    // 结构：<g class="x6-port">（含transform）-> <circle> (magnet)
    // 需要将光圈插入到 x6-port 的父级，才能脱离端口容器的 visibility 控制
    const portEl = magnetCircle.parentElement          // <g class="x6-port">
    const portGroupEl = portEl?.parentElement          // <g class="x6-port-group"> 或 node root

    const r = parseFloat(magnetCircle.getAttribute('r') || '6')
    const haloRadius = r + haloSize

    // 获取 magnet 在 portGroupEl 坐标系下的中心位置
    // 通过读取 portEl 的 transform matrix 来推算
    let absCx = 0
    let absCy = 0
    if (portEl instanceof SVGGraphicsElement && portGroupEl instanceof SVGGraphicsElement) {
      try {
        const matrix = (portEl as SVGGraphicsElement).getCTM()
        const parentMatrix = portGroupEl.getCTM()
        if (matrix && parentMatrix) {
          const invParent = parentMatrix.inverse()
          const local = invParent.multiply(matrix)
          absCx = local.e
          absCy = local.f
        }
      } catch {
        // fallback: 直接读取 transform 属性
        const transform = portEl.getAttribute('transform') || ''
        const match = transform.match(/matrix\([^,]+,[^,]+,[^,]+,[^,]+,([^,]+),([^)]+)\)/)
        if (match) {
          absCx = parseFloat(match[1])
          absCy = parseFloat(match[2])
        }
      }
    }

    const haloGroup = document.createElementNS('http://www.w3.org/2000/svg', 'g')
    haloGroup.classList.add('x6-highlight-halo-group')

    if (animated) {
      // 多层涟漪效果
      for (let i = 0; i < 3; i++) {
        const ripple = document.createElementNS('http://www.w3.org/2000/svg', 'circle')
        ripple.setAttribute('cx', String(absCx))
        ripple.setAttribute('cy', String(absCy))
        ripple.setAttribute('r', String(haloRadius))
        ripple.setAttribute('fill', fill)
        //ripple.setAttribute('stroke', stroke)
        ripple.setAttribute('opacity', String(opacity))
        //ripple.setAttribute('stroke-width', String(strokeWidth))
        ripple.setAttribute('pointer-events', 'none')
        // 🔑 配合 transform-box: fill-box，origin 必须用局部坐标 center center
        //    而不是 SVG 画布绝对坐标，否则 scale() 不绕圆心扩散
        ripple.style.transformOrigin = 'center center'
        ripple.style.transformBox = 'fill-box'
        ripple.classList.add('x6-highlight-halo', 'x6-highlight-halo--animated', `x6-highlight-halo--delay-${i}`)
        haloGroup.appendChild(ripple)
      }
    } else {
      // 静态光圈（单圈）
      const staticHalo = document.createElementNS('http://www.w3.org/2000/svg', 'circle')
      staticHalo.setAttribute('cx', String(absCx))
      staticHalo.setAttribute('cy', String(absCy))
      staticHalo.setAttribute('r', String(haloRadius))
      staticHalo.setAttribute('fill', fill)
      staticHalo.setAttribute('stroke', stroke)
      staticHalo.setAttribute('stroke-width', String(strokeWidth))
      staticHalo.setAttribute('opacity', String(opacity))
      staticHalo.setAttribute('pointer-events', 'none')
      staticHalo.classList.add('x6-highlight-halo')
      haloGroup.appendChild(staticHalo)
    }

    // 🔑 插入到端口容器的父级（portGroupEl），脱离 x6-port 的 visibility 控制
    if (portGroupEl) {
      portGroupEl.appendChild(haloGroup)
    } else if (portEl) {
      portEl.parentElement?.appendChild(haloGroup)
    }

    // 🔑 方案A：X6 在触发 magnetAvailable 之前会将端口 visibility 重置为 hidden
    // 光圈插在 portGroupEl 可绕过此限制，但锚点 <circle> 本身仍不可见
    // 在此强制将 magnet <circle> 设为 visible，确保锚点圆点与光圈同时显示
    magnetCircle.style.visibility = 'visible'

    return haloGroup
  },

  /**
   * 取消高亮：移除光圈组，并恢复锚点 <circle> 的 visibility
   */
  unhighlight(cellView: CellView, magnet: Element): void {
    // 光圈被插入到了端口容器的父级，所以向上两级查找并清理
    const portEl = (magnet as SVGCircleElement).parentElement      // <g class="x6-port">
    const portGroupEl = portEl?.parentElement                       // <g class="x6-port-group">
    const searchRoot = portGroupEl ?? portEl
    if (searchRoot) {
      searchRoot.querySelectorAll('.x6-highlight-halo-group').forEach((el) => el.remove())
    }
    // 恢复 magnet <circle> 的 visibility（交还给 X6 / setPortProp 管理）
    if (magnet instanceof SVGElement) {
      magnet.style.visibility = ''
    }
  },
}
