import type { DesignerMode, ModeCapabilities } from '../../../views/types/flow.types'

/**
 * 权限配置映射表类型
 * 允许为每个模式定义部分权限，未定义的将使用默认值
 */
export type PermissionConfigMap = {
  [K in DesignerMode]?: Partial<ModeCapabilities>
} & {
  // 支持自定义模式（字符串索引）
  [customMode: string]: Partial<ModeCapabilities>
}

/**
 * 权限解析函数类型
 * 接收模式名称，返回完整权限配置
 */
export type PermissionResolver = (mode: string) => ModeCapabilities

/**
 * 权限配置选项
 */
export interface PermissionOptions {
  /**
   * 当前模式
   */
  mode?: string

  /**
   * 方式1：直接传入当前模式的权限（会覆盖 permissionConfig）
   * 优先级最高
   */
  permissions?: Partial<ModeCapabilities>

  /**
   * 方式2：传入完整的模式-权限映射表
   * 会与内置配置深度合并
   */
  permissionConfig?: PermissionConfigMap

  /**
   * 方式3：传入权限解析函数（最灵活）
   * 如果提供此函数，将完全接管权限计算逻辑
   */
  getPermissions?: PermissionResolver

  /**
   * 是否启用权限继承（预留扩展）
   * 允许模式间继承关系，如 'admin' extends 'edit'
   */
  enableInheritance?: boolean
}

