/**
 * 深度合并两个权限对象
 * @param base 基础权限配置
 * @param override 覆盖的权限配置
 * @returns 合并后的权限配置
 */
export function mergePermissions(
  base: ModeCapabilities,
  override?: Partial<ModeCapabilities>,
): ModeCapabilities {
  if (!override) return { ...base }

  return {
    ...base,
    ...override,
  }
}

/**
 * 获取模式的最终权限配置
 * 合并优先级：内置默认 < permissionConfig < permissions
 *
 * @param mode 模式名称
 * @param options 权限选项
 * @returns 最终的权限配置
 */
export function resolvePermissions(
  mode: string,
  options: PermissionOptions = {},
): ModeCapabilities {
  const { permissions, permissionConfig, getPermissions } = options

  // 如果提供了自定义解析函数，直接使用
  if (getPermissions) {
    return getPermissions(mode)
  }

  // 1. 获取内置默认权限
  const builtinDefault = builtinPermissionPresets[mode as DesignerMode]

  // 如果是未知模式，使用 design 作为默认值
  const basePermissions = builtinDefault || builtinPermissionPresets.design

  // 2. 合并 permissionConfig 中的配置
  const configPermissions = permissionConfig?.[mode]
  let merged = mergePermissions(basePermissions, configPermissions)

  // 3. 合并直接传入的 permissions（优先级最高）
  merged = mergePermissions(merged, permissions)

  return merged
}
