<template>
  <div ref="wrapperRef" class="cvn-wrapper">
    <!-- 挂载点：slot 内容将通过 createApp 渲染到此 div -->
    <div ref="slotMountRef" class="cvn-slot-mount" />
    <!-- 无渲染函数时的占位（开发阶段排查用） -->
    <div v-if="showFallback" class="cvn-fallback">
      <span class="cvn-fallback__type">{{ currentNodeType }}</span>
      <span class="cvn-fallback__hint">未注册插槽</span>
    </div>
  </div>
</template>

<script setup lang="ts">
import {
  ref,
  shallowRef,
  watchEffect,
  onMounted,
  onUnmounted,
  inject,
  createApp,
  defineComponent,
  nextTick,
  type App,
} from 'vue'
import type { Node, Graph } from '@antv/x6'
import {
  globalNodeSlotRegistry,
  registryVersion,
  getHostAppContext,
  type NodeSlotScope,
} from './nodeSlotRegistry'

// ─── Props（由 @antv/x6-vue-shape 注入） ─────────────────────────────────────
const props = defineProps<{ node: Node }>()

// ─── X6 Graph 实例（由 @antv/x6-vue-shape 的 getGraph provide 注入） ─────────
const getGraph = inject<() => Graph>('getGraph')

// ─── DOM 引用 ─────────────────────────────────────────────────────────────────
const wrapperRef   = ref<HTMLElement | null>(null)
const slotMountRef = ref<HTMLElement | null>(null)

// ─── 当前 node-type（响应式：监听 X6 prop 变化） ──────────────────────────────
const currentNodeType = shallowRef<string>('')

// ─── 响应式 data 和 props（✅ 方案 B：提供给 slot 使用的响应式变量） ────────
const nodeData = shallowRef<Record<string, any>>(props.node.getData() || {})
const nodeLabel = ref<string>(props.node.getProp('label') as string || '')
const nodeState = ref<string>(props.node.getProp('_state') as string || 'default')  // ✅ 新增响应式 state

// ─── 内部挂载的 Vue app（用于卸载旧内容） ─────────────────────────────────────
let mountedApp: App | null = null

// ─── fallback 显示控制 ────────────────────────────────────────────────────────
const showFallback = ref(false)

// ─── 尺寸同步：读内容真实尺寸 → 通知 X6 resize ───────────────────────────────
function syncNodeSize(width: number, height: number) {
  if (width > 0 && height > 0) {
    const current = props.node.getSize()
    if (Math.abs(current.width - width) > 1 || Math.abs(current.height - height) > 1) {
      props.node.resize(width, height)
    }
  }
}

function syncSizeFromContent() {
  const mount = slotMountRef.value
  if (!mount) return

  const contentEl = mount.querySelector('[data-cvn-root]') as HTMLElement | null
  if (!contentEl) return

  const w = contentEl.offsetWidth
  const h = contentEl.offsetHeight
  syncNodeSize(w, h)
}

// ─── 核心：挂载 slot 渲染函数到 slotMountRef ──────────────────────────────────
function mountSlotContent(nodeType: string) {
  // 1. 卸载旧 app
  if (mountedApp) {
    mountedApp.unmount()
    mountedApp = null
  }

  // 2. 清空挂载容器
  if (slotMountRef.value) {
    slotMountRef.value.innerHTML = ''
  }

  // 3. 无 nodeType 时直接显示 fallback
  if (!nodeType) {
    showFallback.value = true
    return
  }

  // 4. 从全局注册表取渲染函数
  const renderFn = globalNodeSlotRegistry.get(nodeType)
  if (!renderFn) {
    showFallback.value = true
    return
  }
  showFallback.value = false

  // 5. 构造 scope，将响应式 data、label 和 state 传入 ✅
  const scope: NodeSlotScope = {
    node: props.node,
    graph: getGraph?.() ?? null,
    nodeType,
    data: nodeData,      // ✅ 响应式 data
    label: nodeLabel,    // ✅ 响应式 label
    state: nodeState,    // ✅ 响应式 state
  }

  // 6. 用 defineComponent 包装渲染函数
  const SlotWrapper = defineComponent({
    name: `CvnSlot_${nodeType}`,
    setup() {
      return () => renderFn(scope)
    },
  })

  // 7. 创建独立 Vue app，复制宿主 appContext 全局配置
  const app = createApp(SlotWrapper)

  const hostAppContext = getHostAppContext()
  if (hostAppContext) {
    Object.entries(hostAppContext.components).forEach(([name, comp]) => {
      app.component(name, comp as any)
    })
    Object.entries(hostAppContext.directives).forEach(([name, dir]) => {
      app.directive(name, dir as any)
    })
    const provides = (hostAppContext as any).provides
    if (provides) {
      const appProvides = (app as any)._context?.provides
      if (appProvides) {
        Object.assign(appProvides, provides)
      }
    }
  }

  // 8. 挂载到 DOM
  if (slotMountRef.value) {
    mountedApp = app
    app.mount(slotMountRef.value)

    // 9. nextTick + rAF 确保 Vue 渲染完成、浏览器布局完成后同步尺寸
    nextTick(() => {
      requestAnimationFrame(() => {
        syncSizeFromContent()
      })
    })
  }
}

// ─── 监听 node-type prop 变化（X6 setProp 触发 change:* 通配符事件） ────────────
function onPropChange({ key, current }: { key: string; current: any }) {
  console.log('[CommonVueNode] change:* event fired, key:', key, 'current:', current)

  // 根据具体的 key 更新对应的响应式变量
  if (key === 'node-type') {
    const newType = current as string || ''
    if (newType !== currentNodeType.value) {
      currentNodeType.value = newType
    }
  } else if (key === 'label') {
    const newLabel = current as string || ''
    if (newLabel !== nodeLabel.value) {
      nodeLabel.value = newLabel
    }
  } else if (key === '_state') {
    const newState = current as string || 'default'

    if (newState !== nodeState.value) {
      console.log('[CommonVueNode] Updating nodeState from', nodeState.value, 'to', newState)
      nodeState.value = newState
    }
  }
}

// ─── 监听 data 变化（X6 setData 触发 change:data 事件） ✅ 方案 B 核心 ─────
function onDataChange() {
  // 浅拷贝触发 shallowRef 的响应式更新
  nodeData.value = { ...props.node.getData() }
}

let stopWatcher: (() => void) | null = null

// ─── ResizeObserver：监听内容子元素，尺寸变化时同步给 X6 ──────────────────────
let resizeObserver: ResizeObserver | null = null

function startObservingContent() {
  const mount = slotMountRef.value
  if (!mount) return
  const contentEl = mount.querySelector('[data-cvn-root]') as HTMLElement | null
  if (!contentEl) return

  resizeObserver?.disconnect()
  resizeObserver = new ResizeObserver(() => {
    syncSizeFromContent()
  })
  resizeObserver.observe(contentEl)
}

// ─── 生命周期 ─────────────────────────────────────────────────────────────────
onMounted(() => {
  // 初始化 nodeType（优先读取顶层 'node-type'，如果不存在则从 data.nodeType 读取，向后兼容）
  currentNodeType.value =
    (props.node.getProp('node-type') as string) ||
    (props.node.getData()?.nodeType as string) ||
    ''

  // 监听 X6 所有属性变化（使用通配符事件）
  props.node.on('change:*', onPropChange)

  // ✅ 监听 X6 data 变化（方案 B 核心功能）
  props.node.on('change:data', onDataChange)

  // watchEffect：响应 registryVersion 或 currentNodeType 变化
  stopWatcher = watchEffect(() => {
    const _ver = registryVersion.value
    const nodeType = currentNodeType.value
    mountSlotContent(nodeType)
    // 挂载完成后（nextTick 内）启动 ResizeObserver 观察内容子元素
    nextTick(() => {
      requestAnimationFrame(() => {
        startObservingContent()
      })
    })
  })
})

onUnmounted(() => {
  stopWatcher?.()
  stopWatcher = null

  if (mountedApp) {
    mountedApp.unmount()
    mountedApp = null
  }

  props.node.off('change:*', onPropChange)
  props.node.off('change:data', onDataChange)  // ✅ 清理 data 监听

  resizeObserver?.disconnect()
  resizeObserver = null
})
</script>

<style scoped>
.cvn-wrapper {
  display: block;
  width: fit-content;
  height: fit-content;
  overflow: visible;
  box-sizing: border-box;
}

.cvn-slot-mount {
  display: block;
  width: fit-content;
  height: fit-content;
}

/* 未注册插槽占位 */
.cvn-fallback {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  width: 160px;
  height: 60px;
  border: 1.5px dashed #d9d9d9;
  border-radius: 6px;
  background: #fafafa;
  gap: 4px;
  user-select: none;
}

.cvn-fallback__type {
  font-size: 13px;
  font-weight: 600;
  color: #595959;
}

.cvn-fallback__hint {
  font-size: 11px;
  color: #bfbfbf;
}
</style>
