/**
 * FlowEdge - 自定义连线
 *
 * 基于 defaultConfig.ts 中的配置创建标准化的流程连线。
 * 参考 X6 官方示例：https://x6.antv.antgroup.com/api/registry/edge#example
 *
 * 使用方式：
 * 1. 创建连线时指定 shape: 'flow-edge'
 * 2. 或在 Graph 的 defaultEdge 中设置为默认连线类型
 *
 * @example
 * ```typescript
 * graph.addEdge({
 *   shape: 'flow-edge',
 *   source: 'node1',
 *   target: 'node2',
 *   labels: ['条件A'],
 * })
 * ```
 */

import { Graph } from '@antv/x6'
import { DEFAULT_CANVAS_CONFIG } from '../core/defaultConfig'

const config = DEFAULT_CANVAS_CONFIG.connection

/**
 * 注册自定义连线 flow-edge
 *
 * 使用 Graph.registerEdge 方法注册，参考官方文档：
 * https://x6.antv.antgroup.com/api/registry/edge
 */
Graph.registerEdge(
  'flow-edge',
  {
    inherit: 'edge',  // 继承内置 edge

    // ─── 连线样式配置 ───────────────────────────────────────────────────
    markup: [
      {
        tagName: 'path',
        selector: 'wrapper',  // 透明交互层，用于增大 hover 判定范围
        attrs: {
          fill: 'none',
          cursor: 'pointer',
        },
      },
      {
        tagName: 'path',
        selector: 'line',  // 可见的连线
        attrs: {
          fill: 'none',
          cursor: 'pointer',
        },
      },
    ],

    // ─── 连线属性配置 ───────────────────────────────────────────────────
    attrs: {
      // 透明交互层（用于增大 hover/click 判定范围）
      wrapper: {
        connection: true,
        stroke: 'transparent',  // 透明，不可见
        strokeWidth: config.interactionWidth,  // 使用配置的交互宽度
        strokeLinejoin: 'round',
        strokeLinecap: 'round',
        fill: 'none',
        cursor: 'pointer',
      },
      // 可见连线
      line: {
        connection: true,
        stroke: config.strokeColor,
        strokeWidth: config.strokeWidth,
        strokeLinejoin: 'round',
        strokeLinecap: 'round',
        targetMarker: {
          name: 'classic',
          size: 7
        },
      },
    },

    // ─── 路由和连接器配置 ───────────────────────────────────────────────
    router: {
      name: config.router,
      args: { padding: 20 },
    },

    connector: {
      name: config.connector,
      args: config.connector === 'rounded' ? { radius: 8 } : {},
    },

    // ─── Label 默认配置 ─────────────────────────────────────────────────
    defaultLabel: {
      markup: [
        {
          tagName: 'rect',
          selector: 'body',
        },
        {
          tagName: 'text',
          selector: 'label',
        },
      ],
      attrs: {
        label: {
          fill: config.label.textColor,
          fontSize: config.label.fontSize,
          fontWeight: config.label.fontWeight,
          textAnchor: config.label.textAnchor,
          textVerticalAnchor: config.label.textVerticalAnchor,
          pointerEvents: config.label.pointerEvents,
        },
        body: {
          ref: 'label',
          fill: config.label.backgroundColor,
          stroke: config.label.borderColor,
          strokeWidth: config.label.borderWidth,
          rx: config.label.borderRadius,
          ry: config.label.borderRadius,
          refWidth: (config.label.paddingX ?? config.label.padding) * 2,
          refHeight: (config.label.paddingY ?? config.label.padding) * 2,
          refX: -(config.label.paddingX ?? config.label.padding),
          refY: -(config.label.paddingY ?? config.label.padding) + (config.label.offsetY ?? 0),
        },
      },
      position: {
        distance: config.label.position,
      },
    },
  },
  true  // force=true 防止路由切换时重复注册报错
)
