import { ref, computed, watch, unref } from 'vue'
import type { Graph, Node } from '@antv/x6'
import type { FlowNodeData } from '../../../views/types/flow.types'
import type { Ref } from 'vue'

/**
 * 节点过滤函数类型
 * @param node 节点实例
 * @param keyword 搜索关键词（小写）
 * @returns true 表示节点匹配，false 表示不匹配
 */
export type NodeFilterFn = (node: Node, keyword: string) => boolean

/**
 * 节点搜索 Hook
 * 提供节点搜索、导航、高亮功能
 */
export function useNodeSearch(graphRef: Ref<Graph | null> | Graph | null) {
  // ── 状态 ─────────────────────────────────────────────────────────────────
  const keyword = ref('')
  const currentIndex = ref(0)
  const originalStyles = new Map<string, { stroke: string; strokeWidth: number }>()

  // ── 自定义过滤器（可选，不传则使用默认过滤逻辑） ─────────────────────────
  const customFilter = ref<NodeFilterFn | null>(null)

  // ── 默认过滤函数 ─────────────────────────────────────────────────────────
  /**
   * 默认过滤逻辑：搜索 X6原生label、data.label、节点ID
   * @param node 节点实例
   * @param lowerKeyword 小写关键词
   * @returns 是否匹配
   */
  function defaultFilter(node: Node, lowerKeyword: string): boolean {
    const data = node.getData() as FlowNodeData | undefined
    // 支持三种搜索字段（优先级：X6原生label > data.label > id）
    const nativeLabel = node.getProp('label') || node.label
    const dataLabel = data?.label || ''
    const id = node.id

    return nativeLabel.toLowerCase().includes(lowerKeyword) ||
        dataLabel.toLowerCase().includes(lowerKeyword) ||
        id.toLowerCase().includes(lowerKeyword)
  }

  // ── 计算搜索结果 ───────────────────────────────────────────────────────────
  const results = computed<Node[]>(() => {
    const graph = unref(graphRef)
    if (!graph || !keyword.value.trim()) {
      return []
    }

    const lowerKeyword = keyword.value.toLowerCase()
    const nodes = graph.getNodes()

    // 使用自定义过滤器或默认过滤器
    const filterFn = customFilter.value || defaultFilter

    return nodes.filter(node => filterFn(node, lowerKeyword))
  })

  // ── 总数 ──────────────────────────────────────────────────────────────────
  const total = computed(() => results.value.length)

    // ── 监听搜索结果变化，重置索引并聚焦第一个 ──────────────────────────────────────────────
  watch(results, (newResults) => {
    currentIndex.value = 0
    // 如果有结果，自动聚焦第一个节点
    if (newResults.length > 0) {
      focusNode(0)
    } else {
      // 无结果时清除高亮
      clearHighlight()
    }
  })

  // ── 聚焦节点（高亮 + 居中 + 选中） ──────────────────────────────────────────
  function focusNode(index: number) {
    const graph = unref(graphRef)
    if (!graph || results.value.length === 0) return

    const node = results.value[index]
    if (!node) return

    // 1. 清除之前的高亮
    clearHighlight()

    // 2. 保存原始样式
    if (!originalStyles.has(node.id)) {
      originalStyles.set(node.id, {
        stroke: node.attr('body/stroke') || '#8c9bb5',
        strokeWidth: node.attr('body/strokeWidth') || 1.5
      })
    }

    // 3. 高亮当前节点
    node.attr('body/stroke', '#1890ff')
    node.attr('body/strokeWidth', 3)

    // 4. 选中节点
    graph.select(node)

    // 5. 居中显示（带动画）
    graph.centerCell(node, {
      padding: 100,
      animation: {
        duration: 300,
        easing: 'ease-in-out'
      }
    })

    // 6. 如果缩放过小，调整到合适比例
    if (graph.zoom() < 0.8) {
      graph.zoomTo(1, {
        animation: { duration: 300 }
      })
    }
  }

  // ── 下一个 ────────────────────────────────────────────────────────────────
  function next() {
    if (results.value.length === 0) return

    currentIndex.value = (currentIndex.value + 1) % results.value.length
    focusNode(currentIndex.value)
  }

  // ── 上一个 ────────────────────────────────────────────────────────────────
  function prev() {
    if (results.value.length === 0) return

    currentIndex.value = currentIndex.value === 0
      ? results.value.length - 1
      : currentIndex.value - 1
    focusNode(currentIndex.value)
  }

  // ── 清除高亮 ──────────────────────────────────────────────────────────────
  function clearHighlight() {
    const graph = unref(graphRef)
    if (!graph) return

    originalStyles.forEach((style, nodeId) => {
      const node = graph.getCellById(nodeId)
      if (node) {
        node.attr('body/stroke', style.stroke)
        node.attr('body/strokeWidth', style.strokeWidth)
      }
    })
    originalStyles.clear()

    // 取消选中
    graph.unselect(graph.getSelectedCells())
  }

  // ── 重置 ──────────────────────────────────────────────────────────────────
  function reset() {
    keyword.value = ''
    currentIndex.value = 0
    clearHighlight()
  }

  // ── 通过索引选择节点（供下拉列表点击使用） ───────────────────────────────────
  /**
   * 通过索引选择并聚焦节点
   * @param index 节点在搜索结果中的索引
   */
  function selectByIndex(index: number) {
    const graph = unref(graphRef)
    if (!graph || index < 0 || index >= results.value.length) return

    // 更新当前索引
    currentIndex.value = index

    // 聚焦到指定节点
    focusNode(index)
  }

  // ── 获取节点标签（辅助方法） ───────────────────────────────────────────────
  /**
   * 获取节点的显示标签
   * 优先级：X6原生label > data.label > attrs.text.text > '未命名节点'
   * @param node X6 节点实例
   * @returns 节点标签字符串
   */
  function getNodeLabel(node: Node): string {
    // 优先读取 X6 原生 label（通过 getProp）
    const propLabel = node.getProp('label')
    if (propLabel) return String(propLabel)

    // 其次读取 data.label
    const data = node.getData() as FlowNodeData | undefined
    if (data?.label) return data.label

    // 最后尝试从 attrs 中读取（X6 内部存储）
    const attrs = node.getAttrs()
    if (attrs?.text?.text) return String(attrs.text.text)

    return '未命名节点'
  }

  // ── 设置自定义过滤器 ─────────────────────────────────────────────────────
  /**
   * 设置自定义节点过滤函数
   * @param filterFn 自定义过滤函数，传入 null 则恢复默认过滤逻辑
   *
   * @example
   * // 只搜索特定 shape 的节点
   * setFilter((node, keyword) => {
   *   return node.shape === 'rect' && node.getProp('label').includes(keyword)
   * })
   *
   * @example
   * // 恢复默认过滤
   * setFilter(null)
   */
  function setFilter(filterFn: NodeFilterFn | null) {
    customFilter.value = filterFn
  }

  return {
    keyword,
    results,
    currentIndex,
    total,
    next,
    prev,
    reset,
    clearHighlight,
    selectByIndex,
    getNodeLabel,
    setFilter
  }
}
