<template>
  <a-form layout="vertical" size="small">
    <a-form-item label="节点名称">
      <a-input v-model:value="form.label" @change="emitUpdate" />
    </a-form-item>
    <a-form-item label="分支数量">
      <a-input-number
        v-model:value="form.branchCount"
        :min="2" :max="8"
        style="width: 100%"
        @change="emitUpdate"
      />
    </a-form-item>
    <a-form-item label="完成条件">
      <a-radio-group v-model:value="form.parallelFinish" @change="emitUpdate">
                                <a-radio value="all">全部分支完成</a-radio>
        <a-radio value="any">任一分支完成</a-radio>
      </a-radio-group>
    </a-form-item>
    <a-alert
      type="info"
      show-icon
      :message="'并行分支将同时触发多条审批路径，请确保每条路径都能到达结束节点'"
    />
  </a-form>
</template>

<script setup lang="ts">
import { reactive, watch } from 'vue'
import type { Node } from '@antv/x6'
import type { FlowNodeData } from '../types/flow.types'

const props = defineProps<{ node: Node }>()
const emit  = defineEmits<{ (e: 'update', data: FlowNodeData): void }>()
const form = reactive<FlowNodeData>({ label: '', branchCount: 2, parallelFinish: 'all', ...props.node.getData() })
watch(() => props.node.getData(), (d) => { if (d) Object.assign(form, d) }, { deep: true })

function emitUpdate() { emit('update', { ...form }) }
</script>
