<template>
  <div class="fdl-root">
    <!-- 顶部工具栏插槽容器（高度随内容自适应） -->
    <div
      v-if="hasToolbarSlot"
      class="fdl-header"
      :style="{ display: capabilities.showToolbar ? '' : 'none' }"
    >
      <slot name="toolbar" v-bind="toolbarScope" />
    </div>

    <!-- 中间主体区域 -->
    <div class="fdl-body">
      <!-- 左侧节点面板插槽容器（宽度随内容自适应） -->
      <div
        v-if="hasPaletteSlot"
        class="fdl-palette"
        :style="{ display: capabilities.showNodePalette ? '' : 'none' }"
      >
        <slot name="palette" v-bind="paletteScope" />
      </div>

      <!-- 中间画布区域（自动填满剩余空间） -->
      <div class="fdl-canvas">
        <div ref="containerRef" class="fdl-canvas__inner"></div>
                <!-- 小地图容器 + 展开/收起按钮 -->
        <div
          v-if="minimapVisible"
          class="fdl-canvas__minimap-wrapper"
          :class="{ 'fdl-canvas__minimap-wrapper--collapsed': minimapCollapsed }"
        >
          <div ref="minimapRef" class="fdl-canvas__minimap"></div>
          <a-tooltip :title="minimapCollapsed ? '展开小地图' : '收起小地图'" placement="left">
            <div class="fdl-minimap__toggle" @click="toggleMinimap">
              <ExpandOutlined v-if="minimapCollapsed" class="fdl-minimap__toggle-icon" />
              <ShrinkOutlined v-else class="fdl-minimap__toggle-icon" />
            </div>
          </a-tooltip>
        </div>
        <!-- 右键菜单（支持插槽穿透自定义） -->
        <FlowContextMenus ref="contextMenuRef" @action="handleMenuAction">
          <template v-if="slots['node-menu']" #node-menu="scope">
            <slot name="node-menu" v-bind="scope" />
          </template>
          <template v-if="slots['edge-menu']" #edge-menu="scope">
            <slot name="edge-menu" v-bind="scope" />
          </template>
          <template v-if="slots['canvas-menu']" #canvas-menu="scope">
            <slot name="canvas-menu" v-bind="scope" />
          </template>
        </FlowContextMenus>
        <!-- 节点/连线 Tooltip（支持插槽自定义） -->
        <div
          ref="tooltipRef"
          class="fdl-tooltip"
          :class="[
            {
              'fdl-tooltip--custom':
                (tooltipScope.type === 'node' && hasNodeTooltipSlot) ||
                (tooltipScope.type === 'edge' && hasEdgeTooltipSlot) ||
                hasTooltipSlot
            },
            tooltipScope.customClassName  // 新增：动态绑定自定义 className
          ]"
          :style="tooltipStyle"
        >
          <!-- 优先级 1: 细粒度插槽 -->
          <slot
            v-if="tooltipScope.type === 'node' && hasNodeTooltipSlot"
            name="node-tooltip"
            :node="tooltipScope.node"
            :data="tooltipScope.data"
            :designer="designer"
            :graph="designer?.getGraph() ?? null"
          />
          <slot
            v-else-if="tooltipScope.type === 'edge' && hasEdgeTooltipSlot"
            name="edge-tooltip"
            :edge="tooltipScope.edge"
            :data="tooltipScope.data"
            :designer="designer"
            :graph="designer?.getGraph() ?? null"
          />
          <!-- 优先级 2: 统一插槽 -->
          <slot
            v-else-if="hasTooltipSlot"
            name="tooltip"
            :type="tooltipScope.type"
            :node="tooltipScope.node"
            :edge="tooltipScope.edge"
            :data="tooltipScope.data"
          />
          <!-- 优先级 3: 默认渲染 -->
          <template v-else>
            <span data-role="tooltip-content"></span>
            <div
              v-if="tooltipArrowVisible"
              class="fdl-tooltip__arrow"
              :style="tooltipArrowStyle"
            ></div>
          </template>
        </div>
        <!-- 节点搜索框：有插槽则渲染插槽，无插槽渲染内置 SearchBox -->
        <template v-if="searchVisible && capabilities.showSearch">
          <slot
            v-if="hasSearchBoxSlot"
            name="search-box"
            :keyword="searchScope.keyword"
            :results="searchScope.results"
            :current-index="searchScope.currentIndex"
            :total="searchScope.total"
            :next="searchScope.next"
            :prev="searchScope.prev"
            :reset="searchScope.reset"
            :close="searchScope.close"
            :select-by-index="searchScope.selectByIndex"
            :get-node-label="searchScope.getNodeLabel"
            :set-filter="searchScope.setFilter"
            :designer="designer"
            :graph="designer?.getGraph() ?? null"
          />
          <SearchBox
            v-else
            v-model:visible="searchVisible"
            :graph="designer?.getGraph() ?? null"
          />
        </template>
      </div>

      <!-- 右侧属性面板插槽容器（宽度随内容自适应） -->
      <div
        v-if="hasPropertiesSlot"
        class="fdl-properties"
        :style="{ display: capabilities.showPropertiesPanel ? '' : 'none' }"
      >
        <slot name="properties" v-bind="propertiesScope" />
      </div>
    </div>

    <!-- 画布配置抽屉（内部固定，不作为插槽） -->
<!--    <CanvasSettings-->
<!--      v-model:visible="settingsVisible"-->
<!--      @reload-graph="handleReloadGraph"-->
<!--    />-->
  </div>
</template>

<script setup lang="ts">
import { ref, computed, onMounted, onUnmounted, provide, useSlots, watchEffect, watch, createApp, defineComponent, h, reactive, getCurrentInstance } from 'vue'
import {
  updateNodeSlotRegistry,
  setHostAppContext,
  type SlotRenderFn,
} from './nodeSlotRegistry'
import { message } from 'ant-design-vue'
import { ExpandOutlined, ShrinkOutlined } from '@ant-design/icons-vue'
import { FlowDesigner, type FlowDesignerOptions } from './core'
import FlowContextMenus from './ContextMenus/index.vue'
//import CanvasSettings from './CanvasSettings.vue'
import SearchBox from './SearchBox.vue'
import { useNodeSearch } from './composables/useNodeSearch'
import type {
  FlowData,
  DesignerMode,
  FlowNodeShape,
  FlowNodeData,
  ModeCapabilities,
  CanvasConfig,
  ShortcutMap,
  ShortcutConfig,
} from '../../views/types/flow.types'
import type { PermissionOptions } from './types/permissions'
import type {
  BeforeNodeAddEvent,
  AfterNodeAddEvent,
  BeforeNodeRemoveEvent,
  AfterNodeRemoveEvent,
  BeforeEdgeAddEvent,
  AfterEdgeAddEvent,
  BeforeEdgeRemoveEvent,
  AfterEdgeRemoveEvent,
  BeforeNodeHoverEvent,
  AfterNodeHoverEvent,
  BeforeNodeSelectEvent,
  AfterNodeSelectEvent,
  BeforeEdgeHoverEvent,
  AfterEdgeHoverEvent,
  BeforeEdgeSelectEvent,
  AfterEdgeSelectEvent,
} from './types/events'
import type {
  NodeStateRendererMap,
  EdgeStateRendererMap,
  PortStateRenderers,
  NodeTooltipRenderer,
  TooltipRenderer,
} from './types/render'
import type { Graph, Node } from '@antv/x6'
import { register } from '@antv/x6-vue-shape'
import { Graph as GraphClass, Shape } from '@antv/x6'

// ─── Props ──────────────────────────────────────────────────────────────────

const props = withDefaults(defineProps<{
  /** 初始模式，默认 design。支持运行时受控切换（支持自定义模式名） */
  mode?: string
  /**
   * 权限配置映射表（定义多个模式的权限）
   * 示例：{ review: { canEdit: false, canExport: true } }
   */
  permissionConfig?: PermissionOptions['permissionConfig']
  /**
   * 直接覆盖当前模式的权限（优先级最高）
   * 示例：{ canCopy: false }
   */
  permissions?: PermissionOptions['permissions']
  /**
   * 自定义权限解析函数（完全接管权限计算）
   * 示例：(mode) => calculatePermissionsByUserRole(mode)
   */
  getPermissions?: PermissionOptions['getPermissions']
  /**
   * 按模式覆盖默认权限，深度合并。
   * @deprecated 使用 permissionConfig 替代
   * 示例：{ design: { canPublish: false } }
   */
  modeCapabilities?: Partial<Record<DesignerMode, Partial<ModeCapabilities>>>
  /** 画布配置，深度合并到默认配置 */
  canvasConfig?: Partial<CanvasConfig>
  /**
   * 快捷键配置
   * 支持两种方式：
   * 1. keyMap：重新映射内置操作的快捷键（推荐，自动继承权限和逻辑）
   * 2. custom：完全自定义的快捷键处理（高级用法）
   *
   * @example
   * ```typescript
   * // 方式 1：简单键位映射
   * shortcuts: {
   *   keyMap: {
   *     [ShortcutAction.COPY]: 'ctrl+e',  // 复制改为 Ctrl+E
   *   }
   * }
   *
   * // 兼容旧 API：直接传 ShortcutMap
   * shortcuts: {
   *   'ctrl+shift+s': () => alert('自定义保存')
   * }
   * ```
   */
  shortcuts?: ShortcutConfig | ShortcutMap

  // ─── 生命周期钩子 ─────────────────────────────────────────────────────────
  /**
   * 节点添加前钩子，返回 false 可阻止添加
   * @param event - 包含 node、source、position 信息
   * @returns boolean | Promise<boolean> - false 表示阻止操作
   */
  beforeNodeAdd?: (event: BeforeNodeAddEvent) => boolean | Promise<boolean>
  /**
   * 节点添加后钩子
   * @param event - 包含 nodeId、node、source、success、timestamp 信息
   */
  afterNodeAdd?: (event: AfterNodeAddEvent) => void
  /**
   * 节点删除前钩子，返回 false 可阻止删除
   * @param event - 包含 node、nodeId、source 信息
   * @returns boolean | Promise<boolean> - false 表示阻止操作
   */
  beforeNodeRemove?: (event: BeforeNodeRemoveEvent) => boolean | Promise<boolean>
  /**
   * 节点删除后钩子
   * @param event - 包含 nodeId、nodeData、source、success、timestamp 信息
   */
  afterNodeRemove?: (event: AfterNodeRemoveEvent) => void
  /**
   * 连线添加前钩子，返回 false 可阻止连接
   * @param event - 包含 sourceCell、targetCell、sourceMagnet、targetMagnet 信息
   * @returns boolean | Promise<boolean> - false 表示阻止操作
   */
  beforeEdgeAdd?: (event: BeforeEdgeAddEvent) => boolean | Promise<boolean>
  /**
   * 连线添加后钩子
   * @param event - 包含 edge、edgeId、sourceNodeId、targetNodeId、source、success、timestamp 信息
   */
  afterEdgeAdd?: (event: AfterEdgeAddEvent) => void
  /**
   * 连线删除前钩子，返回 false 可阻止删除
   * @param event - 包含 edge、edgeId、sourceNodeId、targetNodeId、source 信息
   * @returns boolean | Promise<boolean> - false 表示阻止操作
   */
  beforeEdgeRemove?: (event: BeforeEdgeRemoveEvent) => boolean | Promise<boolean>
  /**
   * 连线删除后钩子
   * @param event - 包含 edgeId、edgeData、sourceNodeId、targetNodeId、source、success、timestamp 信息
   */
  afterEdgeRemove?: (event: AfterEdgeRemoveEvent) => void
  /**
   * Graph 初始化前钩子，在 new FlowDesigner 之前调用
   * 可用于在初始化之前修改配置或执行准备工作
   * @param options - FlowDesigner 配置对象（可修改）
   * @returns void | Promise<void>
   */
  beforeGraphInit?: (options: FlowDesignerOptions) => void | Promise<void>
  /**
   * 数据加载完成后钩子
   * @param data - 加载的流程数据
   */
  afterDataLoaded?: (data: FlowData) => void

  // ─── 节点/边交互生命周期钩子 ─────────────────────────────────────────────────
  /**
   * 节点 hover 前钩子，返回 false 可阻止 hover 效果
   * @param event - 包含 node、event、currentState 信息
   * @returns boolean - false 表示阻止 hover
   */
  beforeNodeHover?: (event: BeforeNodeHoverEvent) => boolean

  /**
   * 节点 hover 后钩子
   * @param event - 包含 node、event、stateChanged、timestamp 信息
   */
  afterNodeHover?: (event: AfterNodeHoverEvent) => void

  /**
   * 节点选中前钩子，返回 false 可阻止选中
   * @param event - 包含 node、event、isAlreadySelected 信息
   * @returns boolean - false 表示阻止选中
   */
  beforeNodeSelect?: (event: BeforeNodeSelectEvent) => boolean

  /**
   * 节点选中后钩子
   * @param event - 包含 nodeId、node、event、success、timestamp 信息
   */
  afterNodeSelect?: (event: AfterNodeSelectEvent) => void

  /**
   * 边 hover 前钩子，返回 false 可阻止 hover 效果
   * @param event - 包含 edge、event、currentState 信息
   * @returns boolean - false 表示阻止 hover
   */
  beforeEdgeHover?: (event: BeforeEdgeHoverEvent) => boolean

  /**
   * 边 hover 后钩子
   * @param event - 包含 edge、event、stateChanged、timestamp 信息
   */
  afterEdgeHover?: (event: AfterEdgeHoverEvent) => void

  /**
   * 边选中前钩子，返回 false 可阻止选中
   * @param event - 包含 edge、event、isAlreadySelected 信息
   * @returns boolean - false 表示阻止选中
   */
  beforeEdgeSelect?: (event: BeforeEdgeSelectEvent) => boolean

  /**
   * 边选中后钩子
   * @param event - 包含 edgeId、edge、event、success、timestamp 信息
   */
  afterEdgeSelect?: (event: AfterEdgeSelectEvent) => void

  // ─── 状态渲染钩子 ─────────────────────────────────────────────────────────
  /**
   * 节点状态渲染器映射表
   * 支持覆盖内置状态（default、hover、selected）和添加自定义状态
   * @example
   * ```typescript
   * {
   *   hover: (node) => ({
   *     apply: (cell) => cell.attr('body/stroke', 'red'),
   *     cleanup: (cell) => cell.attr('body/stroke', '#d9d9d9')
   *   }),
   *   error: (node) => ({
   *     apply: (cell) => cell.attr('body/fill', '#ffebee')
   *   })
   * }
   * ```
   */
  nodeStateRenderers?: NodeStateRendererMap

  /**
   * 连线状态渲染器映射表
   * 支持覆盖内置状态（default、hover、selected、flowing、dimmed）和添加自定义状态
   * @example
   * ```typescript
   * {
   *   hover: (edge) => ({
   *     apply: (cell) => cell.attr('line/stroke', 'blue'),
   *     cleanup: (cell) => cell.attr('line/stroke', '#8c8c8c')
   *   }),
   *   processing: (edge) => ({
   *     apply: (cell) => cell.attr('line/strokeDasharray', '5, 5')
   *   })
   * }
   * ```
   */
  edgeStateRenderers?: EdgeStateRendererMap

  /**
   * 锚点样式钩子：在锚点样式即将被设置前调用，可返回 PortStyle 覆盖默认样式。
   *
   * @param node      当前节点
   * @param portState 锚点即将进入的状态：
   *   - 'default'    节点不活跃，锚点隐藏/恢复默认
   *   - 'node-hover' 鼠标悬停节点，锚点显示
   *   - 'port-hover' 鼠标悬停在某个锚点上
   *   - 'connecting' 正在拖出连线，所有节点锚点显示
   *   - 'selected'   节点被选中，锚点显示
   * @returns PortStyle 对象（只需返回要覆盖的字段），或 undefined 使用默认样式
   *
   * @example
   * ```typescript
   * const portStateRenderers: PortStateRenderers = (node, portState) => {
   *   if (node.shape === 'condition-node' && portState === 'connecting') {
   *     return { fill: '#fff', stroke: '#52c41a', size: 8, strokeWidth: 2 }
   *   }
   * }
   * ```
   */
  portStateRenderers?: PortStateRenderers

  /**
   * 统一的 Tooltip 渲染控制钩子（推荐）
   * 在权限判断之后、显示 tooltip 之前调用，可用于控制节点和连线 tooltip 的显示和样式
   * 
   * @param cell - 当前元素（Node 或 Edge）
   * @param data - 元素的业务数据
   * @returns 
   *   - `false`: 不显示 tooltip
   *   - `string`: 自定义 className，会添加到 tooltip 容器上
   *   - `undefined` 或 `true`: 使用默认行为
   * 
   * @example
   * ```typescript
   * const tooltipRenderer = (cell, data) => {
   *   if (cell.isNode()) {
   *     // 节点逻辑
   *     if (cell.shape === 'start-node') return false
   *     if (data.status === 'error') return 'tooltip-error'
   *   } else if (cell.isEdge()) {
   *     // 连线逻辑
   *     const labels = cell.getLabels()
   *     const labelText = labels[0]?.attrs?.text?.text || ''
   *     if (labelText.includes('错误')) return 'tooltip-edge-error'
   *   }
   *   return undefined
   * }
   * ```
   */
  tooltipRenderer?: TooltipRenderer

  /**
   * 节点 Tooltip 渲染控制钩子（向后兼容）
   * @deprecated 推荐使用 tooltipRenderer，可以同时控制节点和连线的 tooltip
   * 
   * @param node - 当前节点
   * @param data - 节点的业务数据
   * @returns 
   *   - `false`: 不显示 tooltip
   *   - `string`: 自定义 className
   *   - `undefined` 或 `true`: 默认行为
   */
  nodeTooltipRenderer?: NodeTooltipRenderer
}>(), {
  mode: 'design',
})

// ─── Emits ──────────────────────────────────────────────────────────────────

const emit = defineEmits<{
  (e: 'ready',designer: FlowDesigner, graph: Graph ): void
  (e: 'mode-change', mode: DesignerMode): void
  (e: 'save', data: FlowData): void
  (e: 'error', error: Error): void
  (e: 'selection-change', cells: Array<{ id: string; isNode: () => boolean }>): void
}>()

// ─── Refs ────────────────────────────────────────────────────────────────────

const containerRef = ref<HTMLElement>()
const minimapRef = ref<HTMLElement>()
const tooltipRef = ref<HTMLElement>()
const contextMenuRef = ref<InstanceType<typeof FlowContextMenus> | null>(null)

// ─── 状态 ────────────────────────────────────────────────────────────────────

const zoomPercent = ref(100)
const hasSelection = ref(false)
const canPaste = ref(false)
const canGroup = ref(false)
const canUngroup = ref(false)
const currentMode = ref<DesignerMode>(props.mode)
const settingsVisible = ref(false)
const canUndo = ref(false)
const canRedo = ref(false)

let designer: FlowDesigner | null = null

// ─── 插槽检测 ─────────────────────────────────────────────────────────────────

const slots = useSlots()
const hasToolbarSlot = computed(() => !!slots.toolbar)
const hasPaletteSlot = computed(() => !!slots.palette)
const hasPropertiesSlot = computed(() => !!slots.properties)
const hasSearchBoxSlot = computed(() => !!slots['search-box'])
const hasTooltipSlot = computed(() => !!slots.tooltip)
const hasNodeTooltipSlot = computed(() => !!slots['node-tooltip'])
const hasEdgeTooltipSlot = computed(() => !!slots['edge-tooltip'])
const hasEdgeLabelSlot = computed(() => !!slots['edge-label'])

// ─── Tooltip 状态管理 ──────────────────────────────────────────────────────────

const tooltipScope = ref<{
  visible: boolean
  type: 'node' | 'edge' | null
  node: any
  edge: any
  data: any
  customClassName?: string  // 新增：自定义 className
}>({
  visible: false,
  type: null,
  node: null,
  edge: null,
  data: null,
  customClassName: undefined,
})

// 占位 Ref，需要在搜索逻辑之前声明（搜索依赖 _designerRef）
const _designerRef = ref<FlowDesigner | null>(null)

// ── 搜索逻辑（插槽模式下由 Layout 持有，透传给外部插槽 scope） ──────────────
// 使用 _designerRef（响应式）而非 designer（普通变量），确保 graph 变化能触发重新计算
const _graphRef = computed(() => _designerRef.value?.getGraph() ?? null)
const {
  keyword: _searchKw,
  results: _searchResults,
  currentIndex: _searchIdx,
  total: _searchTotal,
  next: _searchNext,
  prev: _searchPrev,
  reset: _searchReset,
  selectByIndex: _searchSelectByIndex,
  getNodeLabel: _searchGetNodeLabel,
  setFilter: _searchSetFilter,
} = useNodeSearch(_graphRef)

const searchScope = computed(() => ({
  keyword: _searchKw,
  results: _searchResults,
  currentIndex: _searchIdx,
  total: _searchTotal,
  next: _searchNext,
  prev: _searchPrev,
  reset: _searchReset,
  close: () => { searchVisible.value = false },
  selectByIndex: _searchSelectByIndex,
  getNodeLabel: _searchGetNodeLabel,
  setFilter: _searchSetFilter,
}))

// ─── 内置默认权限表 ──────────────────────────────────────────────────────────

// 权限版本号，用于强制刷新 capabilities computed
const capabilitiesVersion = ref(0)

const defaultCapabilitiesMap: Record<DesignerMode, ModeCapabilities> = {
  design: {
    showToolbar: true, showNodePalette: true, showPropertiesPanel: true, showContextMenu: true,
    canDrag: true, canConnect: true, canDelete: true, canCopy: true,
    canPaste: true, canGroup: true, canImport: true,
    canExport: true, canUndo: true, canRedo: true, canZoom: true, canPan: true,
    canFitView: true, canResetView: true, canMultipleSelect: true, canSelectAll: true, canToFront: true, canToBack: true,
    canAlign: true, canAlignLeft: true, canAlignRight: true, canAlignTop: true, canAlignBottom: true,
    canHoverNode: true, canHoverEdge: true, canSelectNode: true, canSelectEdge: true,
    showMinimap: true,  // 设计模式显示小地图
  },
  readonly: {
    showToolbar: true, showNodePalette: false, showPropertiesPanel: true, showContextMenu: true,
    canDrag: false, canConnect: false, canDelete: false, canCopy: false,
    canPaste: false, canGroup: false, canImport: false,
    canExport: true, canUndo: false, canRedo: false, canZoom: true, canPan: true,
    canFitView: true, canResetView: true, canMultipleSelect: true, canSelectAll: true, canToFront: false, canToBack: false,
    canAlign: false, canAlignLeft: false, canAlignRight: false, canAlignTop: false, canAlignBottom: false,
    canHoverNode: true, canHoverEdge: true, canSelectNode: true, canSelectEdge: true,
    showMinimap: true,  // 只读模式显示小地图，方便导航
  },
  preview: {
    showToolbar: false, showNodePalette: false, showPropertiesPanel: false, showContextMenu: false,
    canDrag: false, canConnect: false, canDelete: false, canCopy: false,
    canPaste: false, canGroup: false, canImport: false,
    canExport: true, canUndo: false, canRedo: false, canZoom: true, canPan: true,
    canFitView: false, canResetView: false, canMultipleSelect: false, canSelectAll: false, canToFront: false, canToBack: false,
    canAlign: false, canAlignLeft: false, canAlignRight: false, canAlignTop: false, canAlignBottom: false,
    canHoverNode: false, canHoverEdge: false, canSelectNode: false, canSelectEdge: false,
    showMinimap: false,  // 预览模式隐藏小地图，保持界面简洁
  },
}

/**
 * 当前模式的实际权限
 * - 如果 designer 已初始化，使用 ModeManager 的权限系统
 * - 否则使用内置默认值（初始化前的占位）
 */
const capabilities = computed<ModeCapabilities>(() => {
  // 如果 designer 已初始化，使用其权限系统（支持完整的权限合并逻辑）
  if (_designerRef.value) {
    // ⚠️ 重要：显式访问 currentMode.value 和 capabilitiesVersion.value 以建立响应式依赖
    // 这样当 currentMode 或权限配置改变时，Vue 会重新计算 capabilities
    const _ = currentMode.value  // 触发依赖追踪
    const __ = capabilitiesVersion.value  // 强制刷新机制

    return _designerRef.value.mode.getCapabilities()
  }

  // designer 初始化前的占位值
  const base = defaultCapabilitiesMap[currentMode.value as DesignerMode] || defaultCapabilitiesMap.design

  // 初始化前也应用 props.permissions 覆盖（保证初始 UI 正确）
  if (props.permissions) {
    return { ...base, ...props.permissions }
  }

  // 向后兼容：支持旧的 modeCapabilities prop
  const override = props.modeCapabilities?.[currentMode.value as DesignerMode]
  if (override) {
    return { ...base, ...override }
  }

  return base
})

// ─── Provide（给插槽内的子组件使用） ─────────────────────────────────────────

provide('designer', computed(() => designer ?? null))
provide('graph', computed(() => designer?.getGraph() ?? null))
provide('designerMode', currentMode)
provide('capabilities', capabilities)

// 占位 Ref，在 onMounted 内同步
const _selectedCells = ref<import('@/types/flow.types').SelectedCell[]>([])
const _canvasConfig = ref<import('@/types/flow.types').CanvasConfig | null>(null)
// _designerRef 已在上方搜索逻辑区域提前声明

// 小地图折叠状态——Layout 侧独立 ref，由 designer.toggleMinimap() 返回值同步
const minimapCollapsed = ref(true)
// 节点搜索框可见状态
const searchVisible = ref(false)

// 小地图是否显示：prop 开关 且 画布配置里的 minimap.enabled 同时为 true
// 小地图是否显示：权限 + 画布配置 + prop 开关三重控制
const minimapVisible = computed(() => {
  // 1. 权限检查：必须有 showMinimap 权限
  if (!capabilities.value.showMinimap) return false

  // 2. 画布配置检查
  if (!(_canvasConfig.value?.minimap.enabled ?? true)) return false

  // 3. prop 开关检查（向后兼容）
  return true
})

function toggleMinimap() {
  if (_designerRef.value) {
    minimapCollapsed.value = _designerRef.value.toggleMinimap()
  }
}

// ─── Tooltip 样式 computed ─────────────────────────────────────────────────────
const tooltipStyle = computed(() => {
  // ✅ 优先检查 visible 状态
  // 如果 nodeTooltipRenderer 返回了 false，tooltipScope.visible 会被设置为 false
  // 通过 :style 的 display: 'none' 覆盖 NodeStateManager 直接设置的 display: 'block'
  if (!tooltipScope.value.visible) {
    return {
      display: 'none'
    }
  }

  // 如果使用了自定义插槽，返回清空样式（让插槽完全控制）
  const isCustom =
    (tooltipScope.value.type === 'node' && hasNodeTooltipSlot.value) ||
    (tooltipScope.value.type === 'edge' && hasEdgeTooltipSlot.value) ||
    hasTooltipSlot.value

  if (isCustom) {
    return {
      display: 'block',  // 🔑 关键：显式设置 display: block
      background: 'transparent',
      padding: '0',
      boxShadow: 'none',
      borderRadius: '0',
      color: 'inherit',
      fontSize: 'inherit',
      fontWeight: 'inherit',
      whiteSpace: 'normal',
    }
  }

  // 使用配置的默认样式
  const cfg = _canvasConfig.value?.tooltip
  if (!cfg) return { display: 'block' }  // 至少返回 display: block

  return {
    display: 'block',  // 🔑 关键：显式设置 display: block，覆盖 CSS 的 display: none
    fontSize: `${cfg.fontSize}px`,
    fontWeight: String(cfg.fontWeight),
    color: cfg.color,
    background: cfg.backgroundColor,
    padding: cfg.padding,
    borderRadius: `${cfg.borderRadius}px`,
    boxShadow: cfg.boxShadow,
    zIndex: cfg.zIndex,
    maxWidth: cfg.maxWidth ? `${cfg.maxWidth}px` : undefined,
    whiteSpace: cfg.whiteSpace,
  }
})

const tooltipArrowStyle = computed(() => {
  const cfg = _canvasConfig.value?.tooltip
  if (!cfg || !cfg.arrowEnabled) return { display: 'none' }

  return {
    borderTopWidth: `${cfg.arrowSize}px`,
    borderTopColor: cfg.arrowColor,
    borderLeftWidth: `${cfg.arrowSize / 2}px`,
    borderRightWidth: `${cfg.arrowSize / 2}px`,
  }
})

const tooltipArrowVisible = computed(() => {
  return _canvasConfig.value?.tooltip?.arrowEnabled !== false
})

provide('selectedCells', _selectedCells)
provide('canvasConfig', _canvasConfig)
provide('updateCanvasConfig', (patch: Partial<import('@/types/flow.types').CanvasConfig>) => {
  designer?.updateCanvasConfig(patch)
  if (designer) _canvasConfig.value = designer.getCanvasConfig()
})
provide('flowDesigner', _designerRef)

// ─── node slot 注册表（方案一核心） ──────────────────────────────────────────
//
// 约定：业务层通过具名插槽 `node-<type>` 向 FlowDesignerLayout 传入节点渲染函数。
// 例如：<template #node-custom-task="{ node }">...</template>
//
// 由于 @antv/x6-vue-shape 在 X6 内部使用独立 Vue app 挂载节点组件，
// provide/inject 无法跨 app 实例传递，因此改用模块级单例全局 Map：
//   1. FlowDesignerLayout 将 slot 渲染函数写入 globalNodeSlotRegistry
//   2. CommonVueNode 直接 import 该 Map 读取
//   3. registryVersion 递增触发 CommonVueNode 的 watchEffect 重新渲染

const NODE_SLOT_PREFIX = 'node-'

// 保存宿主 appContext（在 setup 阶段同步执行，此时 getCurrentInstance 可用）
const instance = getCurrentInstance()
if (instance?.appContext) {
  setHostAppContext(instance.appContext)
}

// 🔧 修复：防止 watchEffect 无限循环 - 追踪 slots 的变化
const prevSlotsKey = ref<string>('')

// 每次 slots 变化时，全量同步到全局注册表
watchEffect(() => {
  const entries = new Map<string, SlotRenderFn>()
  for (const [slotName, slotFn] of Object.entries(slots)) {
    if (slotName.startsWith(NODE_SLOT_PREFIX) && typeof slotFn === 'function') {
      const nodeType = slotName.slice(NODE_SLOT_PREFIX.length)
      if (nodeType) {
        entries.set(nodeType, slotFn as SlotRenderFn)
      }
    }
  }

  // 🔧 修复：生成当前 slots 的唯一标识（基于节点类型名称）
  const currentSlotsKey = Array.from(entries.keys()).sort().join(',')

  // 🔧 修复：只有 slots 真正变化时才更新 registry
  if (currentSlotsKey !== prevSlotsKey.value) {
    prevSlotsKey.value = currentSlotsKey
    updateNodeSlotRegistry(entries)
  }
})

// ─── 初始化 FlowDesigner ──────────────────────────────────────────────────────

// 定义生命周期拦截器回调
function createLifecycleCallbacks(): Partial<import('./core/FlowDesigner').FlowDesignerCallbacks> {
  return {
    // 节点添加前拦截器
    beforeNodeAdd: async (node, source) => {
      if (!props.beforeNodeAdd) return true // 没有钩子，默认允许

      const event: BeforeNodeAddEvent = {
        node,
        source: source as import('./types/events').OperationSource,
        position: node.getPosition(),
      }

      const result = await props.beforeNodeAdd(event)
      return result !== false // 返回 false 才阻止，undefined/true 都允许
    },

    // 节点删除前拦截器
    beforeNodeRemove: async (node, source) => {
      if (!props.beforeNodeRemove) return true

      const event: BeforeNodeRemoveEvent = {
        node,
        nodeId: node.id,
        source: source as import('./types/events').OperationSource,
      }

      const result = await props.beforeNodeRemove(event)
      return result !== false
    },

    // 边连线创建前拦截器（在 validateConnection 阶段调用，sourceCell/targetCell 均已知）
    beforeEdgeAdd: ({ sourceCell, targetCell, sourceMagnet, targetMagnet }) => {
      if (!props.beforeEdgeAdd) return true

      const event: BeforeEdgeAddEvent = {
        sourceCell,
        targetCell,
        sourceMagnet,
        targetMagnet,
      }

      const result = props.beforeEdgeAdd(event)
      return result !== false
    },

    // 边删除前拦截器
    beforeEdgeRemove: async (edge, source) => {
      if (!props.beforeEdgeRemove) return true

      const sourceCell = edge.getSourceCell()
      const targetCell = edge.getTargetCell()

      const event: BeforeEdgeRemoveEvent = {
        edge,
        edgeId: edge.id,
        sourceNodeId: sourceCell?.id || '',
        targetNodeId: targetCell?.id || '',
        source: source as import('./types/events').OperationSource,
      }

      const result = await props.beforeEdgeRemove(event)
      return result !== false
    },

    // After 回调
    afterNodeAdd: (node, source) => {
      if (!props.afterNodeAdd) return

      props.afterNodeAdd({
        node,
        nodeId: node.id,
        source: source as import('./types/events').OperationSource,
        success: true,
        timestamp: Date.now(),
      })
    },

    afterNodeRemove: (nodeId, nodeData, source) => {
      if (!props.afterNodeRemove) return

      props.afterNodeRemove({
        nodeId,
        nodeData,
        source: source as import('./types/events').OperationSource,
        success: true,
        timestamp: Date.now(),
      })
    },

    afterEdgeAdd: (edge, source) => {
      if (!props.afterEdgeAdd) return

      const sourceNode = edge.getSourceNode()
      const targetNode = edge.getTargetNode()

      if (sourceNode && targetNode) {
        props.afterEdgeAdd({
          edge,
          edgeId: edge.id,
          sourceNodeId: sourceNode.id,
          targetNodeId: targetNode.id,
          source: source as import('./types/events').OperationSource,
          success: true,
          timestamp: Date.now(),
        })
      }
    },

    afterEdgeRemove: (edgeId, edgeData, source) => {
      if (!props.afterEdgeRemove) return

      const sourceNodeId = edgeData?.source?.cell || ''
      const targetNodeId = edgeData?.target?.cell || ''

      props.afterEdgeRemove({
        edgeId,
        edgeData,
        sourceNodeId,
        targetNodeId,
        source: source as import('./types/events').OperationSource,
        success: true,
        timestamp: Date.now(),
      })
    },

    // ===== 节点/边交互钩子 =====
    beforeNodeHover: (event) => {
      if (!props.beforeNodeHover) return true
      try {
        const result = props.beforeNodeHover(event as BeforeNodeHoverEvent)
        return result !== false
      } catch (error) {
        console.error('[FlowDesignerLayout] beforeNodeHover 钩子执行出错:', error)
        return true
      }
    },

    afterNodeHover: (event) => {
      if (!props.afterNodeHover) return
      try {
        props.afterNodeHover(event as AfterNodeHoverEvent)
      } catch (error) {
        console.error('[FlowDesignerLayout] afterNodeHover 钩子执行出错:', error)
      }
    },

    beforeNodeSelect: (event) => {
      if (!props.beforeNodeSelect) return true
      try {
        const result = props.beforeNodeSelect(event as BeforeNodeSelectEvent)
        return result !== false
      } catch (error) {
        console.error('[FlowDesignerLayout] beforeNodeSelect 钩子执行出错:', error)
        return true
      }
    },

    afterNodeSelect: (event) => {
      if (!props.afterNodeSelect) return
      try {
        props.afterNodeSelect(event as AfterNodeSelectEvent)
      } catch (error) {
        console.error('[FlowDesignerLayout] afterNodeSelect 钩子执行出错:', error)
      }
    },

    beforeEdgeHover: (event) => {
      if (!props.beforeEdgeHover) return true
      try {
        const result = props.beforeEdgeHover(event as BeforeEdgeHoverEvent)
        return result !== false
      } catch (error) {
        console.error('[FlowDesignerLayout] beforeEdgeHover 钩子执行出错:', error)
        return true
      }
    },

    afterEdgeHover: (event) => {
      if (!props.afterEdgeHover) return
      try {
        props.afterEdgeHover(event as AfterEdgeHoverEvent)
      } catch (error) {
        console.error('[FlowDesignerLayout] afterEdgeHover 钩子执行出错:', error)
      }
    },

    beforeEdgeSelect: (event) => {
      if (!props.beforeEdgeSelect) return true
      try {
        const result = props.beforeEdgeSelect(event as BeforeEdgeSelectEvent)
        return result !== false
      } catch (error) {
        console.error('[FlowDesignerLayout] beforeEdgeSelect 钩子执行出错:', error)
        return true
      }
    },

    afterEdgeSelect: (event) => {
      if (!props.afterEdgeSelect) return
      try {
        props.afterEdgeSelect(event as AfterEdgeSelectEvent)
      } catch (error) {
        console.error('[FlowDesignerLayout] afterEdgeSelect 钩子执行出错:', error)
      }
    },

    // 锚点样式钩子：直接透传，NodeStateManager 会在每次设置锚点样式时调用
    portStateRenderers: props.portStateRenderers
      ? (node, portState) => props.portStateRenderers!(node, portState)
      : undefined,
  }
}

function buildDesignerOptions(): FlowDesignerOptions {
  return {
    container: containerRef.value!,
    minimapContainer: minimapRef.value,
    tooltipContainer: tooltipRef.value,
    mode: currentMode.value,
    initialConfig: props.canvasConfig,
    // 新增：权限配置
    permissionConfig: props.permissionConfig,
    permissions: props.permissions,
    getPermissions: props.getPermissions,
    shortcuts: props.shortcuts,
    // 新增：生命周期回调
    callbacks: createLifecycleCallbacks(),
  }
}

/**
 * 设置状态渲染器
 * 将用户提供的简化版渲染器包装为 FlowDesigner 所需的完整格式
 */
function setupStateRenderers(designer: FlowDesigner) {
  const logPrefix = '[FlowDesignerLayout] setupStateRenderers:'

  try {
    // ─── 处理节点状态渲染器 ─────────────────────────────────────────
    if (props.nodeStateRenderers) {
      const allKeys = Object.keys(props.nodeStateRenderers)
      
      if (allKeys.length === 0) {
        console.warn(`${logPrefix} nodeStateRenderers 是空对象，跳过注册`)
        return
      }
      
      // ═══════════════════════════════════════════════════════════════
      // 格式检测：新格式（按节点类型分组）vs 旧格式（全局状态）
      // ═══════════════════════════════════════════════════════════════
      // 新格式：{ 'svg-start-node': { default: {...}, hover: {...} } }
      // 旧格式：{ default: (node) => ({apply, cleanup}), hover: (node) => ({apply, cleanup}) }
      
      const firstKey = allKeys[0]
      const firstValue = props.nodeStateRenderers[firstKey]
      
      let isGroupedByType = false
      
      // 检查第一层值的类型
      if (typeof firstValue === 'function') {
        // 明确是旧格式：第一层值是函数
        isGroupedByType = false
      } else if (typeof firstValue === 'object' && firstValue !== null) {
        // 第一层是对象，需要进一步检查
        if ('apply' in firstValue) {
          // 第一层直接包含 apply，是旧格式或错误格式
          isGroupedByType = false
        } else {
          // 检查第二层：是否包含 apply 属性
          const secondLevelValues = Object.values(firstValue)
          isGroupedByType = secondLevelValues.some(v => 
            v && typeof v === 'object' && 'apply' in v
          )
        }
      }

      if (isGroupedByType) {
        // ═══════════════════════════════════════════════════════════════
        // 新格式：{ 'svg-start-node': { default: {...}, hover: {...} } }
        // ═══════════════════════════════════════════════════════════════
        
        Object.entries(props.nodeStateRenderers).forEach(([nodeType, stateRenderers]: [string, any]) => {
          if (!stateRenderers || typeof stateRenderers !== 'object') {
            console.warn(`${logPrefix} 节点类型 "${nodeType}" 的配置无效`)
            return
          }

          Object.entries(stateRenderers).forEach(([stateName, rendererOrConfig]: [string, any]) => {
            try {
              // 支持两种形式：
              // 1. 直接的 StateRenderer 对象：{ apply: () => {}, cleanup: () => {} }
              // 2. 返回 StateRenderer 的函数：(node) => ({ apply: () => {}, cleanup: () => {} })
              
              let handler: any

              if (typeof rendererOrConfig === 'function') {
                // 情况 2：函数形式
                handler = {
                  apply: (node: Node, context: any) => {
                    try {
                      const result = rendererOrConfig(node)
                      if (result && typeof result.apply === 'function') {
                        result.apply(node, designer)
                      }
                    } catch (error) {
                      console.error(`${logPrefix} [${nodeType}:${stateName}] apply 执行出错:`, error)
                    }
                  },
                  cleanup: (node: Node, context: any) => {
                    try {
                      const result = rendererOrConfig(node)
                      if (result && typeof result.cleanup === 'function') {
                        result.cleanup(node, designer)
                      }
                    } catch (error) {
                      console.error(`${logPrefix} [${nodeType}:${stateName}] cleanup 执行出错:`, error)
                    }
                  }
                }
              } else if (rendererOrConfig && typeof rendererOrConfig.apply === 'function') {
                // 情况 1：直接的 StateRenderer 对象
                handler = {
                  apply: (node: Node, context: any) => {
                    try {
                      rendererOrConfig.apply(node, designer)
                    } catch (error) {
                      console.error(`${logPrefix} [${nodeType}:${stateName}] apply 执行出错:`, error)
                    }
                  },
                  cleanup: (node: Node, context: any) => {
                    try {
                      if (rendererOrConfig.cleanup) {
                        rendererOrConfig.cleanup(node, designer)
                      }
                    } catch (error) {
                      console.error(`${logPrefix} [${nodeType}:${stateName}] cleanup 执行出错:`, error)
                    }
                  }
                }
              } else {
                console.error(`${logPrefix} 节点类型 "${nodeType}" 状态 "${stateName}" 的配置无效`)
                return
              }

              // 注册到指定节点类型
              designer.registerNodeStateHandlerForType(nodeType, stateName, handler, true)
            } catch (error) {
              console.error(`${logPrefix} 注册 [${nodeType}:${stateName}] 失败:`, error)
            }
          })
        })
      } else {
        // ═══════════════════════════════════════════════════════════════
        // 旧格式：{ default: (node) => {...}, hover: (node) => {...} }
        // ═══════════════════════════════════════════════════════════════
        
        Object.entries(props.nodeStateRenderers).forEach(([stateName, renderer]) => {
          try {
            // 验证渲染器是否有效
            if (typeof renderer !== 'function') {
              console.error(`${logPrefix} 节点状态 "${stateName}" 的渲染器必须是函数`)
              return
            }

            // 包装用户渲染器为 FlowDesigner 所需的格式
            const handler = {
              apply: (node: Node, context: any) => {
                try {
                  const result = renderer(node)
                  if (!result || typeof result.apply !== 'function') {
                    console.error(`${logPrefix} 节点状态 "${stateName}" 的渲染器必须返回包含 apply 函数的对象`)
                    return
                  }
                  result.apply(node, designer)
                } catch (error) {
                  console.error(`${logPrefix} 节点状态 "${stateName}" 的 apply 函数执行出错:`, error)
                }
              },
              cleanup: (node: Node, context: any) => {
                try {
                  const result = renderer(node)
                  if (result && typeof result.cleanup === 'function') {
                    result.cleanup(node, designer)
                  }
                } catch (error) {
                  console.error(`${logPrefix} 节点状态 "${stateName}" 的 cleanup 函数执行出错:`, error)
                }
              }
            }

            // 注册为全局状态
            designer.registerNodeStateHandler(stateName, handler, true)
          } catch (error) {
            console.error(`${logPrefix} 注册节点状态 "${stateName}" 失败:`, error)
          }
        })
      }
    }

    // ─── 处理连线状态渲染器 ─────────────────────────────────────────
    if (props.edgeStateRenderers) {
      Object.entries(props.edgeStateRenderers).forEach(([stateName, renderer]) => {
        try {
          // 验证渲染器是否有效
          if (typeof renderer !== 'function') {
            console.error(`${logPrefix} 连线状态 "${stateName}" 的渲染器必须是函数`)
            return
          }

          // 包装用户渲染器为 FlowDesigner 所需的格式
          const handler = {
            apply: (edge: import('@antv/x6').Edge, context: any) => {
              try {
                const result = renderer(edge)
                if (!result || typeof result.apply !== 'function') {
                  console.error(`${logPrefix} 连线状态 "${stateName}" 的渲染器必须返回包含 apply 函数的对象`)
                  return
                }
                result.apply(edge)
              } catch (error) {
                console.error(`${logPrefix} 连线状态 "${stateName}" 的 apply 函数执行出错:`, error)
              }
            },
            cleanup: (edge: import('@antv/x6').Edge, context: any) => {
              try {
                const result = renderer(edge)
                if (result && typeof result.cleanup === 'function') {
                  result.cleanup(edge)
                }
              } catch (error) {
                console.error(`${logPrefix} 连线状态 "${stateName}" 的 cleanup 函数执行出错:`, error)
              }
            }
          }

          // 注册到 FlowDesigner（override = true 允许覆盖内置状态）
          designer.registerEdgeStateHandler(stateName, handler, true)
        } catch (error) {
          console.error(`${logPrefix} 注册连线状态 "${stateName}" 失败:`, error)
        }
      })
    }
  } catch (error) {
    console.error(`${logPrefix} 设置状态渲染器时发生错误:`, error)
  }
}

function initDesigner(): Promise<FlowDesigner> {
  return new Promise(async (resolve) => {
    // 等待 DOM 渲染完成后初始化
    setTimeout(async () => {
      const options = {
        options: buildDesignerOptions(),
        register: register,
        Graph: GraphClass,
        Shape: Shape
      }
      // 调用 beforeGraphInit 钩子（如果提供）
      if (props.beforeGraphInit) {
        try {
          await props.beforeGraphInit(options)
        } catch (error) {
          console.error('[FlowDesignerLayout] beforeGraphInit hook error:', error)
          emit('error', error as Error)
        }
      }

      const inst = new FlowDesigner(options.options)
      resolve(inst)
    }, 100)
  })
}

// ─── 生命周期 ─────────────────────────────────────────────────────────────────

onMounted(async () => {
  if (!containerRef.value) return

    designer = await initDesigner()
  const graph = designer.getGraph()

  // 初始化 provide 的占位 ref，使用 watchEffect 自动跟踪 designer 的响应式状态
  _designerRef.value = designer
  _canvasConfig.value = designer.getCanvasConfig()
    watchEffect(() => {
    if (!designer) return
        _selectedCells.value = [...designer.selectedCells.value]
  })

  // 缩放监听
  graph.on('scale', ({ sx }: { sx: number }) => {
    zoomPercent.value = Math.round(sx * 100)
  })

  // 历史记录状态监听
  const syncHistory = () => {
    canUndo.value = graph.canUndo()
    canRedo.value = graph.canRedo()
  }
  graph.on('history:change', syncHistory)
  graph.on('history:undo', syncHistory)
  graph.on('history:redo', syncHistory)
  syncHistory()

  // 选中状态监听
  graph.on('cell:selected', updateSelectionState)
  graph.on('cell:unselected', updateSelectionState)

  // 剪贴板监听
  graph.on('clipboard:changed', () => {
    canPaste.value = !graph.isClipboardEmpty()
  })

  // 注册回调
  designer.onSave((data) => {
    emit('save', data)
  })

  designer.onError((error) => {
    emit('error', error)
  })

  designer.onSelectionSync((cells) => {
    emit('selection-change', cells)
  })


  // 注册其他回调

    designer.onContextMenu((payload) => {
    if (payload.action !== 'show') return
    const { type, target } = payload
    if (type === 'node') {
      contextMenuRef.value?.showNodeMenu(target.event, target.node, target.isGroup, target.isMultiSelect)
    } else if (type === 'edge') {
      contextMenuRef.value?.showEdgeMenu(target.event, target.edge)
    } else if (type === 'canvas') {
      contextMenuRef.value?.showCanvasMenu(target.event)
    }
  })

  designer.onOpenSearch(() => {
    searchVisible.value = true
  })

  // 注册 Tooltip 状态变化回调
  designer.onTooltipChange((payload) => {
    // 优先使用新的 tooltipRenderer，否则使用旧的 nodeTooltipRenderer（向后兼容）
    const renderer = props.tooltipRenderer || props.nodeTooltipRenderer
    
    if (payload.visible && renderer) {
      try {
        let cell: Node | Edge | null = null
        
        // 获取当前元素（节点或连线）
        if (payload.type === 'node') {
          cell = payload.node
        } else if (payload.type === 'edge') {
          cell = payload.edge
        }
        
        if (cell) {
          const result = renderer(cell, payload.data)
          
          // 返回 false：不显示 tooltip
          if (result === false) {
            tooltipScope.value = {
              ...payload,
              visible: false,
              customClassName: undefined,
            }
            return
          }
          
          // 返回 string：作为自定义 className
          if (typeof result === 'string') {
            tooltipScope.value = {
              ...payload,
              customClassName: result,
            }
            return
          }
        }
      } catch (error) {
        console.error('[FlowDesignerLayout] tooltipRenderer 钩子执行出错:', error)
      }
    }
    
    // 默认行为：直接设置 payload
    tooltipScope.value = {
      ...payload,
      customClassName: undefined,
    }
  })

  // 数据加载完成后调用 Props 钩子
  designer.onAfterDataLoaded((data) => {
    if (props.afterDataLoaded) {
      props.afterDataLoaded(data)
    }
  })

  // 注册 edge-label 插槽渲染器（方案A：foreignObject + createApp）
  if (hasEdgeLabelSlot.value) {
    designer.onEdgeLabelRender((fo, edge, data) => {
      // 构造包裹组件，让 edge-label 插槽内容能访问 edge/data scope
      const WrapperApp = defineComponent({
        setup() {
          return () => h('div', { style: 'display:inline-flex;align-items:center;' },
            slots['edge-label']?.({ edge, data }) ?? []
          )
        },
      })
      const app = createApp(WrapperApp)
      const container = document.createElement('div')
      container.style.cssText = 'display:inline-flex;align-items:center;white-space:nowrap;transform:translate(-50%,-50%);'
      fo.appendChild(container)
      app.mount(container)
      // 返回卸载函数
      return () => {
        app.unmount()
        fo.innerHTML = ''
      }
    })
  }

  // 等待画布完全渲染后 emit ready 事件
  // 使用 requestAnimationFrame 确保 DOM 更新和画布初始化完成
  requestAnimationFrame(() => {
    // 设置状态渲染器（在 ready 事件前调用，允许用户覆盖内置行为）
    setupStateRenderers(designer)
    emit('ready',  designer, graph )
  })

  // 建议 4：监听 mode prop 变化，支持父组件动态切换模式
  watch(() => props.mode, (newMode) => {
    if (newMode && newMode !== currentMode.value) {
      handleModeChange(newMode)
    }
  })

  // 监听 permissionConfig prop 变化，支持动态修改权限配置映射表
  watch(() => props.permissionConfig, (newConfig) => {
    if (!designer) return
    designer.updatePermissions({ permissionConfig: newConfig })
    // 触发 capabilities computed 重新计算，同步 Vue 侧 UI 状态
    capabilitiesVersion.value++
  }, { deep: true })

  // 监听 permissions prop 变化，支持运行时动态修改权限（如 canDrag）
  watch(() => props.permissions, (newPermissions) => {
    if (!designer) return
    designer.updatePermissions({ permissions: newPermissions })
    // 触发 capabilities computed 重新计算，同步 Vue 侧 UI 状态
    capabilitiesVersion.value++
  }, { deep: true })
})

onUnmounted(() => {
  designer?.dispose()
  window.removeEventListener('keydown', handleGlobalKeydown)
  window.removeEventListener('keydown', preventSpaceScroll, { capture: true } as any)
})

// 🔥 关键修复：全局拦截空格键，防止页面滚动
// 在捕获阶段拦截，优先级最高
function preventSpaceScroll(e: KeyboardEvent) {
  // 如果是空格键，且焦点不在输入框/文本域/可编辑元素上
  const target = e.target as HTMLElement
  const isEditableElement =
    target.tagName === 'INPUT' ||
    target.tagName === 'TEXTAREA' ||
    target.isContentEditable

  if (e.code === 'Space' && !isEditableElement) {
    // 只阻止默认滚动行为，不阻止事件传播（让 FlowDesigner 可以处理拖拽）
    e.preventDefault()
    // 注意：不调用 e.stopPropagation()，允许事件继续传播到 FlowDesigner
  }
}

// 在捕获阶段监听，优先级最高
window.addEventListener('keydown', preventSpaceScroll, { capture: true })

// 全局键盘监听——画布未聚焦时也能触发 Ctrl+F
function handleGlobalKeydown(e: KeyboardEvent) {
  if ((e.ctrlKey || e.metaKey) && e.key === 'f') {
    e.preventDefault()
    // 权限检查
    if (!capabilities.value.showSearch) {
      return
    }
    searchVisible.value = true
  }
}
window.addEventListener('keydown', handleGlobalKeydown)

// ─── 内部工具方法 ─────────────────────────────────────────────────────────────

function updateSelectionState() {
  if (!designer) return
  const graph = designer.getGraph()
  const selectedNodes = graph.getSelectedCells().filter(c => c.isNode())
  hasSelection.value = selectedNodes.length > 0
  canGroup.value = designer.canGroup()
  canUngroup.value = designer.canUngroup()
}

// ─── 工具栏操作方法（暴露给 toolbar slot scope） ────────────────────────────

function handleSave() {
  if (!designer) return
  designer.save()
}

function handleNew() {
  if (!designer) return
  // 权限检查
  if (!capabilities.value.canDelete) {
    message.warning('当前模式不允许创建新画布')
    return
  }
  designer.getGraph().clearCells()
  designer.reset()
}

function handleUndo() {
  if (!designer) return
  // 权限检查
  if (!capabilities.value.canUndo) return
  designer.undo()
}
function handleRedo() {
  if (!designer) return
  // 权限检查
  if (!capabilities.value.canRedo) return
  designer.redo()
}
function handleZoomIn() { designer?.zoom(0.1) }
function handleZoomOut() { designer?.zoom(-0.1) }
function handleZoomTo(percent: number) { designer?.zoomTo(percent / 100) }
function handleFitView() { designer?.fitToContent(40) }
function handleResetView() {
  // 权限检查
  if (!capabilities.value.canResetView) return
  designer?.resetView()
}

function handleCopy() {
  if (!designer) return
  // 权限检查
  if (!capabilities.value.canCopy) {
    message.warning('当前模式不允许复制操作')
    return
  }
  const graph = designer.getGraph()
  const cells = graph.getSelectedCells()
  if (!cells.length) return
  graph.copy(cells)
  canPaste.value = true
}

function handlePaste() {
  if (!designer) return
  // 权限检查
  if (!capabilities.value.canPaste) {
    message.warning('当前模式不允许粘贴操作')
    return
  }
  designer.paste()
}

function handleToFront() {
  if (!designer) return
  // 权限检查
  if (!capabilities.value.canToFront) {
    message.warning('当前模式不允许层级前置操作')
    return
  }
  designer.getGraph().getSelectedCells().forEach(cell => cell.toFront())
}

function handleToBack() {
  if (!designer) return
  // 权限检查
  if (!capabilities.value.canToBack) {
    message.warning('当前模式不允许层级后置操作')
    return
  }
  designer.getGraph().getSelectedCells().forEach(cell => cell.toBack())
}

/**
 * 对齐动画辅助函数：
 * 1. 收集所有参与动画节点的相关连线，临时切换为 normal router（直线），避免路由算法在中间态产生路径跳变导致抖动
 * 2. 对每个需要移动的节点执行 animate()
 * 3. 所有动画结束后还原连线 router
 */
function runAlignAnimation(
  nodes: ReturnType<typeof designer.getGraph>['getCells'] extends () => infer R ? R : any[],
  getProp: (n: any) => { prop: string; from: number; to: number },
  fallback: (n: any, to: number) => void,
) {
  const graph = designer!.getGraph()

  // 收集受影响的边及其原始 router
  const edgeRouterMap = new Map<any, any>()
  nodes.forEach((n: any) => {
    graph.getConnectedEdges(n).forEach((edge: any) => {
      if (!edgeRouterMap.has(edge)) {
        edgeRouterMap.set(edge, edge.getRouter())
        edge.setRouter('normal')
      }
    })
  })

  // 所有动画的完成 promise，用于统一还原 router
  const animations: Promise<void>[] = []

  nodes.forEach((n: any) => {
    const { prop, from, to } = getProp(n)
    if (from !== to) {
      const animation = n.animate(
        { [prop]: [from, to] },
        { duration: 300, easing: 'ease-in-out', fill: 'forwards' },
      )
      animations.push(
        new Promise<void>((resolve) => {
          animation.onfinish = () => resolve()
        }),
      )
    } else {
      fallback(n, to)
    }
  })

  // 所有动画完成后还原 router
  if (animations.length > 0) {
    Promise.all(animations).then(() => {
      edgeRouterMap.forEach((router, edge) => {
        edge.setRouter(router ?? { name: designer!.getCanvasConfig().connection.router })
      })
    })
  } else {
    // 无动画（全部走 fallback）时立即还原
    edgeRouterMap.forEach((router, edge) => {
      edge.setRouter(router ?? { name: designer!.getCanvasConfig().connection.router })
    })
  }
}

function handleAlignLeft() {
  if (!designer) return
  if (!capabilities.value.canAlignLeft) {
    message.warning('当前模式不允许左对齐操作')
    return
  }
  const nodes = designer.getGraph().getSelectedCells().filter(c => c.isNode())
  if (nodes.length < 2) return
  const minX = Math.min(...nodes.map((n: any) => n.position().x))
  runAlignAnimation(
    nodes,
    (n) => ({ prop: 'position/x', from: n.position().x, to: minX }),
    (n, to) => n.position(to, n.position().y),
  )
}

function handleAlignRight() {
  if (!designer) return
  if (!capabilities.value.canAlignRight) {
    message.warning('当前模式不允许右对齐操作')
    return
  }
  const nodes = designer.getGraph().getSelectedCells().filter(c => c.isNode())
  if (nodes.length < 2) return
  const maxRight = Math.max(...nodes.map((n: any) => n.position().x + n.size().width))
  runAlignAnimation(
    nodes,
    (n) => ({ prop: 'position/x', from: n.position().x, to: maxRight - n.size().width }),
    (n, to) => n.position(to, n.position().y),
  )
}

function handleAlignTop() {
  if (!designer) return
  if (!capabilities.value.canAlignTop) {
    message.warning('当前模式不允许上对齐操作')
    return
  }
  const nodes = designer.getGraph().getSelectedCells().filter(c => c.isNode())
  if (nodes.length < 2) return
  const minY = Math.min(...nodes.map((n: any) => n.position().y))
  runAlignAnimation(
    nodes,
    (n) => ({ prop: 'position/y', from: n.position().y, to: minY }),
    (n, to) => n.position(n.position().x, to),
  )
}

function handleAlignBottom() {
  if (!designer) return
  if (!capabilities.value.canAlignBottom) {
    message.warning('当前模式不允许下对齐操作')
    return
  }
  const nodes = designer.getGraph().getSelectedCells().filter(c => c.isNode())
  if (nodes.length < 2) return
  const maxBottom = Math.max(...nodes.map((n: any) => n.position().y + n.size().height))
  runAlignAnimation(
    nodes,
    (n) => ({ prop: 'position/y', from: n.position().y, to: maxBottom - n.size().height }),
    (n, to) => n.position(n.position().x, to),
  )
}

function handleGroup() {
  if (!designer) return
  // 权限检查
  if (!capabilities.value.canGroup) {
    message.warning('当前模式不允许分组操作')
    return
  }
  designer.groupSelectedNodes()
  updateSelectionState()
}

function handleUngroup() {
  if (!designer) return
  // 权限检查
  if (!capabilities.value.canGroup) {
    message.warning('当前模式不允许解组操作')
    return
  }
  designer.ungroupSelected()
  updateSelectionState()
}

function handleExport() {
  if (!designer) return
  // 权限检查
  if (!capabilities.value.canExport) {
    message.warning('当前模式不允许导出操作')
    return
  }
  //const data = designer?.export('json')
  const data = designer.graph.toJSON()
  if (!data) return
  const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' })
  const url = URL.createObjectURL(blob)
  const a = document.createElement('a')
  a.href = url
  a.download = 'flow.json'
  // 必须 append 到 body 再触发，防止浏览器路由拦截导致请求打到后端
  document.body.appendChild(a)
  a.click()
  document.body.removeChild(a)
  URL.revokeObjectURL(url)
}

function handleImport(file: File) {
  if (!designer) return
  // 权限检查
  if (!capabilities.value.canImport) {
    message.warning('当前模式不允许导入操作')
    return
  }
  const reader = new FileReader()
  reader.onload = (e) => {
    try {
      const data = JSON.parse(e.target?.result as string)
      designer.load(data)
    } catch {
      emit('error', new Error('导入失败：文件格式错误'))
    }
  }
  reader.readAsText(file)
}

function handleModeChange(mode: DesignerMode) {
  if (!designer) return
  designer.setMode(mode)
  currentMode.value = mode
  emit('mode-change', mode)
}

function handleOpenSettings() {
  settingsVisible.value = true
}

function handleReloadGraph() {
  if (!designer || !_canvasConfig.value) return
  // 将面板上用户修改过的配置同步到 designer 内部，再执行应用
  designer.updateCanvasConfig(_canvasConfig.value)
  designer.applyConfig()
  // 同步回最新的配置（含深拷贝）
  _canvasConfig.value = designer.getCanvasConfig()
}

// ─── 节点拖拽（暴露给 palette slot scope） ───────────────────────────────────

function handleStartDrag(event: MouseEvent, nodeConfig: Partial<Node.Metadata>) {
  if (!designer) return

  // 处理 common-vue-node 的特殊逻辑
  // 将 data.nodeType 提升为节点的 prop 'node-type'
  // 这样 CommonVueNode 可以在拖拽预览时就读取到 node-type
  if (nodeConfig.shape === 'common-vue-node' && nodeConfig.data?.nodeType) {
    nodeConfig['node-type'] = nodeConfig.data.nodeType
  }

  designer.startDrag(event, nodeConfig)
}

// ─── 右键菜单处理 ─────────────────────────────────────────────────────────────

function handleMenuAction({ type, action, target }: { type: string; action: string; target?: any }) {
  if (!designer) return
  designer.handleContextMenuAction(type, action, target)
  if (action === 'group' || action === 'ungroup') {
    updateSelectionState()
  }
}

// ─── Slot Scope 对象（类型完整，统一管理） ────────────────────────────────────

const toolbarScope = computed(() => ({
  designer: designer as FlowDesigner | null,
  graph: designer?.getGraph() as Graph | null,
  currentMode: currentMode.value,
  capabilities: capabilities.value,
  zoomPercent: zoomPercent.value,
  hasSelection: hasSelection.value,
  canPaste: canPaste.value,
  canGroup: canGroup.value,
  canUngroup: canUngroup.value,
  canUndo: canUndo.value,
  canRedo: canRedo.value,
    // 操作方法
  onUndo: handleUndo,
  onRedo: handleRedo,
  onZoomIn: handleZoomIn,
  onZoomOut: handleZoomOut,
  onZoomTo: handleZoomTo,
  onFitView: handleFitView,
  onResetView: handleResetView,
  onCopy: handleCopy,
  onPaste: handlePaste,
  onToFront: handleToFront,
  onToBack: handleToBack,
  onAlignLeft: handleAlignLeft,
  onAlignRight: handleAlignRight,
  onAlignTop: handleAlignTop,
  onAlignBottom: handleAlignBottom,
  onGroup: handleGroup,
  onUngroup: handleUngroup,
  onExport: handleExport,
  onImport: handleImport,
  onModeChange: handleModeChange,
  onOpenSettings: handleOpenSettings,
}))

const paletteScope = computed(() => ({
  designer: designer as FlowDesigner | null,
  graph: designer?.getGraph() as Graph | null ?? null,
  capabilities: capabilities.value,
  currentMode: currentMode.value,
  onStartDrag: handleStartDrag,
}))

const propertiesScope = computed(() => ({
  capabilities: capabilities.value,
  designer: designer as FlowDesigner | null,
  graph: designer?.getGraph() as Graph | null ?? null,
  currentMode: currentMode.value,
  selectedCells: _selectedCells.value,
}))

// ─── 对外暴露 ─────────────────────────────────────────────────────────────────

/**
 * 居中显示指定节点
 * @param nodeId 节点 ID
 */
function centerNode(nodeId: string): void {
  const graph = designer?.getGraph()
  if (!graph) return
  const cell = graph.getCellById(nodeId)
  if (cell?.isNode()) {
    graph.centerCell(cell)
  }
}

defineExpose({
  designer: _designerRef,  // ✅ 改为暴露响应式的 _designerRef（而非普通变量 designer）
  currentMode,
  capabilities,
  centerNode,
})
</script>

<style scoped>
/* 根容器：撑满父元素，竖向 flex */
.fdl-root {
  width: 100%;
  height: 100%;
  display: flex;
  flex-direction: column;
  overflow: hidden;
}

/* 顶部工具栏：高度由内容决定，不压缩 */
.fdl-header {
  flex-shrink: 0;
}

/* 主体区域：横向 flex，填满剩余高度 */
.fdl-body {
  flex: 1;
  display: flex;
  overflow: hidden;
  min-height: 0;
}

/* 左侧面板：宽度由内容决定，不压缩 */
.fdl-palette {
  flex-shrink: 0;
  border-right: 1px solid #f0f0f0;
  background: #fff;
  /* 🔑 关键修复：给 flex item 明确的高度约束，不设置 overflow 让子组件处理滚动 */
  height: 100%;
  min-height: 0;  /* 关键：防止 flex item 被子元素撑开 */
}

/* 右侧面板：宽度由内容决定，不压缩 */
.fdl-properties {
  flex-shrink: 0;
  border-left: 1px solid #f0f0f0;
  background: #fff;
}

/* 中间画布：自动填满剩余宽度 */
.fdl-canvas {
  flex: 1;
  position: relative;
  overflow: hidden;
  min-width: 0;
  min-height: 0; /* 防止 flex item 被子元素撑开 */
}

.fdl-canvas__inner {
  width: 100%;
  height: 100%;
  /* 🔥 关键修复：限制容器高度，防止被 X6 autoResize 撑大 */
  /* overflow: auto 会导致 flex 容器被 scrollHeight 撑开，形成死循环 */
  max-height: 100%;
  overflow: hidden;
}

/* 小地图外层包装：悬浮在画布右下角 */
.fdl-canvas__minimap-wrapper {
  position: absolute;
  right: 20px;
  bottom: 20px;
  border: 1px solid #e8e8e8;
  border-radius: 6px;
  background: #fff;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  overflow: hidden;
}

/* 收起状态：缩为圆形小按钮 */
.fdl-canvas__minimap-wrapper--collapsed {
  width: 40px !important;
  height: 40px !important;
  border-radius: 50%;
  overflow: visible;
}

/* 收起时隐藏 X6 minimap 内容 */
.fdl-canvas__minimap-wrapper--collapsed .fdl-canvas__minimap,
.fdl-canvas__minimap-wrapper--collapsed :deep(.x6-minimap-viewport),
.fdl-canvas__minimap-wrapper--collapsed :deep(.x6-minimap-container) {
  display: none;
}

.fdl-canvas__minimap {
  width: 100%;
  height: 100%;
}

/* 展开/收起按钮 */
.fdl-minimap__toggle {
  position: absolute;
  top: 4px;
  right: 4px;
  width: 24px;
  height: 24px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(255, 255, 255, 0.9);
  border-radius: 4px;
  cursor: pointer;
  z-index: 10;
  transition: all 0.2s;
  box-shadow: 0 1px 4px rgba(0, 0, 0, 0.1);
}

.fdl-minimap__toggle:hover {
  background: #fff;
  box-shadow: 0 2px 6px rgba(0, 0, 0, 0.15);
  transform: scale(1.05);
}

.fdl-minimap__toggle:active {
  transform: scale(0.95);
}

.fdl-minimap__toggle-icon {
  font-size: 12px;
  color: #595959;
  transition: color 0.2s;
}

.fdl-minimap__toggle:hover .fdl-minimap__toggle-icon {
  color: #1677ff;
}

/* 收起状态下按钮居中 */
.fdl-canvas__minimap-wrapper--collapsed .fdl-minimap__toggle {
  position: absolute;
  top: 50%;
  left: 50%;
  right: auto;
  transform: translate(-50%, -50%);
  background: #fff;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
}

.fdl-canvas__minimap-wrapper--collapsed .fdl-minimap__toggle:hover {
  transform: translate(-50%, -50%) scale(1.1);
}

.fdl-canvas__minimap-wrapper--collapsed .fdl-minimap__toggle:active {
  transform: translate(-50%, -50%) scale(0.95);
}

/* 节点/连线 Tooltip */
.fdl-tooltip {
  position: fixed;
  top: 0;
  left: 0;
  display: none;
  pointer-events: none;
  /* 以下样式作为 fallback，优先使用 :style 绑定的配置值 */
  font-size: 13px;
  font-weight: bold;
  color: #fff;
  background: rgba(0, 0, 0, 0.75);
  border-radius: 4px;
  padding: 6px 12px;
  white-space: nowrap;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.25);
  z-index: 9999;
}

.fdl-tooltip__arrow {
  position: absolute;
  left: calc(50% - 5px);
  top: 100%;
  width: 0;
  height: 0;
  /* 以下样式作为 fallback，优先使用 :style 绑定的配置值 */
  border-left: 5px solid transparent;
  border-right: 5px solid transparent;
  border-top: 8px solid rgba(0, 0, 0, 0.75);
}

/* 自定义 Tooltip：清除默认样式，由插槽完全控制 */
.fdl-tooltip--custom {
  background: transparent;
  padding: 0;
  color: inherit;
  font-size: inherit;
  font-weight: inherit;
  white-space: normal;
  box-shadow: none;
}
</style>

<!-- 全局注入流动动画 keyframes（不加 scoped，SVG 内的 style 需全局生效） -->
<style>
@keyframes fd-flow {
  to { stroke-dashoffset: -12; }
}
</style>








