<template>
  <div class="cvn-task" data-cvn-root :class="{ 'cvn-task--selected': isSelected }">
    <div class="cvn-task__bar" />
    <div class="cvn-task__body">
      <div class="cvn-task__title">{{ nodeData.label || '自定义任务' }}</div>
      <div class="cvn-task__owner">负责人：{{ nodeData.owner || '未指定' }}</div>
    </div>
  </div>
</template>

<script setup lang="ts">
import { ref, onMounted, onUnmounted } from 'vue'
import type { Node, Graph } from '@antv/x6'

// graph 通过 slot scope 以 prop 形式传入，不再依赖 inject
// 因为 CommonNodeTask 运行在 CommonVueNode 内部创建的独立 Vue app 中，
// inject 跨 app 实例无效，getGraph 会是 undefined
const props = defineProps<{
  node: Node
  graph: Graph | null
}>()

const nodeData   = ref<Record<string, any>>(props.node.getData() ?? {})
const isSelected = ref(false)

const onDataChange = () => { nodeData.value = props.node.getData() ?? {} }

function onSelected({ cell }: { cell: { id: string } }) {
  if (cell.id === props.node.id) isSelected.value = true
}
function onUnselected({ cell }: { cell: { id: string } }) {
  if (cell.id === props.node.id) isSelected.value = false
}

onMounted(() => {
  props.node.on('change:data', onDataChange)
  if (props.graph) {
    props.graph.on('cell:selected',   onSelected)
    props.graph.on('cell:unselected', onUnselected)
  }
})

onUnmounted(() => {
  props.node.off('change:data', onDataChange)
  if (props.graph) {
    props.graph.off('cell:selected',   onSelected)
    props.graph.off('cell:unselected', onUnselected)
  }
})
</script>

<style scoped>
.cvn-task {
  display: flex;
  flex-direction: column;
  min-width: 160px;
  background: #fff;
  border: 1.5px solid #e8e8e8;
  border-radius: 8px;
  overflow: hidden;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
  user-select: none;
  transition: border-color 0.2s, box-shadow 0.2s;
}

.cvn-task:hover {
  border-color: #ffa940;
}

.cvn-task--selected {
  border: 2px solid #fa8c16;
  box-shadow: 0 0 0 3px rgba(250, 140, 22, 0.15);
}

.cvn-task__bar {
  height: 4px;
  flex-shrink: 0;
  background: linear-gradient(90deg, #fa8c16 0%, #ffc069 100%);
}

.cvn-task__body {
  padding: 10px 14px;
}

.cvn-task__title {
  font-size: 13px;
  font-weight: 600;
  color: #262626;
}

.cvn-task__owner {
  font-size: 11px;
  color: #8c8c8c;
  margin-top: 4px;
}
</style>
