/**
 * CustomMiniMap - 自定义小地图实现
 * 完全兼容 X6 虚拟渲染，使用 Canvas 绘制缩略图
 */

import type { Graph, Node, Edge, Cell } from '@antv/x6'
import type {
  CustomMiniMapOptions,
  RequiredCustomMiniMapOptions,
  Point,
  Rectangle,
  NodeRenderData,
  EdgeRenderData,
} from './CustomMiniMap.types'

export class CustomMiniMap {
  // ===== 核心属性 =====
  private graph: Graph
  private container: HTMLElement
  private canvas: HTMLCanvasElement
  private ctx: CanvasRenderingContext2D
  private options: RequiredCustomMiniMapOptions

  // ===== 离屏Canvas（性能优化） =====
  private offscreenCanvas: HTMLCanvasElement | null = null
  private offscreenCtx: CanvasRenderingContext2D | null = null
  private cacheValid: boolean = false

  // ===== 状态管理 =====
  private scale: number = 1 // 小地图缩放比例
  private graphBBox: Rectangle | null = null // 所有节点的包围盒
  private viewportRect: Rectangle | null = null // 当前视口矩形
  private isDragging: boolean = false
  private dragStartPos: Point | null = null
  private selectedCells: Set<string> = new Set() // 选中的节点ID

  // ===== 居中偏移（新增） =====
  private contentOffsetX: number = 0 // 内容区域的水平偏移（用于居中）
  private contentOffsetY: number = 0 // 内容区域的垂直偏移（用于居中）

  // ===== graphBBox 缓存标志 =====
  private graphBBoxDirty: boolean = true // true=需要重算 BBox，false=可复用缓存

  // ===== 性能监控 =====
  private frameCount: number = 0
  private lastFPSUpdate: number = 0
  private currentFPS: number = 0
  private lastRenderTime: number = 0

  // ===== 事件处理器存储 =====
  private boundHandlers: Map<string, any> = new Map()

  // ===== 渲染函数（会被包装为节流版本） =====
  private throttledRender: () => void
  private throttledRenderViewportOnly: () => void = () => {}

  constructor(graph: Graph, options: CustomMiniMapOptions) {
    this.graph = graph
    this.options = this.mergeOptionsWithDefaults(options)

    // 创建容器和Canvas
    this.container = options.container
    this.canvas = document.createElement('canvas')
    this.ctx = this.canvas.getContext('2d')!

    // 设置Canvas尺寸
    this.canvas.width = this.options.width
    this.canvas.height = this.options.height
    this.canvas.style.border = '1px solid #d9d9d9'
    this.canvas.style.borderRadius = '4px'
    this.canvas.style.cursor = 'pointer'

    // 设置渲染策略
    this.throttledRender = this.setupRenderStrategy()
    this.throttledRenderViewportOnly = this.setupViewportOnlyRenderStrategy()

    this.log('CustomMiniMap 已创建', this.options)
  }

  /**
   * 初始化小地图
   */
  public init(): void {
    this.log('CustomMiniMap 初始化开始')

    // 添加Canvas到容器
    this.container.appendChild(this.canvas)

    // 创建离屏Canvas
    if (this.options.updateStrategy.useOffscreenCache) {
      const time1 = Date.now();
      this.createOffscreenCanvas()
      const time2 = Date.now();
      console.log('ggggggggggggggggggggggg111111::', (time2-time1)/1000);
    }

    // 绑定事件
    this.bindGraphEvents()
    this.bindCanvasEvents()

    // 初始渲染
    const time11 = Date.now();
    this.refresh()
    const time22 = Date.now();
    console.log('ggggggggggggggggggggggg222222222::', (time22-time11)/1000);

    this.log('CustomMiniMap 初始化完成')
  }

  /**
   * 销毁小地图
   */
  public destroy(): void {
    this.log('CustomMiniMap 销毁')
    
    // 解绑事件
    this.unbindGraphEvents()
    this.unbindCanvasEvents()
    
    // 移除Canvas
    if (this.canvas.parentNode) {
      this.canvas.parentNode.removeChild(this.canvas)
    }
    
    // 清理离屏Canvas
    this.offscreenCanvas = null
    this.offscreenCtx = null
    
    // 清理引用
    this.boundHandlers.clear()
  }

  /**
   * 手动刷新小地图（用于 manual 模式）
   */
  public refresh(): void {
    this.invalidateCache()
    this.render()
  }

  /**
   * 更新配置
   */
  public updateOptions(options: Partial<CustomMiniMapOptions>): void {
    this.options = this.mergeOptionsWithDefaults({
      ...this.options,
      ...options,
    })

    // 重新设置渲染策略
    this.throttledRender = this.setupRenderStrategy()

    // 重新渲染
    this.refresh()
  }

  // ===== 私有方法：配置处理 =====

  private mergeOptionsWithDefaults(options: CustomMiniMapOptions): RequiredCustomMiniMapOptions {
    return {
      container: options.container,
      width: options.width ?? 300,
      height: options.height ?? 200,
      padding: options.padding ?? 10,

      rendering: {
        showEdges: options.rendering?.showEdges ?? true,
        showNodeLabels: options.rendering?.showNodeLabels ?? true,
        nodeLabelFontSize: options.rendering?.nodeLabelFontSize ?? 8,
        nodeLabelMaxWidth: options.rendering?.nodeLabelMaxWidth ?? 50,
        colorByNodeType: options.rendering?.colorByNodeType ?? true,
        nodeColorMap: options.rendering?.nodeColorMap ?? {},
        defaultNodeColor: options.rendering?.defaultNodeColor ?? '#1890ff',
        edgeColor: options.rendering?.edgeColor ?? '#d9d9d9',
        edgeWidth: options.rendering?.edgeWidth ?? 1,
        selectedNodeColor: options.rendering?.selectedNodeColor ?? '#ff4d4f',
        selectedNodeBorderWidth: options.rendering?.selectedNodeBorderWidth ?? 2,
        nodeBorderColor: options.rendering?.nodeBorderColor ?? '#ffffff',
        nodeBorderWidth: options.rendering?.nodeBorderWidth ?? 1,
      },

      viewport: {
        color: options.viewport?.color ?? 'rgba(24, 144, 255, 0.1)',
        borderColor: options.viewport?.borderColor ?? '#1890ff',
        borderWidth: options.viewport?.borderWidth ?? 2,
      },

      interaction: {
        enableClickToNavigate: options.interaction?.enableClickToNavigate ?? true,
        enableDragToNavigate: options.interaction?.enableDragToNavigate ?? true,
        enableZoom: options.interaction?.enableZoom ?? true,
        highlightSelected: options.interaction?.highlightSelected ?? true,
        zoomHandleSize: options.interaction?.zoomHandleSize ?? 8,
        zoomHandleColor: options.interaction?.zoomHandleColor ?? '#1890ff',
      },

      updateStrategy: {
        mode: options.updateStrategy?.mode ?? 'throttle',
        throttleDelay: options.updateStrategy?.throttleDelay ?? 200,
        useOffscreenCache: options.updateStrategy?.useOffscreenCache ?? true,
        cacheInvalidation: options.updateStrategy?.cacheInvalidation ?? 'nodeChange',
      },

      performance: {
        maxFPS: options.performance?.maxFPS ?? 30,
        simplifyThreshold: options.performance?.simplifyThreshold ?? 500,
        skeletonModeThreshold: options.performance?.skeletonModeThreshold ?? 2000,
        simplifiedRendering: {
          showNodeLabels: options.performance?.simplifiedRendering?.showNodeLabels ?? false,
          nodeScale: options.performance?.simplifiedRendering?.nodeScale ?? 0.6,
        },
      },

      debug: {
        showFPS: options.debug?.showFPS ?? false,
        showNodeCount: options.debug?.showNodeCount ?? false,
        enableLog: options.debug?.enableLog ?? false,
      },
    }
  }

  private setupRenderStrategy(): () => void {
    const mode = this.options.updateStrategy.mode

    switch (mode) {
      case 'realtime':
        return () => this.render()

      case 'throttle':
        return this.throttle(
          () => this.render(),
          this.options.updateStrategy.throttleDelay
        )

      case 'manual':
        return () => {} // 空函数，手动调用 refresh()

      default:
        return () => this.render()
    }
  }

  /**
   * 建立"仅重绘视口框"的节流渲染策略
   * translate/scale 事件只需更新视口矩形，不需要重绘节点/边
   */
  private setupViewportOnlyRenderStrategy(): () => void {
    const mode = this.options.updateStrategy.mode

    switch (mode) {
      case 'realtime':
        return () => this.renderViewportOnly()

      case 'throttle':
        return this.throttle(
          () => this.renderViewportOnly(),
          this.options.updateStrategy.throttleDelay
        )

      case 'manual':
        return () => {}

      default:
        return () => this.renderViewportOnly()
    }
  }

  // ===== 私有方法：渲染相关 =====

  private render(): void {
    // 性能检查：FPS限制
    if (!this.shouldRender()) {
      return
    }

    this.lastRenderTime = Date.now()

    // 计算图形包围盒和视口
    this.updateGraphBBox()
    this.updateViewportRect()
    this.updateScale()

    // 清空主Canvas
    this.ctx.clearRect(0, 0, this.canvas.width, this.canvas.height)

    // 设置背景
    this.ctx.fillStyle = '#fafafa'
    this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height)

    // 渲染内容
    if (this.graphBBox) {
      // 使用缓存或重新渲染
      if (this.options.updateStrategy.useOffscreenCache && this.cacheValid) {
        this.ctx.drawImage(this.offscreenCanvas!, 0, 0)
      } else {
        this.renderContent()
        if (this.options.updateStrategy.useOffscreenCache) {
          this.renderToOffscreen()
        }
      }

      // ⭐ 渲染内容边框（新增）
      this.renderContentBorder()
    }

    // 渲染视口矩形
    this.renderViewport()

    // 渲染缩放手柄
    if (this.options.interaction.enableZoom && this.viewportRect) {
      this.renderZoomHandle()
    }

    // 渲染调试信息
    if (this.options.debug.showFPS || this.options.debug.showNodeCount) {
      this.renderDebugInfo()
    }

    this.updateFPS()
  }

  /**
   * 轻量渲染：只重绘视口矩形，不重绘节点/边
   * 专供 translate/scale 事件使用，避免大量节点场景下的完整重绘开销
   */
  private renderViewportOnly(): void {
    // 仅更新视口矩形位置，不重算 graphBBox（BBox 未变）
    this.updateViewportRect()

    // 若没有缓存（首次或缓存已失效），回退到完整渲染
    if (!this.options.updateStrategy.useOffscreenCache || !this.cacheValid || !this.offscreenCanvas) {
      this.render()
      return
    }

    // 清空并重绘背景
    this.ctx.clearRect(0, 0, this.canvas.width, this.canvas.height)
    this.ctx.fillStyle = '#fafafa'
    this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height)

    // 贴上缓存的节点/边内容（已包含 contentBorder）
    this.ctx.drawImage(this.offscreenCanvas, 0, 0)

    // 叠加视口矩形
    this.renderViewport()

    // 渲染缩放手柄
    if (this.options.interaction.enableZoom && this.viewportRect) {
      this.renderZoomHandle()
    }

    // 渲染调试信息
    if (this.options.debug.showFPS || this.options.debug.showNodeCount) {
      this.renderDebugInfo()
    }
  }

  private renderContent(): void {
    if (!this.graphBBox) return

    const nodeCount = this.graph.getNodes().length
    const perf = this.options.performance

    // ── 骨架模式（2000+ 节点）：不绘制任何节点/边，仅靠 contentBorder 显示范围 ──
    if (nodeCount > perf.skeletonModeThreshold) {
      return
    }

    // 保存上下文
    this.ctx.save()

    // 设置裁剪区域
    const padding = this.options.padding
    this.ctx.beginPath()
    this.ctx.rect(padding, padding, this.canvas.width - 2 * padding, this.canvas.height - 2 * padding)
    this.ctx.clip()

    // ── 简化模式（500+ 节点）：只绘制节点（缩小），不绘制连线 ──
    const simplified = nodeCount > perf.simplifyThreshold

    // 渲染边（仅完整模式）
    if (!simplified && this.options.rendering.showEdges) {
      this.renderEdges()
    }

    // 渲染节点
    this.renderNodes(simplified)

    // 恢复上下文
    this.ctx.restore()
  }

  private renderToOffscreen(): void {
    if (!this.offscreenCanvas || !this.offscreenCtx) return

    // 清空离屏Canvas
    this.offscreenCtx.clearRect(0, 0, this.canvas.width, this.canvas.height)

    // 设置背景
    this.offscreenCtx.fillStyle = '#fafafa'
    this.offscreenCtx.fillRect(0, 0, this.canvas.width, this.canvas.height)

    // 临时切换上下文
    const originalCtx = this.ctx
    this.ctx = this.offscreenCtx

    // 渲染内容
    this.renderContent()

    // ⭐ 渲染内容边框到缓存
    this.renderContentBorder()

    // 恢复上下文
    this.ctx = originalCtx

    this.cacheValid = true
  }

  private renderNodes(simplified?: boolean): void {
    const nodes = this.graph.getNodes()
    // 若调用方未传入，fallback 到原有的阈值判断
    const isSimplified = simplified ?? this.shouldSimplifyRendering()

    nodes.forEach(node => {
      const isSelected = this.selectedCells.has(node.id)
      this.drawNode(node, isSelected, isSimplified)
    })
  }

  private renderEdges(): void {
    const edges = this.graph.getEdges()

    edges.forEach(edge => {
      this.drawEdge(edge)
    })
  }

  /**
   * 渲染内容边框（标识内容区域）
   */
  private renderContentBorder(): void {
    if (!this.graphBBox) return

    // 计算内容区域的实际尺寸
    const contentWidth = this.graphBBox.width * this.scale
    const contentHeight = this.graphBBox.height * this.scale

    // 保存上下文
    this.ctx.save()

    // 绘制虚线边框
    this.ctx.strokeStyle = '#d9d9d9' // 浅灰色
    this.ctx.lineWidth = 1
    this.ctx.setLineDash([4, 2]) // 虚线样式：4px实线，2px空白

    this.ctx.strokeRect(
      this.contentOffsetX,
      this.contentOffsetY,
      contentWidth,
      contentHeight
    )

    // 恢复上下文（重置虚线）
    this.ctx.setLineDash([])
    this.ctx.restore()
  }

  private renderViewport(): void {
    if (!this.viewportRect) return

    const rect = this.viewportRect

    // 绘制填充
    this.ctx.fillStyle = this.options.viewport.color
    this.ctx.fillRect(rect.x, rect.y, rect.width, rect.height)

    // 绘制边框
    this.ctx.strokeStyle = this.options.viewport.borderColor
    this.ctx.lineWidth = this.options.viewport.borderWidth
    this.ctx.strokeRect(rect.x, rect.y, rect.width, rect.height)
  }

  private renderZoomHandle(): void {
    if (!this.viewportRect) return

    const size = this.options.interaction.zoomHandleSize
    const x = this.viewportRect.x + this.viewportRect.width - size / 2
    const y = this.viewportRect.y + this.viewportRect.height - size / 2

    this.ctx.fillStyle = this.options.interaction.zoomHandleColor
    this.ctx.fillRect(x - size / 2, y - size / 2, size, size)

    this.ctx.strokeStyle = '#ffffff'
    this.ctx.lineWidth = 1
    this.ctx.strokeRect(x - size / 2, y - size / 2, size, size)
  }

  private renderDebugInfo(): void {
    this.ctx.save()
    this.ctx.fillStyle = '#000000'
    this.ctx.font = '10px monospace'

    let y = 15

    if (this.options.debug.showFPS) {
      this.ctx.fillText(`FPS: ${this.currentFPS}`, 5, y)
      y += 12
    }

    if (this.options.debug.showNodeCount) {
      const nodeCount = this.graph.getNodes().length
      this.ctx.fillText(`Nodes: ${nodeCount}`, 5, y)
    }

    this.ctx.restore()
  }

  // ===== 私有方法：节点和边的绘制 =====

  private drawNode(node: Node, isSelected: boolean, simplified: boolean): void {
    const bbox = node.getBBox()
    const miniMapPos = this.graphToMiniMap({ x: bbox.x, y: bbox.y })

    if (!this.isInView(miniMapPos, bbox.width * this.scale, bbox.height * this.scale)) {
      return
    }

    let w = bbox.width * this.scale
    let h = bbox.height * this.scale

    // 简化渲染
    if (simplified) {
      const scale = this.options.performance.simplifiedRendering.nodeScale
      w *= scale
      h *= scale
    }

    // 绘制节点矩形
    this.ctx.fillStyle = this.getNodeColor(node)
    this.ctx.fillRect(miniMapPos.x, miniMapPos.y, w, h)

    // 绘制节点边框
    this.ctx.strokeStyle = this.options.rendering.nodeBorderColor
    this.ctx.lineWidth = this.options.rendering.nodeBorderWidth
    this.ctx.strokeRect(miniMapPos.x, miniMapPos.y, w, h)

    // 选中高亮
    if (isSelected && this.options.interaction.highlightSelected) {
      this.ctx.strokeStyle = this.options.rendering.selectedNodeColor
      this.ctx.lineWidth = this.options.rendering.selectedNodeBorderWidth
      this.ctx.strokeRect(miniMapPos.x, miniMapPos.y, w, h)
    }

    // 绘制文字
    if (this.options.rendering.showNodeLabels && !simplified) {
      this.drawNodeLabel(node, miniMapPos.x + w / 2, miniMapPos.y + h / 2)
    }
  }

  private drawEdge(edge: Edge): void {
    const sourceNode = edge.getSourceNode()
    const targetNode = edge.getTargetNode()

    if (!sourceNode || !targetNode) return

    const sourceBBox = sourceNode.getBBox()
    const targetBBox = targetNode.getBBox()

    const sourceCenter = {
      x: sourceBBox.x + sourceBBox.width / 2,
      y: sourceBBox.y + sourceBBox.height / 2,
    }

    const targetCenter = {
      x: targetBBox.x + targetBBox.width / 2,
      y: targetBBox.y + targetBBox.height / 2,
    }

    const start = this.graphToMiniMap(sourceCenter)
    const end = this.graphToMiniMap(targetCenter)

    this.ctx.strokeStyle = this.options.rendering.edgeColor
    this.ctx.lineWidth = this.options.rendering.edgeWidth
    this.ctx.beginPath()
    this.ctx.moveTo(start.x, start.y)
    this.ctx.lineTo(end.x, end.y)
    this.ctx.stroke()
  }

  private drawNodeLabel(node: Node, centerX: number, centerY: number): void {
    const label = node.attr('label/text') as string || node.id
    if (!label) return

    this.ctx.save()
    this.ctx.fillStyle = '#000000'
    this.ctx.font = `${this.options.rendering.nodeLabelFontSize}px sans-serif`
    this.ctx.textAlign = 'center'
    this.ctx.textBaseline = 'middle'

    // 截断文字
    const maxWidth = this.options.rendering.nodeLabelMaxWidth
    const text = this.truncateText(label, maxWidth)

    this.ctx.fillText(text, centerX, centerY)
    this.ctx.restore()
  }

  private getNodeColor(node: Node): string {
    if (!this.options.rendering.colorByNodeType) {
      return this.options.rendering.defaultNodeColor
    }

    const nodeData = node.getData() as any
    const nodeType = nodeData?.type || node.shape

    const color = this.options.rendering.nodeColorMap[nodeType]
    return color || this.options.rendering.defaultNodeColor
  }

  // ===== 私有方法：计算和坐标转换 =====

  private updateGraphBBox(): void {
    // 缓存有效时直接跳过，避免每帧遍历所有节点调用 getBBox()
    if (!this.graphBBoxDirty && this.graphBBox !== null) {
      return
    }

    const nodes = this.graph.getNodes()
    if (nodes.length === 0) {
      this.graphBBox = null
      this.graphBBoxDirty = false
      return
    }

    let minX = Infinity
    let minY = Infinity
    let maxX = -Infinity
    let maxY = -Infinity

    nodes.forEach(node => {
      const bbox = node.getBBox()
      minX = Math.min(minX, bbox.x)
      minY = Math.min(minY, bbox.y)
      maxX = Math.max(maxX, bbox.x + bbox.width)
      maxY = Math.max(maxY, bbox.y + bbox.height)
    })

    this.graphBBox = {
      x: minX,
      y: minY,
      width: maxX - minX,
      height: maxY - minY,
    }
    this.graphBBoxDirty = false
  }

  private updateViewportRect(): void {
    if (!this.graphBBox) {
      this.viewportRect = null
      return
    }

    const graphArea = this.graph.getGraphArea()
    if (!graphArea) {
      this.viewportRect = null
      return
    }

    const topLeft = this.graphToMiniMap({ x: graphArea.x, y: graphArea.y })
    const bottomRight = this.graphToMiniMap({
      x: graphArea.x + graphArea.width,
      y: graphArea.y + graphArea.height,
    })

    this.viewportRect = {
      x: topLeft.x,
      y: topLeft.y,
      width: bottomRight.x - topLeft.x,
      height: bottomRight.y - topLeft.y,
    }
  }

  private updateScale(): void {
    if (!this.graphBBox) {
      this.scale = 1
      this.contentOffsetX = 0
      this.contentOffsetY = 0
      return
    }

    const padding = this.options.padding
    const availableWidth = this.canvas.width - 2 * padding
    const availableHeight = this.canvas.height - 2 * padding

    const scaleX = availableWidth / this.graphBBox.width
    const scaleY = availableHeight / this.graphBBox.height

    this.scale = Math.min(scaleX, scaleY)

    // ⭐ 计算居中偏移
    const contentWidth = this.graphBBox.width * this.scale
    const contentHeight = this.graphBBox.height * this.scale

    this.contentOffsetX = padding + (availableWidth - contentWidth) / 2
    this.contentOffsetY = padding + (availableHeight - contentHeight) / 2
  }

  private graphToMiniMap(point: Point): Point {
    if (!this.graphBBox) {
      return { x: 0, y: 0 }
    }

    return {
      x: this.contentOffsetX + (point.x - this.graphBBox.x) * this.scale,
      y: this.contentOffsetY + (point.y - this.graphBBox.y) * this.scale,
    }
  }

  private miniMapToGraph(point: Point): Point {
    if (!this.graphBBox) {
      return { x: 0, y: 0 }
    }

    return {
      x: this.graphBBox.x + (point.x - this.contentOffsetX) / this.scale,
      y: this.graphBBox.y + (point.y - this.contentOffsetY) / this.scale,
    }
  }

  // ===== 私有方法：事件处理 =====

  private bindGraphEvents(): void {
    const handlers = {
      'node:added': () => this.onNodeChange(),
      'node:removed': () => this.onNodeChange(),
      'node:moved': () => this.onNodeChange(),
      'node:change:position': () => this.onNodeChange(),
      'node:change:size': () => this.onNodeChange(),
      'edge:added': () => this.onEdgeChange(),
      'edge:removed': () => this.onEdgeChange(),
      'selection:changed': (args: any) => this.onSelectionChanged(args),
      'translate': () => this.onViewportChange(),
      'scale': () => this.onViewportChange(),
      'resize': () => this.onGraphResize(),
    }

    Object.entries(handlers).forEach(([event, handler]) => {
      this.graph.on(event, handler)
      this.boundHandlers.set(`graph:${event}`, handler)
    })
  }

  private unbindGraphEvents(): void {
    this.boundHandlers.forEach((handler, key) => {
      if (key.startsWith('graph:')) {
        const event = key.replace('graph:', '')
        this.graph.off(event, handler)
      }
    })
  }

  private bindCanvasEvents(): void {
    const handlers = {
      mousedown: (e: Event) => this.onCanvasMouseDown(e as MouseEvent),
      mousemove: (e: Event) => this.onCanvasMouseMove(e as MouseEvent),
      mouseup: (e: Event) => this.onCanvasMouseUp(e as MouseEvent),
      click: (e: Event) => this.onCanvasClick(e as MouseEvent),
    }

    Object.entries(handlers).forEach(([event, handler]) => {
      this.canvas.addEventListener(event, handler)
      this.boundHandlers.set(`canvas:${event}`, handler)
    })
  }

  private unbindCanvasEvents(): void {
    this.boundHandlers.forEach((handler, key) => {
      if (key.startsWith('canvas:')) {
        const event = key.replace('canvas:', '')
        this.canvas.removeEventListener(event, handler)
      }
    })
  }

  private onNodeChange(): void {
    this.log('节点变化')
    // 节点增删/移动/尺寸变化都需要重算 graphBBox
    this.graphBBoxDirty = true
    if (this.options.updateStrategy.cacheInvalidation === 'nodeChange') {
      this.invalidateCache()
    }
    this.throttledRender()
  }

  private onEdgeChange(): void {
    this.log('边变化')
    if (this.options.updateStrategy.cacheInvalidation === 'nodeChange') {
      this.invalidateCache()
    }
    this.throttledRender()
  }

  private onSelectionChanged(args: any): void {
    this.log('选中变化', args)

    this.selectedCells.clear()
    const selected = args.selected || []
    selected.forEach((cell: Cell) => {
      this.selectedCells.add(cell.id)
    })

    this.throttledRender()
  }

  private onViewportChange(): void {
    this.log('视口变化')
    // 视口变化只需更新视口矩形，不重绘节点/边内容
    this.throttledRenderViewportOnly()
  }

  private onGraphResize(): void {
    this.log('画布大小变化')
    this.throttledRender()
  }

  private onCanvasMouseDown(e: MouseEvent): void {
    if (!this.viewportRect) return

    const point = this.getCanvasPoint(e)

    if (this.isPointInViewport(point)) {
      this.isDragging = true
      this.dragStartPos = point
      this.canvas.style.cursor = 'grabbing'
    }
  }

  private onCanvasMouseMove(e: MouseEvent): void {
    if (!this.isDragging || !this.dragStartPos) return

    if (this.options.interaction.enableDragToNavigate) {
      const point = this.getCanvasPoint(e)
      this.handleDragNavigation(point)
      this.dragStartPos = point
    }
  }

  private onCanvasMouseUp(e: MouseEvent): void {
    if (this.isDragging) {
      this.isDragging = false
      this.dragStartPos = null
      this.canvas.style.cursor = 'pointer'
    }
  }

  private onCanvasClick(e: MouseEvent): void {
    if (!this.options.interaction.enableClickToNavigate) return
    if (this.isDragging) return // 拖拽不触发点击

    const point = this.getCanvasPoint(e)
    this.handleClickNavigation(point)
  }

  // ===== 私有方法：交互逻辑 =====

  private handleClickNavigation(point: Point): void {
    const graphPoint = this.miniMapToGraph(point)
    this.graph.centerPoint(graphPoint.x, graphPoint.y)
    this.log('点击导航到', graphPoint)
  }

  private handleDragNavigation(point: Point): void {
    if (!this.dragStartPos) return

    const delta = {
      x: point.x - this.dragStartPos.x,
      y: point.y - this.dragStartPos.y,
    }

    const graphDelta = {
      x: delta.x / this.scale,
      y: delta.y / this.scale,
    }

    const currentTranslate = this.graph.translate()
    this.graph.translate(
      currentTranslate.tx - graphDelta.x,
      currentTranslate.ty - graphDelta.y
    )

    this.log('拖拽导航', graphDelta)
  }

  // ===== 工具方法 =====

  private getCanvasPoint(e: MouseEvent): Point {
    const rect = this.canvas.getBoundingClientRect()
    return {
      x: e.clientX - rect.left,
      y: e.clientY - rect.top,
    }
  }

  private isPointInViewport(point: Point): boolean {
    if (!this.viewportRect) return false

    return (
      point.x >= this.viewportRect.x &&
      point.x <= this.viewportRect.x + this.viewportRect.width &&
      point.y >= this.viewportRect.y &&
      point.y <= this.viewportRect.y + this.viewportRect.height
    )
  }

  private isInView(point: Point, width: number, height: number): boolean {
    const padding = this.options.padding
    return !(
      point.x + width < padding ||
      point.y + height < padding ||
      point.x > this.canvas.width - padding ||
      point.y > this.canvas.height - padding
    )
  }

  private truncateText(text: string, maxWidth: number): string {
    this.ctx.font = `${this.options.rendering.nodeLabelFontSize}px sans-serif`
    const metrics = this.ctx.measureText(text)

    if (metrics.width <= maxWidth) {
      return text
    }

    let truncated = text
    while (this.ctx.measureText(truncated + '...').width > maxWidth && truncated.length > 0) {
      truncated = truncated.slice(0, -1)
    }

    return truncated + '...'
  }

  // ===== 工具方法 =====

  private createOffscreenCanvas(): void {
    this.offscreenCanvas = document.createElement('canvas')
    this.offscreenCanvas.width = this.canvas.width
    this.offscreenCanvas.height = this.canvas.height
    this.offscreenCtx = this.offscreenCanvas.getContext('2d')!
  }

  private invalidateCache(): void {
    this.cacheValid = false
  }

  private shouldRender(): boolean {
    const minInterval = 1000 / this.options.performance.maxFPS
    const now = Date.now()
    return now - this.lastRenderTime >= minInterval
  }

  private shouldSimplifyRendering(): boolean {
    const nodeCount = this.graph.getNodes().length
    return nodeCount > this.options.performance.simplifyThreshold
  }

  private updateFPS(): void {
    this.frameCount++
    const now = Date.now()

    if (now - this.lastFPSUpdate >= 1000) {
      this.currentFPS = this.frameCount
      this.frameCount = 0
      this.lastFPSUpdate = now
    }
  }

  private throttle(func: Function, delay: number): () => void {
    let lastCall = 0
    let timeoutId: number | null = null

    return () => {
      const now = Date.now()

      if (now - lastCall >= delay) {
        lastCall = now
        func()
      } else {
        if (timeoutId !== null) {
          clearTimeout(timeoutId)
        }
        timeoutId = window.setTimeout(() => {
          lastCall = Date.now()
          func()
        }, delay - (now - lastCall))
      }
    }
  }

  private log(...args: any[]): void {
    if (this.options.debug.enableLog) {
      console.log('[CustomMiniMap]', ...args)
    }
  }

  private clamp(value: number, min: number, max: number): number {
    return Math.min(Math.max(value, min), max)
  }
}
