<template>
  <a-form layout="vertical" size="small">
    <a-form-item label="节点名称">
      <a-input v-model:value="form.label" @change="emitUpdate" />
    </a-form-item>

    <a-divider>分支配置</a-divider>

    <div v-for="(branch, idx) in form.branches" :key="branch.portId" class="branch-item">
      <div class="branch-header">
        <a-tag :color="branch.isDefault ? 'default' : 'orange'" style="margin: 0">
          {{ branch.isDefault ? '默认分支' : `分支 ${idx + 1}` }}
        </a-tag>
        <a-button
                    v-if="!branch.isDefault"
          type="text"
          danger
          size="small"
          @click="removeBranch(idx)"
        >
          删除
        </a-button>
      </div>
      <a-form-item label="分支名称" style="margin-top: 8px; margin-bottom: 6px">
        <a-input v-model:value="branch.label" @change="emitUpdate" />
      </a-form-item>
      <a-form-item v-if="!branch.isDefault" label="条件表达式">
        <a-textarea
          v-model:value="branch.condition"
          :rows="2"
          :placeholder="'例：${金额} > 10000'"
          @change="emitUpdate"
        />
      </a-form-item>
    </div>

    <a-button
      block
      dashed
      :disabled="nonDefaultBranches >= 6"
      @click="addBranch"
      style="margin-top: 8px"
    >
      + 添加分支
    </a-button>

    <a-alert
      type="info"
      show-icon
      style="margin-top: 12px"
      :message="'可用变量：${发起人}  ${部门}  ${金额}  ${日期}'"
    />
  </a-form>
</template>

<script setup lang="ts">
import { reactive, computed, watch } from 'vue'
import { v4 as uuidv4 } from 'uuid'
import type { Node } from '@antv/x6'
import type { FlowNodeData, ConditionBranch } from '../types/flow.types'

const props = defineProps<{ node: Node }>()
const emit  = defineEmits<{ (e: 'update', data: FlowNodeData): void }>()
const form = reactive<FlowNodeData>({ label: '', branches: [], ...props.node.getData() })
watch(() => props.node.getData(), (d) => { if (d) Object.assign(form, d) }, { deep: true })

const nonDefaultBranches = computed(
  () => (form.branches ?? []).filter(b => !b.isDefault).length
)

function addBranch() {
  const portId = `out-extra-${uuidv4().slice(0, 6)}`
  const branch: ConditionBranch = { portId, label: `条件${nonDefaultBranches.value + 1}`, condition: '', isDefault: false }
  form.branches = [...(form.branches ?? []).filter(b => !b.isDefault), branch, ...(form.branches ?? []).filter(b => b.isDefault)]
  emitUpdate()
}

function removeBranch(idx: number) {
  form.branches = (form.branches ?? []).filter((_, i) => i !== idx)
  emitUpdate()
}

function emitUpdate() {
  emit('update', { ...form })
}
</script>

<style scoped>
.branch-item {
  background: #fafafa; border: 1px solid #f0f0f0;
  border-radius: 6px; padding: 10px 12px; margin-bottom: 8px;
}
.branch-header {
  display: flex; align-items: center; justify-content: space-between;
}
</style>
