import { register } from '@antv/x6-vue-shape'
import { Graph, Shape } from '@antv/x6'
import type { Component } from 'vue'
import GroupNode       from './GroupNode.vue'
import CommonVueNode   from './CommonVueNode.vue'
import { DEFAULT_CANVAS_CONFIG } from './core/defaultConfig'

// ─── 公共 Port 样式 ───────────────────────────────────────────────────────────

export interface PortDefaultConfig {
  fill: string
  stroke: string
  size: number
  strokeWidth: number
}

function makePortAttr(cfg: PortDefaultConfig) {
  return {
    circle: {
      r: cfg.size,
      magnet: true,
      stroke: cfg.stroke,
      strokeWidth: cfg.strokeWidth,
      fill: cfg.fill,
      style: { visibility: 'hidden' },
    },
  }
}

const DEFAULT_PORT_CONFIG: PortDefaultConfig = DEFAULT_CANVAS_CONFIG.highlight.portDefault

// 统一的4个双向锚点（上下左右均可入线和出线）
function makeFourWayPorts(cfg: PortDefaultConfig = DEFAULT_PORT_CONFIG) {
  const attr = makePortAttr(cfg)
  return {
    groups: {
      top:    { position: 'top',    attrs: attr },
      right:  { position: 'right',  attrs: attr },
      bottom: { position: 'bottom', attrs: attr },
      left:   { position: 'left',   attrs: attr },
    },
    items: [
      { group: 'top',    id: 'port-top'    },
      { group: 'right',  id: 'port-right'  },
      { group: 'bottom', id: 'port-bottom' },
      { group: 'left',   id: 'port-left'   },
    ],
  }
}

// ─── 注册所有节点 ─────────────────────────────────────────────────────────────
export function registerAllInnerNodes(portConfig?: PortDefaultConfig) {
  const cfg = portConfig ?? DEFAULT_PORT_CONFIG

  // 组节点
  register({
    shape: 'group-node',
    width: 300,
    height: 200,
    component: GroupNode as Component,
    ports: {}, // 组节点不需要连接点
  })

  // 通用 Vue 节点（不固定大小，由内容撑开）
  register({
    shape: 'common-vue-node',
    width: 200,
    height: 72,
    component: CommonVueNode as Component,
    ports: makeFourWayPorts(cfg),
  })
}













































































