import { Graph, Node, Edge } from '@antv/x6'
import type { CanvasConfigManager } from './CanvasConfigManager'
import type { ModeManager } from './ModeManager'
import type { CanvasConfig } from '../../../views/types/flow.types'

// ─── 类型定义 ───────────────────────────────────────────────────────────────

/** 边状态上下文（传递给状态处理器） */
export interface EdgeStateContext {
  config: CanvasConfig
  graph: Graph
  manager: EdgeStateManager
}

/** 边状态处理器接口 */
export interface EdgeStateHandler {
  /**
   * 应用状态样式
   * @param edge 目标连线
   * @param context 上下文（包含 config、graph、manager）
   */
  apply(edge: Edge, context: EdgeStateContext): void

  /**
   * 清理状态（可选，离开状态时调用）
   * @param edge 目标连线
   * @param context 上下文
   */
  cleanup?(edge: Edge, context: EdgeStateContext): void
}

/** 边状态类型 */
export type EdgeState = 'default' | 'selected' | 'hover' | 'flowing' | 'dimmed' | string

// ─── 配置选项 ───────────────────────────────────────────────────────────────

export interface EdgeStateManagerOptions {
  graph: Graph
  config: CanvasConfigManager
  mode: ModeManager
  tooltipEl?: HTMLElement | null
  /**
   * 获取回调函数的 getter，动态获取最新的回调引用
   * （解决 FlowDesigner 构造函数中值传递导致的回调丢失问题）
   */
  getCallbacks?: () => {
    onEdgeLabelRender?: (fo: SVGForeignObjectElement, edge: Edge, data: any) => (() => void)
    onTooltipChange?: (payload: any) => void
  }
}

/**
 * EdgeStateManager 边状态管理器
 *
 * 职责：
 * - 管理边的状态（default、hover、selected、flowing、dimmed等）
 * - 管理边的标签渲染（SVG/Vue）
 * - 管理边的流动动画（节点hover时的出线效果）
 * - 提供边状态处理器的注册/获取/移除 API
 */
export class EdgeStateManager {
  private graph: Graph
  private config: CanvasConfigManager
  private mode: ModeManager
  private tooltipEl: HTMLElement | null
  private getCallbacks: () => {
    onEdgeLabelRender?: (fo: SVGForeignObjectElement, edge: Edge, data: any) => (() => void)
    onTooltipChange?: (payload: any) => void
  }

  // 状态处理器注册表（策略模式）
  private stateHandlers: Map<string, EdgeStateHandler> = new Map()

  // 按边类型注册的处理器（edge.shape -> stateName -> handler）
  private typeHandlers: Map<string, Map<string, EdgeStateHandler>> = new Map()
  private readonly GLOBAL_KEY = '__global__'

  // 状态来源追踪（用于区分内置状态和用户自定义状态）
  private readonly BUILTIN_STATES = new Set(['default', 'hover', 'selected', 'flowing', 'dimmed'])
  private userDefinedStates: Set<string> = new Set()     // 用户新增的状态
  private overriddenStates: Set<string> = new Set()      // 用户覆盖的内置状态

  // hover 状态追踪
  private hoveredEdgeId: string | null = null

  // label 渲染相关
  private isRenderingLabel = false
  private labelRafMap: Map<string, number> = new Map()
  private labelUnmountMap: Map<string, () => void> = new Map()

  constructor(options: EdgeStateManagerOptions) {
    this.graph = options.graph
    this.config = options.config
    this.mode = options.mode
    this.tooltipEl = options.tooltipEl || null
    this.getCallbacks = options.getCallbacks || (() => ({}))

    // 注册内置状态处理器
    this.registerBuiltInHandlers()
  }

  // ─── 状态管理 API ───────────────────────────────────────────────────────────

  /**
   * 设置连线状态：使用策略模式调用注册的状态处理器
   * @param edge  目标连线
   * @param state 状态名称（default | selected | hover | flowing | dimmed | 自定义状态）
   *
   * 注意：此方法是幂等的，即使状态相同也会重新应用样式（用于修复被外部修改的样式）
   */
  public setEdgeState(edge: Edge, state: string): void {
    // 1. 从 prop 读取当前状态（不污染业务 data）
    const prevState = edge.getProp('_state') ?? 'default'

    // 2. 只有在状态真正切换时，才调用旧状态的 cleanup
    if (prevState !== state) {
      const prevHandler = this.getHandler(edge, prevState)
      if (prevHandler?.cleanup) {
        try {
          prevHandler.cleanup(edge, this.getStateContext())
        } catch (error) {
          console.error(`[EdgeStateManager] Error cleaning up state "${prevState}":`, error)
        }
      }
    }

    // 3. 更新状态到 prop（移除 silent: true，触发 change:_state 事件）
    edge.setProp('_state', state)

    // 4. 调用新状态的 apply（即使状态相同也重新应用，用于修复被外部修改的样式）
    const handler = this.getHandler(edge, state)
    if (!handler) {
      console.warn(`[EdgeStateManager] Unknown edge state: "${state}", available states:`, this.getRegisteredStates())
      return
    }

    try {
      handler.apply(edge, this.getStateContext())
    } catch (error) {
      console.error(`[EdgeStateManager] Error applying state "${state}":`, error)
    }

    // 5. 判断是否需要更新 label（用户自定义状态完全由用户控制）
    const isUserControlled = this.userDefinedStates.has(state) || this.overriddenStates.has(state)

    if (!isUserControlled) {
      // 内置状态：系统自动管理 label 样式
      this.setEdgeLabel(edge, undefined, state as EdgeState)
    }
    // 用户自定义状态或覆盖的内置状态：不调用 setEdgeLabel()，完全由用户的 apply() 控制
  }

  /**
   * 重置所有连线为 default 状态（可排除指定连线）
   */
  public resetAllEdges(exceptId?: string): void {
    this.graph.getEdges().forEach((edge) => {
      if (edge.id !== exceptId) {
        this.setEdgeState(edge, 'default')
      }
    })
  }

  /**
   * 获取边状态上下文
   */
  public getStateContext(): EdgeStateContext {
    return {
      config: this.config.getConfig(),
      graph: this.graph,
      manager: this,
    }
  }

  /**
   * 获取边的状态处理器（带降级）
   * @param edge 目标边
   * @param stateName 状态名称
   * @returns 找到的处理器，优先返回边类型专属，其次返回全局
   */
  private getHandler(edge: Edge, stateName: string): EdgeStateHandler | undefined {
    const edgeType = edge.shape

    // 先查边类型专属
    const typeHandlers = this.typeHandlers.get(edgeType)
    if (typeHandlers?.has(stateName)) {
      return typeHandlers.get(stateName)
    }

    // 降级到全局
    return this.stateHandlers.get(stateName)
  }

  /**
   * 从 edge 的 labels 中提取文本
   * 支持两种 label 结构：
   * 1. flow-edge: attrs.label.text
   * 2. 普通 edge: attrs.text.text
   * @private
   */
  private getEdgeLabelText(edge: Edge): string {
    const labels = edge.getLabels()

    if (!labels || labels.length === 0) {
      return ''
    }

    const firstLabel = labels[0]

    // 支持两种 label 结构
    return firstLabel.attrs?.label?.text || firstLabel.attrs?.text?.text || ''
  }

  // ─── 流动动画管理 ───────────────────────────────────────────────────────────

  /**
   * 对指定节点的所有出线启动流动动画
   */
  public startOutEdgeFlow(node: Node): void {
    const flowCfg = this.config.getConfig().highlight.nodeHoverOutEdgeFlow
    if (!flowCfg?.enabled) return

    // 节点数量阈值保护：防止节点过多时出线流动导致性能问题
    const threshold = flowCfg.disableWhenNodeCountExceeds
    if (threshold && threshold > 0) {
      const nodeCount = this.graph.getNodes().length
      if (nodeCount > threshold) return
    }

    const outEdges = this.graph.getConnectedEdges(node, { outgoing: true })

    // 出线数量阈值保护：防止某个节点出线过多时流动动画影响性能
    const outEdgeThreshold = flowCfg.disableWhenOutEdgeCountExceeds
    if (outEdgeThreshold && outEdgeThreshold > 0) {
      if (outEdges.length > outEdgeThreshold) return
    }

    // 为每条出线设置 flowing 状态
    outEdges.forEach((edge) => {
      // 从 prop 读取当前状态
      const currentState = edge.getProp('_state') ?? 'default'

      // 保存当前状态（如果不是 flowing）
      if (currentState !== 'flowing') {
        // 使用 prop 保存原状态，不污染业务数据
        edge.setProp('_prevState', currentState, { silent: true })
      }

      // 切换到 flowing 状态
      this.setEdgeState(edge, 'flowing')
    })
  }

  /**
   * 还原指定节点的所有出线流动动画
   */
  public stopOutEdgeFlow(node: Node): void {
    const flowCfg = this.config.getConfig().highlight.nodeHoverOutEdgeFlow
    if (!flowCfg?.enabled) return

    const outEdges = this.graph.getConnectedEdges(node, { outgoing: true })

    outEdges.forEach((edge) => {
      // 从 prop 读取当前状态
      const currentState = edge.getProp('_state') ?? 'default'

      // 只处理当前处于 flowing 状态的边
      if (currentState === 'flowing') {
        // 从 prop 中恢复之前保存的状态
        const prevState = edge.getProp('_prevState') ?? 'default'

        // 清除 prop 中的 _prevState 标记
        edge.removeProp('_prevState', { silent: true })

        // 恢复状态
        this.setEdgeState(edge, prevState)
      }
    })
  }

  /**
   * 还原画布中所有出线的流动动画（blank:click 等全局清理场景）
   */
  public stopAllOutEdgeFlows(): void {
    const flowCfg = this.config.getConfig().highlight.nodeHoverOutEdgeFlow
    if (!flowCfg?.enabled) return

    this.graph.getEdges().forEach((edge) => {
      // 从 prop 读取当前状态
      const currentState = edge.getProp('_state') ?? 'default'

      // 只处理 flowing 状态的边
      if (currentState === 'flowing') {
        // 全局清理：直接恢复为 default，清除 prop 中的 _prevState
        edge.removeProp('_prevState', { silent: true })

        this.setEdgeState(edge, 'default')
      }
    })
  }

  // ─── 标签管理 ───────────────────────────────────────────────────────────────

  /**
   * 设置连线标签（统一入口，命令式调用）
   * @param edge 目标连线
   * @param label 标签文本（undefined 则保持当前值）
   * @param state 状态（undefined 则保持当前值）
   */
  public setEdgeLabel(
    edge: Edge,
    label?: string,
    state?: EdgeState
  ): void {
    // ✅ 改造：从 labels 读取，不再使用 data.label
    // 如果 label 未传入，从 edge.getLabels() 读取当前文本
    const finalLabel = label !== undefined ? label : this.getEdgeLabelText(edge)

    // 从 prop 读取状态，而不是从 data 读取
    const finalState = state !== undefined ? state : (edge.getProp('_state') ?? 'default')

    // ✅ 移除 data 操作，不再污染业务数据
    // edge.setData({ ...currentData, label: finalLabel }, { silent: true })

    // 直接调用渲染
    // renderSVGLabel 和 renderVueLabel 都会检查 !label.trim()，
    // 如果为空则调用 edge.setLabels([]) 完全移除 label（包括包围框）
    this.renderEdgeLabel(edge, finalLabel, finalState)
  }

  /**
   * 只更新连线标签的文本内容，保持当前样式和状态不变
   * @param edge 目标连线
   * @param label 新的标签文本
   * @example
   * ```ts
   * // 只修改 label 文本，不改变当前的高亮、选中等状态样式
   * edgeStateManager.updateEdgeLabelText(edge, '新标签')
   * ```
   */
  public updateEdgeLabelText(edge: Edge, label: string): void {
    // ✅ 改造：移除 data 操作
    // 从 prop 读取当前状态
    const currentState = edge.getProp('_state') ?? 'default'

    // ✅ 直接渲染，不更新 data
    // 重新渲染 label（使用当前的 state，样式保持不变）
    this.renderEdgeLabel(edge, label, currentState)
  }

  /**
   * 内部渲染方法
   */
  private renderEdgeLabel(edge: Edge, label: string, state: string): void {
    if (this.isRenderingLabel) return
    this.isRenderingLabel = true

    try {
      // 检查是否为用户自定义状态
      const isUserControlled = this.userDefinedStates.has(state) || this.overriddenStates.has(state)

      if (isUserControlled) {
        // 用户自定义状态：只更新文本，不改变样式
        this.updateLabelTextOnly(edge, label)
        return
      }

      // 内置状态：完整渲染
      const callbacks = this.getCallbacks()
      if (callbacks?.onEdgeLabelRender) {
        this.renderVueLabel(edge, label, state)
      } else {
        this.renderSVGLabel(edge, label, state)
      }
    } finally {
      this.isRenderingLabel = false
    }
  }

  /**
   * 仅更新 label 文本，保持现有样式（用于用户自定义状态）
   * @private
   */
  private updateLabelTextOnly(edge: Edge, label: string): void {
    const labels = edge.getLabels()
    if (labels.length === 0) return

    const firstLabel = labels[0]

    // 优先更新 attrs.label.text（用于 flow-edge）
    if (firstLabel.attrs?.label) {
      edge.setLabelAt(0, {
        ...firstLabel,
        attrs: {
          ...firstLabel.attrs,
          label: {
            ...firstLabel.attrs.label,
            text: label
          }
        }
      })
    }
    // 回退到 attrs.text.text（用于普通 SVG label）
    else if (firstLabel.attrs?.text) {
      edge.setLabelAt(0, {
        ...firstLabel,
        attrs: {
          ...firstLabel.attrs,
          text: {
            ...firstLabel.attrs.text,
            text: label
          }
        }
      })
    }
  }

  /**
   * 同步 SVG label 渲染
   */
  private renderSVGLabel(edge: Edge, label: string, state: string): void {
    const config = this.config.getConfig()
    if (!label.trim()) {
      edge.setLabels([])
      return
    }

    // 确保 config 存在
    if (!config) {
      console.warn('[EdgeStateManager] Config is undefined')
      return
    }

    // 检查是否需要降低透明度（通过 prop 标记）
    const labelOpacity = edge.getProp('_labelOpacity') ?? 1

    // 根据 state 选择文本颜色
    let textColor = config.connection.label.textColor || '#999999'
    if (state === 'selected' && config.highlight.edgeSelected.enabled) {
      textColor = (config.highlight.edgeSelected as any).textColor || config.highlight.edgeSelected.strokeColor
    } else if (state === 'hover' && config.highlight.edgeHover.enabled) {
      textColor = (config.highlight.edgeHover as any).textColor || config.highlight.edgeHover.strokeColor
    }

    // 根据 state 选择 label 边框颜色
    let borderColor = config.connection.label.borderColor || '#999999'
    if (state === 'selected' && config.highlight.edgeSelected.enabled) {
      borderColor = config.highlight.edgeSelected.strokeColor
    } else if (state === 'hover' && config.highlight.edgeHover.enabled) {
      borderColor = config.highlight.edgeHover.strokeColor
    }

    let borderWidth = config.connection.label.borderWidth || 1
    if (state === 'selected' && config.highlight.edgeSelected.enabled) {
      borderWidth = config.highlight.edgeSelected.strokeWidth
    } else if (state === 'hover' && config.highlight.edgeHover.enabled) {
      borderWidth = config.highlight.edgeHover.strokeWidth
    }

    const labelCfg = config.connection.label
    edge.setLabels([
      {
        attrs: {
          body: {
            fill: labelCfg.backgroundColor,
            stroke: borderColor,
            strokeWidth: borderWidth,
            rx: labelCfg.borderRadius,
            ry: labelCfg.borderRadius,
            refWidth: (labelCfg.paddingX ?? labelCfg.padding) * 2,
            refHeight: (labelCfg.paddingY ?? labelCfg.padding) * 2,
            refX: -(labelCfg.paddingX ?? labelCfg.padding),
            refY: -(labelCfg.paddingY ?? labelCfg.padding) + (labelCfg.offsetY ?? 0),
            filter: {
              name: 'dropShadow',
              args: { dx: 0, dy: 1, stdDeviation: 2, color: 'rgba(0,0,0,0.10)' },
            },
            fillOpacity: labelOpacity,
            strokeOpacity: labelOpacity,
            cursor: 'pointer',
          },
          label: {
            text: label,
            fill: textColor,
            fontSize: labelCfg.fontSize,
            fontWeight: labelCfg.fontWeight,
            textAnchor: labelCfg.textAnchor,
            textVerticalAnchor: labelCfg.textVerticalAnchor,
            pointerEvents: labelCfg.pointerEvents,
            fillOpacity: labelOpacity,
            cursor: 'pointer',
          },
        },
        position: { distance: labelCfg.position },
      },
    ])
  }

  /**
   * 同步 Vue label 渲染
   */
  private renderVueLabel(edge: Edge, label: string, state: string): void {
    const config = this.config.getConfig()
    // 动态获取最新的回调引用
    const callbacks = this.getCallbacks()
    const renderer = callbacks?.onEdgeLabelRender
    if (!renderer || !config) return

    // 取消该 edge 上未执行的旧 rAF（防止竞态条件）
    const oldRaf = this.labelRafMap.get(edge.id)
    if (oldRaf !== undefined) {
      cancelAnimationFrame(oldRaf)
      this.labelRafMap.delete(edge.id)
    }

    // 卸载当前 edge 上已有的 Vue app
    const prevUnmount = this.labelUnmountMap.get(edge.id)
    if (prevUnmount) {
      prevUnmount()
      this.labelUnmountMap.delete(edge.id)
    }

    if (!label.trim()) {
      edge.setLabels([])
      return
    }

    // 设置一个最小化的占位符 label，放置 foreignObject
    edge.setLabels([
      {
        markup: [{ tagName: 'foreignObject', selector: 'fo' }],
        attrs: {
          fo: {
            width: 1,
            height: 1,
            x: 0,
            y: 0,
            style: 'overflow: visible; pointer-events: none;',
          },
        },
        position: { distance: config.connection.label.position },
      },
    ])

    // 延迟一帧，等 X6 将 foreignObject 渲染到 DOM
    const rafId = requestAnimationFrame(() => {
      this.labelRafMap.delete(edge.id)
      const edgeView = this.graph.findViewByCell(edge)
      if (!edgeView) return
      const fo = edgeView.container.querySelector('foreignObject') as SVGForeignObjectElement | null
      if (!fo) return
      const unmount = renderer(fo, edge, { label, state })
      this.labelUnmountMap.set(edge.id, unmount)
    })
    this.labelRafMap.set(edge.id, rafId)
  }

  // ─── Hover 状态追踪 ─────────────────────────────────────────────────────────

  /**
   * 设置当前 hover 的边 ID
   */
  public setHoveredEdge(edgeId: string | null): void {
    this.hoveredEdgeId = edgeId
  }

  /**
   * 获取当前 hover 的边 ID
   */
  public getHoveredEdge(): string | null {
    return this.hoveredEdgeId
  }

  // ─── 状态处理器注册 ─────────────────────────────────────────────────────────

  /**
   * 注册或覆盖边状态处理器（公共 API）
   * @param stateName 状态名称（如 'flowing', 'warning', 'error'）
   * @param handler 状态处理器对象
   * @param override 是否覆盖已有状态（默认 true）
   * @example
   * ```ts
   * // 重写 flowing 状态
   * manager.registerStateHandler('flowing', {
   *   apply(edge, ctx) {
   *     edge.attr('line/stroke', '#ff0000')
   *   }
   * }, true)
   *
   * // 新增 warning 状态
   * manager.registerStateHandler('warning', {
   *   apply(edge, ctx) {
   *     edge.attr('line/stroke', '#ff9800')
   *   }
   * })
   * ```
   */
  public registerStateHandler(
    stateName: string,
    handler: EdgeStateHandler,
    override = true
  ): void {
    // 检查是否允许覆盖
    if (!override && this.stateHandlers.has(stateName)) {
      throw new Error(`[EdgeStateManager] State "${stateName}" already exists. Use override=true to replace.`)
    }

    // 检查是否覆盖内置状态
    if (this.BUILTIN_STATES.has(stateName) && this.stateHandlers.has(stateName)) {
      this.overriddenStates.add(stateName)
      console.log(`[EdgeStateManager] Overriding built-in state: "${stateName}"`)
    }
    // 检查是否为用户自定义状态
    else if (!this.BUILTIN_STATES.has(stateName)) {
      this.userDefinedStates.add(stateName)
      console.log(`[EdgeStateManager] Registering user-defined state: "${stateName}"`)
    }

    this.stateHandlers.set(stateName, handler)
    console.log(`[EdgeStateManager] Registered edge state handler: "${stateName}"`)
  }

  /**
   * 获取已注册的状态处理器（用于组合状态）
   * @param stateName 状态名称
   * @returns 状态处理器，未找到返回 undefined
   * @example
   * ```ts
   * // 组合状态：selected + warning
   * const selectedHandler = manager.getStateHandler('selected')
   * if (selectedHandler) {
   *   selectedHandler.apply(edge, context)
   * }
   * ```
   */
  public getStateHandler(stateName: string): EdgeStateHandler | undefined {
    return this.stateHandlers.get(stateName)
  }

  /**
   * 移除状态处理器
   * @param stateName 状态名称
   * @returns 是否成功移除
   */
  public unregisterStateHandler(stateName: string): boolean {
    const result = this.stateHandlers.delete(stateName)

    if (result) {
      // 清理追踪记录
      this.userDefinedStates.delete(stateName)
      this.overriddenStates.delete(stateName)
      console.log(`[EdgeStateManager] Unregistered edge state handler: "${stateName}"`)
    }

    return result
  }

  /**
   * 获取所有已注册的状态名称
   * @returns 状态名称数组
   */
  public getRegisteredStates(): string[] {
    return Array.from(this.stateHandlers.keys())
  }

  /**
   * 为特定边类型注册状态处理器（新增）
   * @param edgeType 边类型（如 'flow-edge'、'polyline'）
   * @param stateName 状态名称
   * @param handler 状态处理器
   * @param override 是否覆盖已存在的处理器
   */
  public registerStateHandlerForType(
    edgeType: string,
    stateName: string,
    handler: EdgeStateHandler,
    override = true
  ): void {
    // 确保存在 Map
    if (!this.typeHandlers.has(edgeType)) {
      this.typeHandlers.set(edgeType, new Map())
    }

    const handlers = this.typeHandlers.get(edgeType)!

    // 检查是否已存在
    if (!override && handlers.has(stateName)) {
      throw new Error(`[EdgeStateManager] 边类型 "${edgeType}" 的状态 "${stateName}" 已存在，使用 override=true 覆盖`)
    }

    // 注册处理器
    handlers.set(stateName, handler)
    console.log(`[EdgeStateManager] Registered edge state handler for type "${edgeType}": "${stateName}"`)
  }

  /**
   * 批量注册边状态处理器（便捷方法）
   * @param edgeType 边类型（null 表示全局）
   * @param handlers 状态处理器映射表
   */
  public registerStateHandlers(
    edgeType: string | null,
    handlers: Record<string, EdgeStateHandler>
  ): void {
    Object.entries(handlers).forEach(([stateName, handler]) => {
      if (edgeType) {
        this.registerStateHandlerForType(edgeType, stateName, handler)
      } else {
        this.registerStateHandler(stateName, handler)
      }
    })
  }

  /**
   * 获取特定边类型的状态处理器
   * @param edgeType 边类型
   * @param stateName 状态名称
   */
  public getStateHandlerForType(edgeType: string, stateName: string): EdgeStateHandler | undefined {
    const typeHandlers = this.typeHandlers.get(edgeType)
    return typeHandlers?.get(stateName)
  }

  /**
   * 移除特定边类型的状态处理器
   * @param edgeType 边类型（null 表示全局）
   * @param stateName 状态名称
   */
  public unregisterStateHandlerForType(edgeType: string | null, stateName: string): boolean {
    if (edgeType === null) {
      return this.unregisterStateHandler(stateName)
    }

    const typeHandlers = this.typeHandlers.get(edgeType)
    if (!typeHandlers) return false

    const result = typeHandlers.delete(stateName)
    return result
  }

  /**
   * 获取特定边类型支持的所有状态
   * @param edgeType 边类型
   */
  public getRegisteredStatesForType(edgeType: string): string[] {
    const states = new Set<string>()

    // 1. 添加全局状态
    this.stateHandlers.forEach((_, stateName) => states.add(stateName))

    // 2. 添加边类型专属状态
    const typeHandlers = this.typeHandlers.get(edgeType)
    if (typeHandlers) {
      typeHandlers.forEach((_, stateName) => states.add(stateName))
    }

    return Array.from(states)
  }

  /**
   * 获取所有已注册的边类型
   */
  public getRegisteredEdgeTypes(): string[] {
    return Array.from(this.typeHandlers.keys())
  }

  /**
   * 判断是否为内置状态
   * @param stateName 状态名称
   * @returns 是否为内置状态
   */
  public isBuiltinState(stateName: string): boolean {
    return this.BUILTIN_STATES.has(stateName)
  }

  /**
   * 判断是否为用户自定义状态（包括用户新增和用户覆盖的内置状态）
   * @param stateName 状态名称
   * @returns 是否为用户自定义状态
   */
  public isUserDefinedState(stateName: string): boolean {
    return this.userDefinedStates.has(stateName) || this.overriddenStates.has(stateName)
  }

  /**
   * 注册内置边状态处理器
   * @private
   */
  private registerBuiltInHandlers(): void {
    // ────────────────────────────────────────────────────────────────
    // default 状态：默认样式
    // ────────────────────────────────────────────────────────────────
    this.stateHandlers.set('default', {
      apply: (edge, ctx) => {
        const config = ctx.config
        edge.attr({
          line: {
            stroke: config.connection.strokeColor,
            strokeWidth: config.connection.strokeWidth,
            strokeDasharray: '',
            style: { animation: 'none' },
          },
        })
      },
    })

    // ────────────────────────────────────────────────────────────────
    // hover 状态：hover 高亮
    // ────────────────────────────────────────────────────────────────
    this.stateHandlers.set('hover', {
      apply: (edge, ctx) => {
        const config = ctx.config
        const strokeColor = config.highlight.edgeHover.enabled
          ? config.highlight.edgeHover.strokeColor
          : '#1677ff'
        const strokeWidth = config.highlight.edgeHover.enabled
          ? config.highlight.edgeHover.strokeWidth
          : config.connection.strokeWidth
        // 使用路径形式修改属性，避免覆盖其他属性（如 targetMarker）
        edge.attr('line/stroke', strokeColor)
        edge.attr('line/strokeWidth', strokeWidth)
      },
    })

    // ────────────────────────────────────────────────────────────────
    // selected 状态：选中高亮
    // ────────────────────────────────────────────────────────────────
    this.stateHandlers.set('selected', {
      apply: (edge, ctx) => {
        const config = ctx.config
        const strokeColor = config.highlight.edgeSelected.enabled
          ? config.highlight.edgeSelected.strokeColor
          : '#1677ff'
        const strokeWidth = config.highlight.edgeSelected.enabled
          ? config.highlight.edgeSelected.strokeWidth
          : config.connection.strokeWidth

        // 使用路径形式修改属性，避免覆盖其他属性（如 targetMarker）
        edge.attr('line/stroke', strokeColor)
        edge.attr('line/strokeWidth', strokeWidth)
        edge.attr('line/strokeDasharray', '')
        edge.attr('line/style/animation', 'none')
      },
    })

    // ────────────────────────────────────────────────────────────────
    // flowing 状态：流动动画（节点 hover 时的出线效果）
    // ────────────────────────────────────────────────────────────────
    this.stateHandlers.set('flowing', {
      apply: (edge, ctx) => {
        const flowCfg = ctx.config.highlight.nodeHoverOutEdgeFlow
        // 使用路径形式修改属性，避免覆盖其他属性（如 targetMarker）
        edge.attr('line/stroke', flowCfg.strokeColor)
        edge.attr('line/strokeWidth', flowCfg.strokeWidth)
        edge.attr('line/strokeDasharray', '8 4')
        edge.attr('line/style/animation', `fd-flow ${flowCfg.duration}s linear infinite`)
      },
      cleanup: (edge, ctx) => {
        // 停止动画，使用路径形式
        edge.attr('line/strokeDasharray', '')
        edge.attr('line/style/animation', 'none')
      },
    })

    // ────────────────────────────────────────────────────────────────
    // dimmed 状态：降低透明度（边重叠时使用）
    // ────────────────────────────────────────────────────────────────
    this.stateHandlers.set('dimmed', {
      apply: (edge, ctx) => {
        const config = ctx.config
        const overlapCfg = config.highlight.edgeHoverOverlap
        const opacity = overlapCfg?.opacity ?? 0.3

        // 从 prop 中获取原状态（不从 data 中读取）
        const originalState = edge.getProp('_prevState') ?? 'default'

        // 根据原状态选择对应的颜色和宽度
        let strokeColor = config.connection.strokeColor
        let strokeWidth = config.connection.strokeWidth

        if (originalState === 'hover') {
          strokeColor = config.highlight.edgeHover.strokeColor
          strokeWidth = config.highlight.edgeHover.strokeWidth
        } else if (originalState === 'selected') {
          strokeColor = config.highlight.edgeSelected.strokeColor
          strokeWidth = config.highlight.edgeSelected.strokeWidth
        } else if (originalState === 'flowing') {
          strokeColor = config.highlight.nodeHoverOutEdgeFlow.strokeColor
          strokeWidth = config.highlight.nodeHoverOutEdgeFlow.strokeWidth
        }

        // 应用样式 + 透明度
        edge.attr('line/stroke', strokeColor)
        edge.attr('line/strokeWidth', strokeWidth)
        edge.attr('line/strokeOpacity', opacity)
        edge.attr('line/strokeDasharray', '') // 清除虚线
        edge.attr('line/style/animation', 'none') // 清除动画

        // 设置 label 透明度标记
        edge.setProp('_labelOpacity', opacity, { silent: true })

        // 重新渲染 label（使用原状态名，但透明度已降低）
        // ✅ 使用新的工具方法读取 label 文本
        const labelText = this.getEdgeLabelText(edge)
        this.setEdgeLabel(edge, labelText, originalState as EdgeState)
      },

      cleanup: (edge, ctx) => {
        // 恢复完全不透明
        edge.attr('line/strokeOpacity', 1)
        edge.removeProp('_labelOpacity', { silent: true })
      },
    })
  }

  // ─── 清理 ───────────────────────────────────────────────────────────────────

  /**
   * 销毁时清理资源
   */
  public dispose(): void {
    // 清理所有 label RAF
    this.labelRafMap.forEach((rafId) => cancelAnimationFrame(rafId))
    this.labelRafMap.clear()

    // 卸载所有 Vue label
    this.labelUnmountMap.forEach((unmount) => unmount())
    this.labelUnmountMap.clear()

    // 清理状态处理器和追踪记录
    this.stateHandlers.clear()
    this.userDefinedStates.clear()
    this.overriddenStates.clear()
  }
}
