/**
 * nodeSlotRegistry.ts
 *
 * 全局单例注册表（使用 window 对象确保跨模块实例共享）
 *
 * 为什么不用 provide/inject：
 *   @antv/x6-vue-shape 在 X6 内部创建了独立的 Vue app 实例来挂载节点组件，
 *   该 app 实例不在 FlowDesignerLayout 的组件树中，inject 无法跨 app 实例传递。
 *
 * 为什么不用 ES 模块单例：
 *   在构建产物中，模块可能被打包成多份副本（代码分割、循环依赖等），
 *   导致 FlowDesignerLayout 和 CommonVueNode 引用的是不同的 Map 实例。
 *
 * 解决方案：
 *   使用全局对象（window）存储注册表，确保无论模块如何打包，
 *   所有组件都访问同一个注册表实例。
 *
 * 响应式更新：
 *   每次 FlowDesignerLayout 更新插槽时，递增 registryVersion。
 *   CommonVueNode 用 watchEffect 监听 registryVersion，触发重新渲染。
 */

import type { Node, Graph } from '@antv/x6'
import type { AppContext, VNode, Ref } from 'vue'
import { shallowRef } from 'vue'

// ─── 类型定义 ─────────────────────────────────────────────────────────────────

/** slot 渲染函数的 scope 参数 */
export interface NodeSlotScope {
  /** X6 Node 实例（原始 API，不响应变化） */
  node: Node
  /** X6 Graph 实例，用于监听 cell:selected 等全局事件 */
  graph: Graph | null
  /** 当前 node-type 字符串 */
  nodeType: string
  /** 响应式 data（✅ 推荐使用，自动响应 setData 变化） */
  data: Ref<Record<string, any>>
  /** 响应式 label（✅ 推荐使用，自动响应 setProp('label') 变化） */
  label: Ref<string>
  /** 响应式 state（✅ 推荐使用，自动响应 setProp('_state') 变化） */
  state: Ref<string>
}

/** slot 渲染函数签名：接收 scope，返回 VNode 数组 */
export type SlotRenderFn = (scope: NodeSlotScope) => VNode[]

// ─── 全局对象接口 ───────────────────────────────────────────────────────────────

interface FlowDesignerGlobal {
  /** 全局 slot 渲染函数注册表 */
  nodeSlotRegistry: Map<string, SlotRenderFn>
  /** 版本号：每次注册表内容变化时 +1 */
  registryVersion: { value: number }
  /** 宿主 Vue app 的 appContext */
  hostAppContext: AppContext | null
}

// ─── 初始化全局对象 ───────────────────────────────────────────────────────────────

declare global {
  interface Window {
    __FLOW_DESIGNER__?: FlowDesignerGlobal
  }
}

// 确保全局对象存在
if (typeof window !== 'undefined' && !window.__FLOW_DESIGNER__) {
  window.__FLOW_DESIGNER__ = {
    nodeSlotRegistry: new Map<string, SlotRenderFn>(),
    registryVersion: { value: 0 },
    hostAppContext: null,
  }
}

// ─── 导出访问器（兼容原有 API） ─────────────────────────────────────────────────

/**
 * 全局 slot 渲染函数注册表
 * key: node-type 字符串（如 'custom-task'）
 * value: slot 渲染函数
 */
export const globalNodeSlotRegistry: Map<string, SlotRenderFn> = 
  (typeof window !== 'undefined' && window.__FLOW_DESIGNER__?.nodeSlotRegistry) || new Map()

/**
 * 版本号（shallowRef）：每次注册表内容变化时 +1
 * CommonVueNode 通过 watchEffect 监听此值，触发响应式重渲染
 */
export const registryVersion = shallowRef(
  typeof window !== 'undefined' && window.__FLOW_DESIGNER__ 
    ? window.__FLOW_DESIGNER__.registryVersion.value 
    : 0
)

/**
 * 获取宿主 Vue app 的 appContext
 */
export function getHostAppContext(): AppContext | null {
  if (typeof window !== 'undefined' && window.__FLOW_DESIGNER__) {
    return window.__FLOW_DESIGNER__.hostAppContext
  }
  return null
}

/**
 * 设置宿主 Vue app 的 appContext
 * 由 FlowDesignerLayout 调用，注册宿主 appContext
 */
export function setHostAppContext(ctx: AppContext) {
  if (typeof window !== 'undefined' && window.__FLOW_DESIGNER__) {
    window.__FLOW_DESIGNER__.hostAppContext = ctx
  }
}

/**
 * 更新全局注册表（由 FlowDesignerLayout 调用）
 * 传入当前所有 node-* 插槽的渲染函数 Map，全量替换并递增版本号
 */
export function updateNodeSlotRegistry(entries: Map<string, SlotRenderFn>) {
  if (typeof window !== 'undefined' && window.__FLOW_DESIGNER__) {
    const registry = window.__FLOW_DESIGNER__.nodeSlotRegistry
    registry.clear()
    entries.forEach((fn, key) => registry.set(key, fn))
    
    // 递增版本号，触发所有 CommonVueNode 的 watchEffect 重新执行
    window.__FLOW_DESIGNER__.registryVersion.value++
    registryVersion.value = window.__FLOW_DESIGNER__.registryVersion.value
    
    console.log('✅ [nodeSlotRegistry] 已更新注册表，版本:', registryVersion.value, '插槽数:', registry.size)
  }
}
