import { Graph, Node } from '@antv/x6'
import type { CanvasConfigManager } from './CanvasConfigManager'
import type { ModeManager } from './ModeManager'
import type { CanvasConfig } from '../../../views/types/flow.types'
import type { PortStateRenderers, PortStyle, PortState } from '../types/render'

// ─── 类型定义 ───────────────────────────────────────────────────────────────

/** 节点状态上下文（传递给状态处理器） */
export interface NodeStateContext {
  config: CanvasConfig
  graph: Graph
  manager: NodeStateManager
  canConnect: boolean  // 是否允许连线（影响锚点显示）
}

/** 节点状态处理器接口 */
export interface NodeStateHandler {
  /**
   * 应用状态样式
   * @param node 目标节点
   * @param context 上下文（包含 config、graph、manager、canConnect）
   */
  apply(node: Node, context: NodeStateContext): void

  /**
   * 清理状态（可选，离开状态时调用）
   * @param node 目标节点
   * @param context 上下文
   */
  cleanup?(node: Node, context: NodeStateContext): void
}

/** 节点状态类型 */
export type NodeState = 'default' | 'selected' | 'hover' | 'dragging' | string

// ─── 配置选项 ───────────────────────────────────────────────────────────────

export interface NodeStateManagerOptions {
  graph: Graph
  config: CanvasConfigManager
  mode: ModeManager
  tooltipEl?: HTMLElement | null
  /**
   * 获取回调函数的 getter，动态获取最新的回调引用
   */
  getCallbacks?: () => {
    onTooltipChange?: (payload: any) => void
    portStateRenderers?: PortStateRenderers
  }
}

/**
 * NodeStateManager 节点状态管理器
 *
 * 职责：
 * - 管理节点的状态（default、hover、selected、dragging等）
 * - 管理节点的锚点显示和样式
 * - 管理节点的 Tooltip 显示和位置
 * - 提供节点状态处理器的注册/获取/移除 API
 */
export class NodeStateManager {
  private graph: Graph
  private config: CanvasConfigManager
  private mode: ModeManager
  private tooltipEl: HTMLElement | null
  private getCallbacks: () => {
    onTooltipChange?: (payload: any) => void
  }

  // 🆕 内置状态处理器（框架固定行为，不可被覆盖）
  private builtInHandlers: Map<string, NodeStateHandler> = new Map()

  // 🆕 自定义状态处理器（用户通过 API 注册，可按节点类型分组）
  private customHandlers: Map<string, Map<string, NodeStateHandler>> = new Map()

  // 全局处理器的特殊 key
  private readonly GLOBAL_KEY = '__global__'

  // 节点当前状态追踪（节点ID -> 状态名）
  private nodeStates: Map<string, string> = new Map()

  // hover 状态追踪
  private hoveredNodeId: string | null = null

  // 拖拽状态追踪
  private draggingNodeId: string | null = null

  constructor(options: NodeStateManagerOptions) {
    this.graph = options.graph
    this.config = options.config
    this.mode = options.mode
    this.tooltipEl = options.tooltipEl || null
    this.getCallbacks = options.getCallbacks || (() => ({}))

    // 🔒 注册框架内置状态处理器（优先）
    this.registerBuiltInHandlers()
  }

  // ─── 状态管理 API ───────────────────────────────────────────────────────────

  /**
   * 🎯 设置节点状态（双层调用机制）
   * 先执行内置行为（锚点等），再执行自定义样式
   * @param node  目标节点
   * @param state 状态名称（default | selected | hover | dragging | 自定义状态）
   */
  public setNodeState(node: Node, state: string): void {
    const nodeId = node.id
    const prevState = this.nodeStates.get(nodeId) || node.getProp('_state') || 'default'

    // ═══════════════════════════════════════════════════════════════
    // 第一步：清理旧状态
    // ═══════════════════════════════════════════════════════════════
    if (prevState !== state) {
      // 清理自定义处理器
      const prevCustomHandler = this.getHandler(node, prevState, 'custom')
      if (prevCustomHandler?.cleanup) {
        try {
          prevCustomHandler.cleanup(node, this.getStateContext())
        } catch (error) {
          console.error(`[NodeStateManager] 清理自定义状态 "${prevState}" 失败:`, error)
        }
      }

      // 清理内置处理器
      const prevBuiltInHandler = this.getHandler(node, prevState, 'builtin')
      if (prevBuiltInHandler?.cleanup) {
        try {
          prevBuiltInHandler.cleanup(node, this.getStateContext())
        } catch (error) {
          console.error(`[NodeStateManager] 清理内置状态 "${prevState}" 失败:`, error)
        }
      }
    }

    // ═══════════════════════════════════════════════════════════════
    // 第二步：🔒 应用内置处理器（框架行为，始终执行）
    // ═══════════════════════════════════════════════════════════════
    const builtInHandler = this.getHandler(node, state, 'builtin')
    if (builtInHandler) {
      try {
        builtInHandler.apply(node, this.getStateContext())
      } catch (error) {
        console.error(`[NodeStateManager] 内置状态 "${state}" 执行失败:`, error)
      }
    }

    // ═══════════════════════════════════════════════════════════════
    // 第三步：应用自定义处理器（用户样式，可选）
    // ═══════════════════════════════════════════════════════════════
    const customHandler = this.getHandler(node, state, 'custom')
    if (customHandler) {
      try {
        customHandler.apply(node, this.getStateContext())
      } catch (error) {
        console.error(`[NodeStateManager] 自定义状态 "${state}" 执行失败:`, error)
      }
    }

    // ═══════════════════════════════════════════════════════════════
    // 第四步：记录新状态
    // ═══════════════════════════════════════════════════════════════
    this.nodeStates.set(nodeId, state)
    node.setProp('_state', state)
  }

  /**
   * 重置所有节点为 default 状态（可排除指定节点）
   */
  public resetAllNodes(exceptId?: string): void {
    this.graph.getNodes().forEach((node) => {
      if (node.id !== exceptId) {
        this.setNodeState(node, 'default')
      }
    })
  }

  /**
   * 获取节点状态上下文
   */
  public getStateContext(): NodeStateContext {
    return {
      config: this.config.getConfig(),
      graph: this.graph,
      manager: this,
      canConnect: this.mode.can('canConnect'),
    }
  }

  /**
   * 获取节点的状态处理器（带降级）
   * @param node 目标节点
   * @param stateName 状态名称
   * @returns 找到的处理器，优先返回节点类型专属，其次返回全局
   */
  /**
   * 获取状态处理器
   * @param node 节点
   * @param stateName 状态名称
   * @param handlerType 'builtin' | 'custom' | 'both'（默认 'both'）
   * @returns 处理器或 undefined
   */
  private getHandler(
    node: Node,
    stateName: string,
    handlerType: 'builtin' | 'custom' | 'both' = 'both'
  ): NodeStateHandler | undefined {

    // 1️⃣ 只获取内置处理器
    if (handlerType === 'builtin') {
      return this.builtInHandlers.get(stateName)
    }

    // 2️⃣ 只获取自定义处理器
    if (handlerType === 'custom') {
      const nodeType = node.shape

      // 先查节点类型专属
      const typeHandlers = this.customHandlers.get(nodeType)
      if (typeHandlers?.has(stateName)) {
        return typeHandlers.get(stateName)
      }

      // 降级到全局
      const globalHandlers = this.customHandlers.get(this.GLOBAL_KEY)
      return globalHandlers?.get(stateName)
    }

    // 3️⃣ 获取所有（'both'）- 优先返回自定义，没有则返回内置
    // 注：通常不会用到这个分支，因为我们会分别调用
    const nodeType = node.shape
    const typeHandlers = this.customHandlers.get(nodeType)
    if (typeHandlers?.has(stateName)) {
      return typeHandlers.get(stateName)
    }

    const globalHandlers = this.customHandlers.get(this.GLOBAL_KEY)
    if (globalHandlers?.has(stateName)) {
      return globalHandlers.get(stateName)
    }

    return this.builtInHandlers.get(stateName)
  }

  // ─── 锚点（Port）管理 ───────────────────────────────────────────────────────

  /**
   * 设置节点所有锚点的可见性和样式。
   *
   * 使用 setPortProp 写入 port model，让 X6 re-render 时读到正确的值。
   * visibility 也写入 model（style.visibility），这样 re-render 不会用
   * group 的默认值（'hidden'）覆盖它。
   *
   * @param node 目标节点
   * @param visible 是否可见
   * @param style 'default' | 'hover'（当 visible=true 时有效）
   * @param portState 锚点状态（传给 portStateRenderers 钩子）
   */
  public setPortsVisibility(node: Node, visible: boolean, style: 'default' | 'hover' = 'default', portState: PortState = 'default'): void {
    if (!this.mode.can('canConnect')) return

    const config = this.config.getConfig()
    const hook = this.getCallbacks().portStateRenderers

    node.getPorts().forEach((p) => {
      if (!p.id) return

      // 1. 设置 visibility（写入 model，re-render 时读取）
      node.setPortProp(p.id, 'attrs/circle/style/visibility', visible ? 'visible' : 'hidden')

      if (!visible) return

      // 2. 计算默认样式
      let fill: string, stroke: string, r: number | string, strokeWidth: number | string
      if (style === 'hover') {
        const cfg = config.highlight.portHover
        fill = cfg.fillColor; stroke = cfg.strokeColor; r = cfg.size; strokeWidth = cfg.strokeWidth
      } else {
        const cfg = config.highlight.portDefault
        fill = cfg.fill; stroke = cfg.stroke; r = cfg.size; strokeWidth = cfg.strokeWidth
      }

      // 3. 钩子覆盖
      if (hook) {
        const override = hook(node, portState)
        if (override?.fill        !== undefined) fill        = override.fill
        if (override?.stroke      !== undefined) stroke      = override.stroke
        if (override?.size        !== undefined) r           = override.size
        if (override?.strokeWidth !== undefined) strokeWidth = override.strokeWidth
      }

      // 4. 写入 model（一并触发 re-render，值已包含正确 visibility）
      node.setPortProp(p.id, 'attrs/circle/fill',         fill)
      node.setPortProp(p.id, 'attrs/circle/stroke',       stroke)
      node.setPortProp(p.id, 'attrs/circle/r',            r)
      node.setPortProp(p.id, 'attrs/circle/strokeWidth',  strokeWidth)
    })
  }

  /**
   * 设置单个锚点的 hover 样式（写入 port model）。
   */
  public setPortHoverStyle(node: Node, portId: string): void {
    const config = this.config.getConfig()
    const portConfig = config.highlight.portHover
    if (!portConfig.enabled) return

    let fill: string = portConfig.fillColor
    let stroke: string = portConfig.strokeColor
    let r: number | string = portConfig.size
    let strokeWidth: number | string = portConfig.strokeWidth

    // 钩子覆盖
    const hook = this.getCallbacks().portStateRenderers
    if (hook) {
      const override = hook(node, 'port-hover')
      if (override?.fill        !== undefined) fill        = override.fill
      if (override?.stroke      !== undefined) stroke      = override.stroke
      if (override?.size        !== undefined) r           = override.size
      if (override?.strokeWidth !== undefined) strokeWidth = override.strokeWidth
    }

    node.setPortProp(portId, 'attrs/circle/fill',         fill)
    node.setPortProp(portId, 'attrs/circle/stroke',       stroke)
    node.setPortProp(portId, 'attrs/circle/r',            r)
    node.setPortProp(portId, 'attrs/circle/strokeWidth',  strokeWidth)
  }

  /**
   * 恢复单个锚点的默认样式（写入 port model）。
   */
  public resetPortStyle(node: Node, portId: string): void {
    const config = this.config.getConfig()
    const portConfig = config.highlight.portDefault

    let fill: string = portConfig.fill
    let stroke: string = portConfig.stroke
    let r: number | string = portConfig.size
    let strokeWidth: number | string = portConfig.strokeWidth

    // 钩子覆盖
    const hook = this.getCallbacks().portStateRenderers
    if (hook) {
      const override = hook(node, 'default')
      if (override?.fill        !== undefined) fill        = override.fill
      if (override?.stroke      !== undefined) stroke      = override.stroke
      if (override?.size        !== undefined) r           = override.size
      if (override?.strokeWidth !== undefined) strokeWidth = override.strokeWidth
    }

    node.setPortProp(portId, 'attrs/circle/fill',         fill)
    node.setPortProp(portId, 'attrs/circle/stroke',       stroke)
    node.setPortProp(portId, 'attrs/circle/r',            r)
    node.setPortProp(portId, 'attrs/circle/strokeWidth',  strokeWidth)
  }

  // ─── Tooltip 管理 ───────────────────────────────────────────────────────────

  /**
   * 显示节点 Tooltip
   */
  public showTooltip(node: Node, mouseEvent?: any): void {
    // 权限检查：如果不允许显示节点 tooltip，直接返回
    if (!this.mode.can('canNodeTooltip')) return

    const el = this.tooltipEl
    if (!el) return

    el.style.display = 'block'

    // 触发回调
    const callbacks = this.getCallbacks()
    callbacks.onTooltipChange?.({
      visible: true,
      type: 'node',
      node: node,
      edge: null,
      data: node.getData()
    })

    requestAnimationFrame(() => {
      const contentEl = el.querySelector('[data-role="tooltip-content"]')
      //兼容2种模式
      if (contentEl) {
        contentEl.innerHTML = node.getProp('label') || ((node as any).getLabel ? (node as any).getLabel() : '') || (node.getData()?.label ?? '')
      }
      this.updateTooltipPosition(node)
    })
  }

  /**
   * 隐藏 Tooltip
   */
  public hideTooltip(): void {
    const el = this.tooltipEl
    if (!el) return

    el.style.left = '0px'
    el.style.top = '0px'
    el.style.display = 'none'

    // 触发回调
    const callbacks = this.getCallbacks()
    callbacks.onTooltipChange?.({
      visible: false,
      type: null,
      node: null,
      edge: null,
      data: null
    })
  }

  /**
   * 更新 Tooltip 位置（根据节点当前坐标计算）
   */
  public updateTooltipPosition(node: Node): void {
    const el = this.tooltipEl
    if (!el || el.style.display === 'none') return

    const nodePos = node.position()
    const nodePos2 = this.graph.localToPage(nodePos.x, nodePos.y)
    const zoom = this.graph.zoom()
    const nodeSize = {
      width: node.size().width * zoom,
      height: node.size().height * zoom
    }
    const zoomLevel = Math.max(1, zoom)

    // 获取 tooltip 偏移量配置
    const tooltipConfig = this.config.getConfig().tooltip
    const offsetX = tooltipConfig?.offsetX ?? 0
    const offsetY = tooltipConfig?.offsetY ?? 0

    el.style.transform = `scale(${zoomLevel})`
    el.style.transformOrigin = 'center bottom'
    el.style.left = nodePos2.x + nodeSize.width / 2 - el.clientWidth / 2 + offsetX + 'px'
    el.style.top = nodePos2.y - 50 + offsetY + 'px'
  }

  // ─── Hover 状态追踪 ─────────────────────────────────────────────────────────

  /**
   * 设置当前 hover 的节点 ID
   */
  public setHoveredNode(nodeId: string | null): void {
    this.hoveredNodeId = nodeId
  }

  /**
   * 获取当前 hover 的节点 ID
   */
  public getHoveredNode(): string | null {
    return this.hoveredNodeId
  }

  // ─── 拖拽状态追踪 ───────────────────────────────────────────────────────────

  /**
   * 设置当前拖拽的节点 ID
   */
  public setDraggingNode(nodeId: string | null): void {
    this.draggingNodeId = nodeId
  }

  /**
   * 获取当前拖拽的节点 ID
   */
  public getDraggingNode(): string | null {
    return this.draggingNodeId
  }

  // ─── 状态处理器注册 ─────────────────────────────────────────────────────────

  /**
   * 注册或覆盖节点状态处理器（支持节点类型）
   * @param nodeType 节点类型（null 表示全局）
   * @param stateName 状态名称
   * @param handler 状态处理器
   * @param override 是否覆盖已存在的处理器
   */
  /**
   * 注册自定义状态处理器（用户 API）
   * @param nodeType 节点类型（null 表示全局）
   * @param stateName 状态名称
   * @param handler 处理器
   * @param override 是否允许覆盖已有的自定义处理器
   */
  public registerStateHandler(
    nodeType: string | null,
    stateName: string,
    handler: NodeStateHandler,
    override = true
  ): void {
    const key = nodeType || this.GLOBAL_KEY

    // 确保存在 Map
    if (!this.customHandlers.has(key)) {
      this.customHandlers.set(key, new Map())
    }

    const handlers = this.customHandlers.get(key)!

    // 检查是否已存在
    if (!override && handlers.has(stateName)) {
      throw new Error(`[NodeStateManager] 自定义状态 "${key}:${stateName}" 已存在，使用 override=true 覆盖`)
    }

    // 注册自定义处理器
    handlers.set(stateName, handler)
  }

  /**
   * 获取已注册的状态处理器（全局）
   * @deprecated 使用 getStateHandlerForType 代替
   */
  public getStateHandler(stateName: string): NodeStateHandler | undefined {
    const globalHandlers = this.customHandlers.get(this.GLOBAL_KEY)
    return globalHandlers?.get(stateName)
  }

  /**
   * 获取特定节点类型的自定义状态处理器
   * @param nodeType 节点类型
   * @param stateName 状态名称
   */
  public getStateHandlerForType(nodeType: string, stateName: string): NodeStateHandler | undefined {
    const typeHandlers = this.customHandlers.get(nodeType)
    return typeHandlers?.get(stateName)
  }

  /**
   * 移除状态处理器（全局）
   * @deprecated 使用 unregisterStateHandlerForType 代替
   */
  public unregisterStateHandler(stateName: string): boolean {
    const globalHandlers = this.customHandlers.get(this.GLOBAL_KEY)
    if (!globalHandlers) return false

    const result = globalHandlers.delete(stateName)
    if (result) {
      console.log(`[NodeStateManager] Unregistered node state handler: "${this.GLOBAL_KEY}:${stateName}"`)
    }
    return result
  }

  /**
   * 移除特定节点类型的自定义状态处理器
   * @param nodeType 节点类型（null 表示全局）
   * @param stateName 状态名称
   */
  public unregisterStateHandlerForType(nodeType: string | null, stateName: string): boolean {
    const key = nodeType || this.GLOBAL_KEY
    const typeHandlers = this.customHandlers.get(key)
    if (!typeHandlers) return false

    const result = typeHandlers.delete(stateName)
    return result
  }

  /**
   * 获取所有已注册的状态名称（合并内置 + 自定义，所有节点类型）
   */
  public getRegisteredStates(): string[] {
    const allStates = new Set<string>()

    // 添加内置状态
    this.builtInHandlers.forEach((_, stateName) => {
      allStates.add(stateName)
    })

    // 添加自定义状态
    this.customHandlers.forEach((typeHandlers) => {
      typeHandlers.forEach((_, stateName) => {
        allStates.add(stateName)
      })
    })

    return Array.from(allStates)
  }

  /**
   * 获取特定节点类型支持的所有状态
   * @param nodeType 节点类型
   * @returns 状态名称数组（内置 + 节点类型专属 + 全局）
   */
  public getRegisteredStatesForType(nodeType: string): string[] {
    const states = new Set<string>()

    // 1. 添加内置状态
    this.builtInHandlers.forEach((_, stateName) => states.add(stateName))

    // 2. 添加节点类型专属状态
    const typeHandlers = this.customHandlers.get(nodeType)
    if (typeHandlers) {
      typeHandlers.forEach((_, stateName) => states.add(stateName))
    }

    // 3. 添加全局自定义状态
    const globalHandlers = this.customHandlers.get(this.GLOBAL_KEY)
    if (globalHandlers) {
      globalHandlers.forEach((_, stateName) => states.add(stateName))
    }

    return Array.from(states)
  }

  /**
   * 获取所有已注册的节点类型
   * @returns 节点类型数组（不包含全局 key）
   */
  public getRegisteredNodeTypes(): string[] {
    return Array.from(this.customHandlers.keys()).filter(
      type => type !== this.GLOBAL_KEY
    )
  }

  /**
   * 注册内置节点状态处理器
   * @private
   */
  /**
   * 🔒 注册框架内置的状态处理器（不可被用户覆盖）
   * 这里定义框架级别的行为：锚点、tooltip、基础样式等
   */
  private registerBuiltInHandlers(): void {
    // ═══════════════════════════════════════════════════════════════
    // default 状态：隐藏锚点、隐藏 tooltip
    // ═══════════════════════════════════════════════════════════════
    this.builtInHandlers.set('default', {
      apply: (node, ctx) => {
        // 1️⃣ 锚点控制：隐藏
        ctx.manager.setPortsVisibility(node, false, 'default', 'default')

        // 2️⃣ Tooltip 控制：隐藏
        ctx.manager.hideTooltip()
      },
      cleanup: (node, ctx) => {
        ctx.manager.hideTooltip()
      }
    })

    // ═══════════════════════════════════════════════════════════════
    // hover 状态：显示锚点、显示 tooltip
    // ═══════════════════════════════════════════════════════════════
    this.builtInHandlers.set('hover', {
      apply: (node, ctx) => {
        // 1️⃣ 锚点控制：显示 default 样式（空心），鼠标悬停在锚点上才变为实心
        if (ctx.canConnect) {
          ctx.manager.setPortsVisibility(node, true, 'default', 'node-hover')
        }

        // 2️⃣ Tooltip 控制：显示
        // 注：mouseEvent 需要从外部传入 context
      },
      cleanup: (node, ctx) => {
        ctx.manager.hideTooltip()
      }
    })

    // ═══════════════════════════════════════════════════════════════
    // selected 状态：显示锚点
    // ═══════════════════════════════════════════════════════════════
    this.builtInHandlers.set('selected', {
      apply: (node, ctx) => {
        // 1️⃣ 锚点控制：显示（default 样式）
        if (ctx.canConnect) {
          ctx.manager.setPortsVisibility(node, true, 'default', 'selected')
        }
      },
      cleanup: (node, ctx) => {
        // selected 状态的 cleanup 通常不需要特殊处理
      }
    })

    // ═══════════════════════════════════════════════════════════════
    // dragging 状态：保持锚点可见
    // ═══════════════════════════════════════════════════════════════
    this.builtInHandlers.set('dragging', {
      apply: (node, ctx) => {
        // 拖拽时保持锚点可见
        if (ctx.canConnect) {
          ctx.manager.setPortsVisibility(node, true, 'default', 'selected')
        }
      },
      cleanup: (node, ctx) => {
        // 拖拽结束后的清理
      }
    })
  }

  // ─── 清理 ───────────────────────────────────────────────────────────────────

  /**
   * 销毁时清理资源
   */
  /**
   * 销毁时清理资源
   */
  public dispose(): void {
    this.builtInHandlers.clear()
    this.customHandlers.clear()
    this.nodeStates.clear()
    this.hoveredNodeId = null
    this.draggingNodeId = null
  }
}
