<template>
  <a-form layout="vertical" size="small">
    <a-form-item label="节点名称">
      <a-input v-model:value="form.label" @change="emitUpdate" />
    </a-form-item>
    <a-form-item label="通知标题">
      <a-input v-model:value="form.notifyTitle"       :placeholder="'请输入通知标题'" @change="emitUpdate" />
    </a-form-item>
    <a-form-item label="通知对象">
      <a-radio-group v-model:value="form.notifyTargetType" @change="emitUpdate">
                                <a-radio value="initiator">发起人</a-radio>
        <a-radio value="user">指定人员</a-radio>
        <a-radio value="role">指定角色</a-radio>
      </a-radio-group>
    </a-form-item>
    <a-form-item v-if="form.notifyTargetType === 'user'" label="通知人员">
      <a-select v-model:value="form.notifyTargets" mode="multiple" placeholder="选择人员" @change="emitUpdate">
        <a-select-option value="u1">张三 · 研发部</a-select-option>
        <a-select-option value="u2">李四 · 产品部</a-select-option>
        <a-select-option value="u3">王五 · 财务部</a-select-option>
      </a-select>
    </a-form-item>
    <a-form-item v-if="form.notifyTargetType === 'role'" label="通知角色">
      <a-select v-model:value="form.notifyTargets" mode="multiple" placeholder="选择角色" @change="emitUpdate">
        <a-select-option value="r1">部门经理</a-select-option>
        <a-select-option value="r2">项目负责人</a-select-option>
      </a-select>
    </a-form-item>
    <a-form-item label="通知方式">
      <a-checkbox-group v-model:value="form.notifyMethods" @change="emitUpdate">
                                <a-checkbox value="message">站内信</a-checkbox>
        <a-checkbox value="email">邮件</a-checkbox>
        <a-checkbox value="sms">短信</a-checkbox>
      </a-checkbox-group>
    </a-form-item>
    <a-form-item label="通知内容">
      <a-textarea
        v-model:value="form.notifyTemplate"
        :rows="4"
        :placeholder="'支持变量：${发起人}、${流程名称}、${申请内容}'"
        @change="emitUpdate"
      />
    </a-form-item>
  </a-form>
</template>

<script setup lang="ts">
import { reactive, watch } from 'vue'
import type { Node } from '@antv/x6'
import type { FlowNodeData } from '../types/flow.types'

const props = defineProps<{ node: Node }>()
const emit  = defineEmits<{ (e: 'update', data: FlowNodeData): void }>()
const form = reactive<FlowNodeData>({
  label: '', notifyTitle: '', notifyTargetType: 'initiator',
  notifyTargets: [], notifyMethods: ['message'], notifyTemplate: '',
  ...props.node.getData(),
})
watch(() => props.node.getData(), (d) => { if (d) Object.assign(form, d) }, { deep: true })

function emitUpdate() { emit('update', { ...form }) }
</script>
