import type { Graph } from '@antv/x6'

/**
 * 历史记录管理器
 * 基于 X6 的 History 插件，提供撤销/重做功能
 */
export class HistoryManager {
  private graph: Graph | null = null
  private canUndoState = false
  private canRedoState = false

  // ─── 绑定 Graph ─────────────────────────────────────────────────────────────

  bind(graph: Graph): void {
    this.graph = graph

    // 监听历史变化事件
    graph.on('history:change', () => {
      this.updateState()
    })

    // 初始化状态
    this.updateState()
  }

  // ─── 更新状态 ───────────────────────────────────────────────────────────────

  private updateState(): void {
    if (!this.graph) return
    this.canUndoState = this.graph.canUndo()
    this.canRedoState = this.graph.canRedo()
  }

  // ─── 撤销/重做 ──────────────────────────────────────────────────────────────

  undo(): boolean {
    if (this.graph && this.canUndo()) {
      this.graph.undo()
      return true
    }
    return false
  }

  redo(): boolean {
    if (this.graph && this.canRedo()) {
      this.graph.redo()
      return true
    }
    return false
  }

  canUndo(): boolean {
    return this.canUndoState
  }

  canRedo(): boolean {
    return this.canRedoState
  }

  // ─── 历史记录操作 ───────────────────────────────────────────────────────────

  clear(): void {
    if (this.graph) {
      this.graph.clearHistory()
      this.updateState()
    }
  }

  getUndoStack(): any[] {
    if (!this.graph) return []
    return this.graph.getUndoStack?.() || []
  }

  getRedoStack(): any[] {
    if (!this.graph) return []
    return this.graph.getRedoStack?.() || []
  }

  // ─── 状态查询 ───────────────────────────────────────────────────────────────

  getStackSize(): number {
    const undoStack = this.getUndoStack()
    const redoStack = this.getRedoStack()
    return undoStack.length + redoStack.length
  }

  isEmpty(): boolean {
    return !this.canUndo() && !this.canRedo()
  }

  // ─── 工具方法 ───────────────────────────────────────────────────────────────

  toJSON() {
    return {
      canUndo: this.canUndoState,
      canRedo: this.canRedoState,
      undoStackSize: this.getUndoStack().length,
      redoStackSize: this.getRedoStack().length,
    }
  }
}
