import { v4 as uuidv4 } from 'uuid'
import type { FlowMeta, SelectedCell } from '../../../views/types/flow.types'

/**
 * 流程状态管理器
 * 负责管理流程元数据、选中状态、脏标记等
 */
export class FlowState {
  private meta: FlowMeta
  private selectedCells: SelectedCell[] = []
  private isDirty = false
  private isSaving = false

  constructor(initialMeta?: Partial<FlowMeta>) {
    this.meta = {
      id: uuidv4(),
      name: '未命名流程',
      category: 'leave',
      description: '',
      version: '1.0.0',
      status: 'draft',
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      allowRevoke: true,
      revokeLimit: 24,
      initiatorScope: { type: 'all', values: [] },
      ...initialMeta,
    }
  }

  // ─── 元数据操作 ─────────────────────────────────────────────────────────────

  getMeta(): FlowMeta {
    return { ...this.meta }
  }

  setMeta(meta: Partial<FlowMeta>): void {
    this.meta = { ...this.meta, ...meta }
    this.markDirty()
  }

  updateMetaField<K extends keyof FlowMeta>(key: K, value: FlowMeta[K]): void {
    this.meta[key] = value
    this.markDirty()
  }

  // ─── 选中状态操作 ───────────────────────────────────────────────────────────

  getSelectedCells(): SelectedCell[] {
    return [...this.selectedCells]
  }

  setSelectedCells(cells: SelectedCell[]): void {
    this.selectedCells = [...cells]
  }

  addSelectedCell(cell: SelectedCell): void {
    if (!this.selectedCells.some(c => c.id === cell.id)) {
      this.selectedCells.push(cell)
    }
  }

  removeSelectedCell(id: string): void {
    this.selectedCells = this.selectedCells.filter(c => c.id !== id)
  }

  clearSelection(): void {
    this.selectedCells = []
  }

  isSelected(id: string): boolean {
    return this.selectedCells.some(c => c.id === id)
  }

  getSelectedNodes(): SelectedCell[] {
    return this.selectedCells.filter(c => c.type === 'node')
  }

  getSelectedEdges(): SelectedCell[] {
    return this.selectedCells.filter(c => c.type === 'edge')
  }

  hasSelection(): boolean {
    return this.selectedCells.length > 0
  }

  isMultiSelection(): boolean {
    return this.selectedCells.length > 1
  }

  // ─── 脏状态操作 ─────────────────────────────────────────────────────────────

  isDirtyState(): boolean {
    return this.isDirty
  }

  markDirty(): void {
    this.isDirty = true
  }

  markClean(): void {
    this.isDirty = false
    this.meta.updatedAt = new Date().toISOString()
  }

  // ─── 保存状态 ───────────────────────────────────────────────────────────────

  isSavingState(): boolean {
    return this.isSaving
  }

  setSaving(saving: boolean): void {
    this.isSaving = saving
  }

  // ─── 序列化 ─────────────────────────────────────────────────────────────────

  toJSON() {
    return {
      meta: this.meta,
      selectedCells: this.selectedCells,
      isDirty: this.isDirty,
      isSaving: this.isSaving,
    }
  }

  // ─── 重置 ───────────────────────────────────────────────────────────────────

  reset(meta?: Partial<FlowMeta>): void {
    this.meta = {
      id: uuidv4(),
      name: '未命名流程',
      category: 'leave',
      description: '',
      version: '1.0.0',
      status: 'draft',
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      allowRevoke: true,
      revokeLimit: 24,
      initiatorScope: { type: 'all', values: [] },
      ...meta,
    }
    this.selectedCells = []
    this.isDirty = false
    this.isSaving = false
  }
}
