import type { MenuItem } from './types'
import type { ModeCapabilities } from '../../../views/types/flow.types'
import {
  SelectOutlined,
  UndoOutlined,
  RedoOutlined,
  ZoomInOutlined,
  ZoomOutOutlined,
  CompressOutlined,
  FullscreenExitOutlined,
  ImportOutlined,
  ExportOutlined,
  ClearOutlined,
} from '@ant-design/icons-vue'

/**
 * 画布右键菜单配置
 */
export function useCanvasMenu() {
  /**
   * 获取画布菜单项
   * @param capabilities 模式权限
   */
  function getCanvasMenuItems(capabilities: ModeCapabilities): MenuItem[] {
    const items: MenuItem[] = []
    
    // 全选（需要多选和全选权限）
    if (capabilities.canSelectAll && capabilities.canMultipleSelect) {
      items.push(
        { key: 'selectAll', label: '全选节点 (Ctrl+A)', icon: SelectOutlined },
        { key: 'div1', divider: true }
      )
    }
    
    // 撤销/重做（仅设计模式）
    if (capabilities.canUndo || capabilities.canRedo) {
      if (capabilities.canUndo) {
        items.push({ key: 'undo', label: '撤销 (Ctrl+Z)', icon: UndoOutlined })
      }
      if (capabilities.canRedo) {
        items.push({ key: 'redo', label: '重做 (Ctrl+Y)', icon: RedoOutlined })
      }
      items.push({ key: 'div2', divider: true })
    }
    
    // 缩放和视图操作（所有模式都可用）
    if (capabilities.canZoom) {
      items.push(
        { key: 'zoomIn', label: '放大 (Ctrl+=)', icon: ZoomInOutlined },
        { key: 'zoomOut', label: '缩小 (Ctrl+-)', icon: ZoomOutOutlined }
      )
    }
    
    if (capabilities.canFitView) {
      items.push(
        { key: 'fitView', label: '适应窗口 (Ctrl+0)', icon: CompressOutlined },
        { key: 'resetView', label: '重置视图', icon: FullscreenExitOutlined }
      )
    }
    
    // 导入/导出/清空（仅设计模式）
    if (capabilities.canImport || capabilities.canExport) {
      items.push({ key: 'div3', divider: true })
      
      if (capabilities.canImport) {
        items.push({ key: 'import', label: '导入 JSON', icon: ImportOutlined })
      }
      
      if (capabilities.canExport) {
        items.push({ key: 'export', label: '导出 JSON', icon: ExportOutlined })
      }
    }
    
    if (capabilities.canDelete) {
      items.push(
        { key: 'div4', divider: true },
        { key: 'clear', label: '清空画布', icon: ClearOutlined, danger: true }
      )
    }
    
    return items
  }

  return {
    getCanvasMenuItems
  }
}
